INSERT INTO text_questions (text_id, question_type, question_text, options, correct_index, explanation, difficulty, order_index) VALUES
('02439f00-9323-4e02-bd86-1ad0404b6120','main_idea',$$Bu metnin ana fikri aşağıdakilerden hangisidir?$$,'["Sindirim, besinlerin mekanik ve kimyasal yollarla parçalanarak hücrelerin kullanabileceği formlara dönüştürülmesidir.","Besinler yalnızca kimyasal yollarla sindirilebilir.","Emilim yalnızca kalın bağırsakta gerçekleşir.","Sindirim sistemi sadece karbonhidratları işler."]'::jsonb, 0, $$Metin, sindirim ve emilimin temel süreçlerini bütüncül biçimde açıklamaktadır; mekanik ve kimyasal sindirim birlikte ele alınmaktadır.$$, 2, 1),
('02439f00-9323-4e02-bd86-1ad0404b6120','detail',$$Metne göre emilimin büyük çoğunluğu nerede gerçekleşir?$$,'["Kalın bağırsakta","İnce bağırsakta","Midede","Ağız boşluğunda"]'::jsonb, 1, $$Metinde emilimin ağırlıklı olarak ince bağırsakta gerçekleştiği belirtilmektedir.$$, 2, 2),
('02439f00-9323-4e02-bd86-1ad0404b6120','inference',$$Bu metne göre sindirim sistemi organlarının sıralı çalışması hakkında ne söylenebilir?$$,'["Her organ bağımsız çalışır, diğerleriyle ilişkisi yoktur.","Organlar sıralı çalışarak sindirim verimliliğini artırır.","Sindirim yalnızca midede tamamlanır.","Kalın bağırsak sindirimde hiçbir rol oynamaz."]'::jsonb, 1, $$Metinde organların birbirini tamamlayan sıralı işlevlerinden söz edilmektedir; bu da verimliliği artırmaktadır.$$, 2, 3),
('02439f00-9323-4e02-bd86-1ad0404b6120','vocabulary',$$Metinde geçen "emilim" kelimesinin anlamı aşağıdakilerden hangisidir?$$,'["Besinlerin mekanik olarak parçalanması","Sindirilen besin maddelerinin kan dolaşımına geçmesi","Besinlerin ağızda çiğnenmesi","Atık maddelerin dışarı atılması"]'::jsonb, 1, $$Emilim; sindirilen küçük moleküllerin bağırsak duvarından geçerek kana karışması sürecidir.$$, 2, 4),
('02439f00-9323-4e02-bd86-1ad0404b6120','detail',$$Proteinlerin sindiriminde kullanılan enzimler aşağıdakilerden hangisidir?$$,'["Amilaz ve lipaz","Pepsin ve tripsin","Safra tuzları ve lipaz","Laktaz ve maltaz"]'::jsonb, 1, $$Pepsin midede, tripsin ince bağırsakta proteinleri parçalayan enzimlerdir.$$, 2, 5);
INSERT INTO text_questions (text_id, question_type, question_text, options, correct_index, explanation, difficulty, order_index) VALUES
('7a0f841d-fb03-4d58-9ad3-b754d0a898ee','main_idea',$$Bu metnin ana fikri nedir?$$,'["Ekosistemler yalnızca canlı varlıklardan oluşur.","Ekosistem; canlı ve cansız unsurların etkileşimiyle oluşan dinamik bir bütündür ve biyoçeşitlilik bu dengeyi korur.","Biyoçeşitlilik yalnızca tropikal bölgelerde önemlidir.","Cansız çevre faktörleri ekosistemleri etkilemez."]'::jsonb, 1, $$Metin, ekosistemi canlı-cansız etkileşimler bütünü olarak tanımlamakta ve biyoçeşitliliğin bu dengedeki rolünü vurgulamaktadır.$$, 2, 1),
('7a0f841d-fb03-4d58-9ad3-b754d0a898ee','detail',$$Metne göre bir türün yok olması ekosistemi nasıl etkiler?$$,'["Hiçbir etkisi olmaz.","Diğer türleri ve besin zincirini olumsuz etkiler.","Yalnızca avcı türleri etkiler.","Ekosistemin daha verimli çalışmasını sağlar."]'::jsonb, 1, $$Bir türün yok olması besin zincirini bozar ve diğer türleri olumsuz etkiler.$$, 2, 2),
('7a0f841d-fb03-4d58-9ad3-b754d0a898ee','inference',$$Bu metne göre biyoçeşitliliğin azalması hakkında ne söylenebilir?$$,'["Biyoçeşitliliğin azalması ekosistem dengesini güçlendirir.","Biyoçeşitliliğin azalması ekosistemlerin çevresel değişimlere direncini düşürür.","Biyoçeşitlilik yalnızca estetik bir değer taşır.","Az sayıda tür içeren ekosistemler daha kararlıdır."]'::jsonb, 1, $$Biyoçeşitlilik ekosistemlere esneklik kazandırır; tür sayısı azaldıkça denge bozulur.$$, 2, 3),
('7a0f841d-fb03-4d58-9ad3-b754d0a898ee','vocabulary',$$Metinde "biyoçeşitlilik" kavramı nasıl tanımlanmaktadır?$$,'["Yalnızca hayvan türlerinin çokluğu","Gen, tür ve ekosistem düzeyinde yaşam çeşitliliği","Sadece bitki türlerinin sayısı","Cansız çevre öğelerinin farklılığı"]'::jsonb, 1, $$Biyoçeşitlilik gen, tür ve ekosistem olmak üç farklı düzeyde değerlendirilir.$$, 2, 4),
('7a0f841d-fb03-4d58-9ad3-b754d0a898ee','detail',$$Aşağıdakilerden hangisi biyoçeşitliliği tehdit eden insan kaynaklı faktörlerden biridir?$$,'["Fotosentez","Habitat yıkımı ve kirlilik","Mevsimsel değişimler","Doğal seçilim"]'::jsonb, 1, $$Habitat yıkımı ve kirlilik, insan faaliyetleri nedeniyle biyoçeşitliliği doğrudan azaltan başlıca etkenlerdir.$$, 2, 5);
INSERT INTO text_questions (text_id, question_type, question_text, options, correct_index, explanation, difficulty, order_index) VALUES
('9874bac9-aca9-4efc-910b-5da233ee8df8','main_idea',$$Metnin ana konusu aşağıdakilerden hangisidir?$$,'["Yalnızca statik elektrik olayları","Elektrik ve manyetizmanın birbirleriyle ilişkili temel fizik kavramları","Yalnızca mıknatısların özellikleri","Elektrik enerjisinin ısıya dönüşümü"]'::jsonb, 1, $$Metin hem elektrik hem manyetizma kavramlarını ve aralarındaki ilişkiyi birlikte ele almaktadır.$$, 3, 1),
('9874bac9-aca9-4efc-910b-5da233ee8df8','detail',$$Metne göre elektromanyetik indüksiyon ne anlama gelir?$$,'["Mıknatısların birbirini itmesi","Değişen manyetik alanın elektrik akımı oluşturması","Elektrik yüklerinin durgun halde bulunması","Iletkenin ısınması"]'::jsonb, 1, $$Elektromanyetik indüksiyon, değişen manyetik alanın bir iletken içinde akım oluşturması olayıdır.$$, 3, 2),
('9874bac9-aca9-4efc-910b-5da233ee8df8','inference',$$Bu metne göre elektrik enerjisinin üretiminde manyetizmanın rolü nedir?$$,'["Manyetizma elektrik üretimiyle ilgisizdir.","Manyetik alan değişimi generatörlerde elektrik üretmek için kullanılır.","Mıknatıslar yalnızca demir çekmek için kullanılır.","Elektrik üretimi yalnızca kimyasal reaksiyonlarla mümkündür."]'::jsonb, 1, $$Generatörler, manyetik alan değişiminden yararlanarak mekanik enerjiyi elektriğe dönüştürür.$$, 3, 3),
('9874bac9-aca9-4efc-910b-5da233ee8df8','vocabulary',$$Metinde geçen "iletken" kelimesi nasıl tanımlanmaktadır?$$,'["Elektrik akımına yüksek direnç gösteren madde","Elektrik yüklerinin kolayca hareket edebildiği madde","Manyetik alan oluşturan cihaz","Elektrik enerjisini depolayan element"]'::jsonb, 1, $$İletkenler, serbest elektronların kolayca hareket edebildiği maddelerdir.$$, 3, 4),
('9874bac9-aca9-4efc-910b-5da233ee8df8','detail',$$Aşağıdakilerden hangisi mıknatıslarda doğru bir bilgidir?$$,'["Mıknatısların yalnızca bir kutbu vardır.","Her mıknatısın kuzey ve güney olmak üzere iki kutbu bulunur.","Aynı kutuplar birbirini çeker.","Mıknatıslar elektriksel yük taşır."]'::jsonb, 1, $$Her mıknatıs N (kuzey) ve S (güney) olmak üzere iki kutupludur; zıt kutuplar çeker, aynı kutuplar iter.$$, 3, 5);
INSERT INTO text_questions (text_id, question_type, question_text, options, correct_index, explanation, difficulty, order_index) VALUES
('2c84c8d1-8143-44f4-812f-3c059ea98869','main_idea',$$Bu metnin ana fikri aşağıdakilerden hangisidir?$$,'["Hücreler yalnızca bitkisel organizmalarda bulunur.","Hücre; yaşamın temel birimi olup farklı organeller aracılığıyla hayati işlevleri gerçekleştirir.","Tüm hücreler aynı yapıda ve işlevdedir.","Organeller yalnızca hayvan hücrelerinde bulunur."]'::jsonb, 1, $$Metin, hücreyi yaşamın temel birimi olarak ele almakta ve organellerin işlevlerini açıklamaktadır.$$, 2, 1),
('2c84c8d1-8143-44f4-812f-3c059ea98869','detail',$$Metne göre mitokondri hangi işlevi gerçekleştirir?$$,'["Protein sentezini gerçekleştirir.","Hücresel solunum yoluyla ATP (enerji) üretir.","Genetik bilgiyi saklar.","Hücreyi dış etkenlerden korur."]'::jsonb, 1, $$Mitokondri, hücresel solunum yoluyla besinlerden ATP enerjisi üreten organeldir.$$, 2, 2),
('2c84c8d1-8143-44f4-812f-3c059ea98869','inference',$$Bitki hücrelerinde kloroplast bulunması hakkında ne çıkarılabilir?$$,'["Bitki hücreleri fotosentez yapamaz.","Kloroplast, bitki hücrelerinin güneş enerjisini besin enerjisine dönüştürmesini sağlar.","Kloroplast yalnızca enerji depolar.","Tüm canlı hücreler kloroplast içerir."]'::jsonb, 1, $$Kloroplast, klorofil pigmentini barındırarak fotosentezi mümkün kılar.$$, 2, 3),
('2c84c8d1-8143-44f4-812f-3c059ea98869','vocabulary',$$Metinde geçen "organel" kavramı ne anlama gelir?$$,'["Hücre dışı yapılar","Hücre içinde belirli işlevleri yerine getiren küçük yapılar","Hücreler arası bağlantı kanalları","Hücre çekirdeğinin zarı"]'::jsonb, 1, $$Organeller, hücre içinde özelleşmiş görevler üstlenen küçük yapı birimleridir.$$, 2, 4),
('2c84c8d1-8143-44f4-812f-3c059ea98869','detail',$$Prokaryot ve ökaryot hücre arasındaki temel fark nedir?$$,'["Prokaryotlarda hücre zarı yoktur.","Ökaryot hücrelerin zarla çevrili bir çekirdeği varken prokaryotlarda yoktur.","Prokaryotlar yalnızca hayvanlarda bulunur.","Ökaryot hücrelerde DNA bulunmaz."]'::jsonb, 1, $$Ökaryot hücrelerin belirgin özelliği, genetik materyalin zarla çevrili bir çekirdekte bulunmasıdır.$$, 2, 5);
INSERT INTO text_questions (text_id, question_type, question_text, options, correct_index, explanation, difficulty, order_index) VALUES
('ab47b8b5-8f9d-4493-8c35-60e0ecb0d8c7','main_idea',$$Bu metnin ana konusu nedir?$$,'["Yalnızca mercekler ve görme kusurları","Işığın farklı ortamlarda nasıl davrandığı ve optik olaylar","Yalnızca güneş spektrumu","Gözün anatomik yapısı"]'::jsonb, 1, $$Metin ışığın kırılması, yansıması ve optik aletlerle olan ilişkisini birlikte ele almaktadır.$$, 3, 1),
('ab47b8b5-8f9d-4493-8c35-60e0ecb0d8c7','detail',$$Işığın kırılması ne zaman gerçekleşir?$$,'["Işık aynı ortamda ilerlediğinde","Işık yoğunlukları farklı iki ortam arasında geçiş yaptığında","Işık tam karanlık bir ortama girdiğinde","Işık yalnızca camdan geçtiğinde"]'::jsonb, 1, $$Kırılma; ışığın farklı yoğunluktaki ortamlar arasında geçiş yaparken yön değiştirmesidir.$$, 3, 2),
('ab47b8b5-8f9d-4493-8c35-60e0ecb0d8c7','inference',$$Gökkuşağının oluşması ışığın hangi özelliğiyle açıklanır?$$,'["Işığın yalnızca yansımasıyla","Işığın prizmada farklı dalga boylarında kırılarak renklerine ayrılmasıyla","Işığın tam yansımasıyla","Işığın emilmesiyle"]'::jsonb, 1, $$Gökkuşağı, güneş ışığının su damlacıklarında kırılarak bileşenlerine ayrılmasıyla oluşur.$$, 3, 3),
('ab47b8b5-8f9d-4493-8c35-60e0ecb0d8c7','vocabulary',$$Metinde "kırılma indisi" kavramı neyi ifade eder?$$,'["Işığın emilim miktarı","Işığın bir ortamdan diğerine geçerken yavaşlama oranını gösteren değer","Ortamın rengi","Işık kaynağının parlaklığı"]'::jsonb, 1, $$Kırılma indisi, ortamın ışığı ne kadar yavaşlattığını ve ışığın ne kadar kırılacağını gösterir.$$, 3, 4),
('ab47b8b5-8f9d-4493-8c35-60e0ecb0d8c7','detail',$$Yakınsak (konveks) mercek nasıl bir görüntü oluşturur?$$,'["Her zaman küçük ve sanal görüntü","Cismin konumuna göre gerçek veya sanal görüntü oluşturabilir.","Her zaman ters ve gerçek görüntü","Hiçbir zaman görüntü oluşturmaz."]'::jsonb, 1, $$Yakınsak mercekler; cismin odak noktasına olan uzaklığına bağlı olarak farklı türde görüntüler oluşturur.$$, 3, 5);
INSERT INTO text_questions (text_id, question_type, question_text, options, correct_index, explanation, difficulty, order_index) VALUES
('556fd77c-3f11-4942-a559-9b9fcb16c41a','main_idea',$$Bu metnin ana fikri aşağıdakilerden hangisidir?$$,'["Teknoloji insan ilişkilerini tamamen yok etmiştir.","Teknoloji günlük hayatın vazgeçilmez bir parçası olmuş; iletişim, eğitim ve sağlık alanlarını dönüştürmüştür.","Akıllı telefonlar gereksiz cihazlardır.","Teknoloji yalnızca işletmelere yarar sağlar."]'::jsonb, 1, $$Metin teknolojinin günlük hayattaki olumlu dönüşümleri üzerine odaklanmakta ve geniş bir etki alanını ele almaktadır.$$, 2, 1),
('556fd77c-3f11-4942-a559-9b9fcb16c41a','detail',$$Metne göre akıllı telefonlar günlük hayatımızı nasıl değiştirmiştir?$$,'["Yalnızca sosyal medyaya erişim sağlamıştır.","İletişim, bilgiye erişim ve çevrimiçi hizmetleri herkesin cebine taşımıştır.","Sadece eğlence amaçlı kullanılmaktadır.","Telefon görüşmelerini ortadan kaldırmıştır."]'::jsonb, 1, $$Akıllı telefonlar, iletişim ve bilgiye erişimi kolaylaştırarak pek çok hizmeti mobilleştirmiştir.$$, 2, 2),
('556fd77c-3f11-4942-a559-9b9fcb16c41a','inference',$$Metne göre teknolojinin sağlık alanındaki etkisi hakkında ne söylenebilir?$$,'["Teknoloji sağlık hizmetlerine hiç katkı sağlamamıştır.","Dijital araçlar hastalık takibini, uzaktan konsültasyonu ve sağlık yönetimini iyileştirmiştir.","Hastaneler teknolojiden faydalanmamaktadır.","Teknoloji yalnızca fiziksel sağlığı olumsuz etkiler."]'::jsonb, 1, $$Metin, dijital araçların sağlık hizmetlerini daha erişilebilir ve etkili kıldığından söz etmektedir.$$, 2, 3),
('556fd77c-3f11-4942-a559-9b9fcb16c41a','vocabulary',$$Metinde geçen "seamless" kelimesinin Türkçe karşılığı nedir?$$,'["Zahmetli","Aksamasız, sorunsuz","Pahalı","Yavaş"]'::jsonb, 1, $$Seamless; kesintisiz, sorunsuz ve akıcı anlamına gelir; teknolojinin günlük hayata entegrasyonunu tanımlar.$$, 2, 4),
('556fd77c-3f11-4942-a559-9b9fcb16c41a','detail',$$Metne göre uzaktan eğitim teknolojisi ne sağlamaktadır?$$,'["Öğrenmeyi yalnızca zenginlere açık hale getirmiştir.","Coğrafi engelleri aşarak kaliteli eğitimi daha geniş kitlelere ulaştırmıştır.","Geleneksel sınıf ortamını tamamen ortadan kaldırmıştır.","Yalnızca üniversite öğrencilerine hitap etmektedir."]'::jsonb, 1, $$Uzaktan eğitim platformları, kaliteli eğitimi fiziksel sınırları kaldırarak herkes için erişilebilir kılmaktadır.$$, 2, 5);
INSERT INTO text_questions (text_id, question_type, question_text, options, correct_index, explanation, difficulty, order_index) VALUES
('170dda74-f3fc-4a6e-997c-c2bb8077adee','main_idea',$$Bu metnin ana fikri nedir?$$,'["Denklemler yalnızca geometride kullanılır.","Denklemler ve eşitsizlikler, günlük hayat problemlerini matematiksel olarak ifade etmeye ve çözmeye yarayan temel araçlardır.","Eşitsizliklerin gerçek hayatta uygulaması yoktur.","Matematik soyut bir bilimdir ve hayatla ilgisi yoktur."]'::jsonb, 1, $$Metin, denklem ve eşitsizlikleri hayatla bağlantılı problem çözme araçları olarak konumlandırmaktadır.$$, 2, 1),
('170dda74-f3fc-4a6e-997c-c2bb8077adee','detail',$$2x + 5 = 13 denkleminin çözümü nedir?$$,'["x = 3","x = 4","x = 9","x = 6"]'::jsonb, 1, $$2x = 13 - 5 = 8, x = 4. Temel denklem çözme adımları uygulanmaktadır.$$, 2, 2),
('170dda74-f3fc-4a6e-997c-c2bb8077adee','inference',$$Metne göre bir eşitsizliği çözerken negatif sayıyla çarpmak neden özel dikkat gerektirir?$$,'["Negatif sayıyla çarpmak yasaktır.","Negatif sayıyla çarpma veya bölmede eşitsizliğin yönü tersine döner.","Negatif sayılar eşitsizlikte kullanılamaz.","Eşitsizliğin yönü hiçbir işlemde değişmez."]'::jsonb, 1, $$Eşitsizliklerde negatif sayıyla çarpma/bölme yapıldığında büyüktür/küçüktür işareti yer değiştirir.$$, 2, 3),
('170dda74-f3fc-4a6e-997c-c2bb8077adee','vocabulary',$$Metinde "bilinmeyen" terimi ne anlama gelir?$$,'["Denklemde bilinen sabit değer","Değeri bulmak istediğimiz ve genellikle x,y,z ile gösterilen değişken","Sayı doğrusundaki negatif bölge","Eşitsizliğin çözüm kümesi"]'::jsonb, 1, $$Bilinmeyen; değeri henüz belirlenmemiş ve denklem ya da eşitsizlik aracılığıyla bulunmaya çalışılan değişkendir.$$, 2, 4),
('170dda74-f3fc-4a6e-997c-c2bb8077adee','detail',$$3x - 2 > 7 eşitsizliğinin çözüm kümesi nedir?$$,'["x < 3","x > 3","x = 3","x ≤ 3"]'::jsonb, 1, $$3x > 9, x > 3. Eşitsizlik aynı yönde korunur çünkü pozitif sayıyla bölünmüştür.$$, 2, 5);
INSERT INTO text_questions (text_id, question_type, question_text, options, correct_index, explanation, difficulty, order_index) VALUES
('62a9f9cf-3995-4108-bcf9-c4e583041a10','main_idea',$$Bu metnin ana fikri aşağıdakilerden hangisidir?$$,'["Olasılık yalnızca kumar oyunlarında kullanılır.","Olasılık ve istatistik; verileri analiz edip yorumlamamızı ve belirsiz durumlar hakkında bilinçli kararlar almamızı sağlar.","İstatistik yalnızca ekonomistler için gereklidir.","Veri toplamak her zaman yanıltıcı sonuçlar doğurur."]'::jsonb, 1, $$Metin, olasılık ve istatistiği karar alma ve veri yorumlama açısından ele almaktadır.$$, 3, 1),
('62a9f9cf-3995-4108-bcf9-c4e583041a10','detail',$$Bir madeni paranın atılmasında yazı gelme olasılığı kaçtır?$$,'["1/4","1/3","1/2","2/3"]'::jsonb, 2, $$Adil bir madeni parada tura ve yazı olmak üzere 2 eşit olası sonuç vardır; P(yazı) = 1/2.$$, 3, 2),
('62a9f9cf-3995-4108-bcf9-c4e583041a10','inference',$$Metne göre büyük bir örneklem kullanmanın istatistiksel analiz açısından önemi nedir?$$,'["Büyük örneklem her zaman hatalı sonuç verir.","Büyük örneklem, örneklem hatasını azaltarak bulgular ile ana kütle arasındaki farkı küçültür.","Küçük örneklemler daha doğru sonuç verir.","Örneklem büyüklüğü sonuçları etkilemez."]'::jsonb, 1, $$Örneklem ne kadar büyük olursa, elde edilen sonuçlar ana kütleye o kadar yakın olur.$$, 3, 3),
('62a9f9cf-3995-4108-bcf9-c4e583041a10','vocabulary',$$Metinde geçen "ortalama" kavramı istatistikte ne anlama gelir?$$,'["Veri setinin en sık tekrar eden değeri","Veri setinin tüm değerlerinin toplamının veri sayısına bölünmesiyle elde edilen değer","Veri setinin ortadaki değeri","Veri setinin en büyük ve en küçük değerinin farkı"]'::jsonb, 1, $$Aritmetik ortalama; tüm değerlerin toplamının veri sayısına bölünmesiyle hesaplanır.$$, 3, 4),
('62a9f9cf-3995-4108-bcf9-c4e583041a10','detail',$$Aşağıdakilerden hangisi istatistiğin gerçek hayat uygulama alanlarından birini doğru şekilde ifade eder?$$,'["İstatistik gerçek hayatta kullanılmaz.","Hava durumu tahmini, seçim anketleri ve sağlık araştırmalarında olasılık ve istatistik kullanılır.","Olasılık yalnızca sınav sorularında çıkar.","Istatistik yalnızca geçmiş verileri gösterir, gelecek hakkında bilgi vermez."]'::jsonb, 1, $$İstatistik ve olasılık; meteoroloji, tıp, sosyal bilimler ve mühendislik gibi pek çok alanda karar vermeye yardımcı olur.$$, 3, 5);
INSERT INTO text_questions (text_id, question_type, question_text, options, correct_index, explanation, difficulty, order_index) VALUES
('11ed226a-51f9-4898-9b1c-d12c9a811a8c','main_idea',$$Bu metnin ana fikri nedir?$$,'["Türkiye yalnızca İç Anadolu Bölgesi''nden oluşmaktadır.","Türkiye, farklı iklim ve coğrafi özelliklere sahip 7 bölgesinden oluşan çeşitli bir coğrafyaya sahiptir.","Tüm Türkiye bölgeleri aynı iklim tipine sahiptir.","Coğrafi bölgeler yalnızca idari amaçlarla belirlenmiştir."]'::jsonb, 1, $$Metin, Türkiye''nin coğrafi çeşitliliğini ve 7 bölgesinin birbirinden farklı özelliklerini aktarmaktadır.$$, 2, 1),
('11ed226a-51f9-4898-9b1c-d12c9a811a8c','detail',$$Karadeniz Bölgesi''ni diğer bölgelerden ayıran temel özellik nedir?$$,'["En az yağış alan bölge olması","Dört mevsim yağış alması ve yoğun orman örtüsüne sahip olması","En fazla tarım yapılan bölge olması","Türkiye''nin en geniş ovalarını barındırması"]'::jsonb, 1, $$Karadeniz Bölgesi, dört mevsim yağış alması ve sık ormanlarıyla diğer bölgelerden ayrılır.$$, 2, 2),
('11ed226a-51f9-4898-9b1c-d12c9a811a8c','inference',$$Metne göre Türkiye''nin coğrafi çeşitliliği nasıl bir sonuç doğurur?$$,'["Ülke yönetimini zorlaştırmaktan başka bir etkisi yoktur.","Farklı tarım ürünleri yetiştirilmesine, turizme ve zengin biyoçeşitliliğe zemin hazırlar.","Tüm bölgeler aynı ekonomik faaliyetlere yönelir.","Coğrafi çeşitlilik ticaret için dezavantajdır."]'::jsonb, 1, $$Coğrafi çeşitlilik farklı iklim ve toprak yapıları sayesinde ülkenin ekonomik ve biyolojik zenginliğini artırır.$$, 2, 3),
('11ed226a-51f9-4898-9b1c-d12c9a811a8c','vocabulary',$$Metinde "step iklimi" kavramı ne anlama gelir?$$,'["Çok yağışlı ve nemli iklim","Az yağışlı, sert kışlar ve sıcak yazlarla karakterize, geniş düzlüklerin görüldüğü iklim","Ilıman Akdeniz iklimi","Yüksek rakımda görülen soğuk iklim"]'::jsonb, 1, $$Step iklimi; az yağışlı, yarı kurak olup kışlar sert, yazlar sıcak geçen ve çayır-bozkır bitki örtüsünün hâkim olduğu iklim tipidir.$$, 2, 4),
('11ed226a-51f9-4898-9b1c-d12c9a811a8c','detail',$$Ege ve Akdeniz bölgelerinin ortak iklim özelliği nedir?$$,'["Her iki bölgede de dört mevsim eşit yağış görülür.","Her iki bölge de Akdeniz iklimine sahiptir; yazlar sıcak ve kurak, kışlar ılık ve yağışlıdır.","İki bölge de karasal iklime sahiptir.","Yazın kar yağışı görülen tek bölgelerdir."]'::jsonb, 1, $$Ege ve Akdeniz bölgelerinde yazlar sıcak-kurak, kışlar ılık-yağışlı olan Akdeniz iklimi hâkimdir.$$, 2, 5);
INSERT INTO text_questions (text_id, question_type, question_text, options, correct_index, explanation, difficulty, order_index) VALUES
('81c8b9ef-bdc2-4597-8ad7-94b2f475d883','main_idea',$$Bu metnin ana fikri nedir?$$,'["Anadolu yalnızca Osmanlılar tarafından yurt edinilmiştir.","Anadolu, binlerce yıl boyunca çeşitli medeniyetlere ev sahipliği yapmış ve insanlık tarihine büyük katkılar sağlamıştır.","Anadolu medeniyetleri birbirinden etkilenmemiştir.","Hitit medeniyeti Anadolu''da kurulan tek önemli uygarlıktır."]'::jsonb, 1, $$Metin, Anadolu''nun çok katmanlı medeniyet birikimini ve farklı kültürlerin bu topraklara katkılarını ele almaktadır.$$, 2, 1),
('81c8b9ef-bdc2-4597-8ad7-94b2f475d883','detail',$$Hitit medeniyeti hangi alanda öne çıkmıştır?$$,'["Denizcilik ve deniz ticareti","Demir işlemeciliği ve hukuk alanındaki gelişmiş düzenlemeler","Büyük sulama sistemleri","Felsefe ve doğa bilimleri"]'::jsonb, 1, $$Hititler, demir kullanımını yaygınlaştırmaları ve yazılı hukuk gelenekleri ile öne çıkmıştır.$$, 2, 2),
('81c8b9ef-bdc2-4597-8ad7-94b2f475d883','inference',$$Metne göre Anadolu''nun "medeniyetlerin beşiği" olarak anılmasının nedeni nedir?$$,'["Anadolu coğrafi olarak dünyanın merkezindedir.","Sürekli göçler, verimli topraklar ve stratejik konum, farklı uygarlıkların Anadolu''da gelişmesini sağlamıştır.","Anadolu yalnızca büyük savaşlara sahne olmuştur.","Doğal kaynaklar bakımından dünyanın en zengin topraklarıdır."]'::jsonb, 1, $$Anadolu''nun stratejik konumu, verimli toprakları ve köprü görevi, birçok medeniyetin burada kök salmasını sağlamıştır.$$, 2, 3),
('81c8b9ef-bdc2-4597-8ad7-94b2f475d883','vocabulary',$$Metinde "uygarlık" (medeniyet) kelimesi nasıl kullanılmaktadır?$$,'["Belirli bir toprak parçasının adı","Yazı, hukuk, sanat ve teknoloji gibi alanlarda gelişmiş insan topluluğunun oluşturduğu kültürel birikim","Yalnızca kentsel nüfusun adı","Büyük askeri imparatorlukların ortak adı"]'::jsonb, 1, $$Medeniyet; yazı, hukuk, sanat, mimari ve teknolojik gelişmelerin birleşimiyle ortaya çıkan kültürel bütündür.$$, 2, 4),
('81c8b9ef-bdc2-4597-8ad7-94b2f475d883','detail',$$Anadolu''da kurulan uygarlıkların ortak özelliği nedir?$$,'["Hepsi aynı dili konuşmuştur.","Hepsi tarım yapılabilen verimli alanlarda kurulmuş ve ticaret yolları üzerinde yer almıştır.","Hepsi deniz kıyısında yaşamıştır.","Hiçbirinde yazı sistemi gelişmemiştir."]'::jsonb, 1, $$Anadolu''daki uygarlıklar genellikle verimli tarım arazilerine ve önemli ticaret güzergahlarına yakın konumda gelişmiştir.$$, 2, 5);
INSERT INTO text_questions (text_id, question_type, question_text, options, correct_index, explanation, difficulty, order_index) VALUES
('37858831-cab0-4f62-b9fb-1c9d13a153ed','main_idea',$$Bu metnin ana fikri aşağıdakilerden hangisidir?$$,'["Osmanlı Devleti yalnızca askeri güce dayanmıştır.","Osmanlı''nın yükseliş dönemi; askeri zaferler, güçlü yönetim anlayışı ve hoşgörülü politikaların bir arada işlemesiyle gerçekleşmiştir.","Osmanlı''nın yükselişi yalnızca coğrafi şansa bağlıdır.","Fatih Sultan Mehmet Osmanlı''yı kuran padişahtır."]'::jsonb, 1, $$Metin, Osmanlı''nın yükselişini çok boyutlu bir süreç olarak ele almakta; askeri, siyasi ve kültürel faktörleri birlikte değerlendirmektedir.$$, 2, 1),
('37858831-cab0-4f62-b9fb-1c9d13a153ed','detail',$$İstanbul''un fethinin Osmanlı açısından önemi nedir?$$,'["İstanbul yalnızca ticari açıdan önemlidir.","İstanbul''un fethi Osmanlı''yı dünya sahnesinin merkezine taşımış ve Doğu Roma''nın sona ermesine neden olmuştur.","Fetih yalnızca siyasi bir prestij kazanımıdır.","İstanbul o dönemde küçük ve önemsiz bir şehirdi."]'::jsonb, 1, $$İstanbul''un 1453''te fethi hem Orta Çağ''ı simgesel olarak sonlandırmış hem de Osmanlı''ya büyük bir stratejik ve sembolik güç kazandırmıştır.$$, 2, 2),
('37858831-cab0-4f62-b9fb-1c9d13a153ed','inference',$$Osmanlı''nın farklı din ve kültürleri bir arada tutabilmesi hakkında ne çıkarılabilir?$$,'["Osmanlı diğer kültürleri tamamen asimile etmiştir.","Millet sistemi ve hoşgörülü yönetim anlayışı, farklı toplulukların bir arada barış içinde yaşamasını sağlamıştır.","Osmanlı''da dinî azınlıklar hiçbir hakka sahip değildi.","Kültürel çeşitlilik devlet için sürekli bir tehdit unsuruydu."]'::jsonb, 1, $$Osmanlı''nın millet sistemi, gayrimüslim topluluklara kendi iç işlerinde özerklik tanıyarak birliği pekiştirmiştir.$$, 2, 3),
('37858831-cab0-4f62-b9fb-1c9d13a153ed','vocabulary',$$Metinde geçen "devşirme sistemi" ne anlama gelir?$$,'["Vergi toplama yöntemi","Hristiyan ailelerin çocuklarının devlet hizmetine alınarak yetiştirildiği Osmanlı insan kaynağı sistemi","Toprak dağıtım politikası","Ticaret güzergahlarını kontrol eden askeri düzen"]'::jsonb, 1, $$Devşirme; genç Hristiyan erkeklerin Osmanlı devlet hizmetine alınarak yetiştirildiği ve önemli görevlere atandığı sistemdir.$$, 2, 4),
('37858831-cab0-4f62-b9fb-1c9d13a153ed','detail',$$Osmanlı''nın Avrupa''daki ilerleyişini durduran olay nedir?$$,'["Çanakkale Savaşı","1683''te Viyana önünde yaşanan yenilgi ve kuşatmanın başarısızlıkla sonuçlanması","Haçlı Seferleri","Otlukbeli Savaşı"]'::jsonb, 1, $$1683 Viyana Kuşatması''nın başarısızlıkla sonuçlanması, Osmanlı''nın Batı''ya doğru genişlemesinin durma noktasının simgesi olmuştur.$$, 2, 5);
INSERT INTO text_questions (text_id, question_type, question_text, options, correct_index, explanation, difficulty, order_index) VALUES
('ab7e2fdd-8829-43ef-b499-7424dede2ff6','main_idea',$$Bu metnin ana fikri nedir?$$,'["Türkçede yalnızca isim ve fiil olmak üzere iki sözcük türü vardır.","Türkçede sözcükler işlevlerine göre sınıflandırılır; bu sınıflandırma dilin doğru ve etkili kullanılmasını kolaylaştırır.","Sözcük türleri yalnızca gramer sınavları için önemlidir.","Tüm sözcükler aynı işlevi görmektedir."]'::jsonb, 1, $$Metin, sözcük türlerini işlevsel sınıflandırma sistemi olarak ele almakta ve dilin doğru kullanımındaki rolünü vurgulamaktadır.$$, 1, 1),
('ab7e2fdd-8829-43ef-b499-7424dede2ff6','detail',$$Aşağıdakilerden hangisi bir sıfatın temel özelliğidir?$$,'["Bir eylemi ifade eder.","Bir ismi niteleyerek ona renk, şekil, büyüklük vb. özellik katar.","Cümle içindeki yeri her zaman öznedir.","Yalnızca sayılarla birlikte kullanılır."]'::jsonb, 1, $$Sıfatlar, isimleri niteleyen ya da belirten kelimelerdir ve ismin önünde yer alır.$$, 1, 2),
('ab7e2fdd-8829-43ef-b499-7424dede2ff6','inference',$$"Hızlı araba geçti." cümlesinde altı çizili sözcük türü ne olur?$$,'["Zarf","Sıfat","Fiil","Zamir"]'::jsonb, 1, $$"Hızlı" kelimesi "araba" ismini nitelediği için sıfattır.$$, 1, 3),
('ab7e2fdd-8829-43ef-b499-7424dede2ff6','vocabulary',$$Metinde "zamir" kavramı nasıl tanımlanmaktadır?$$,'["Bir eylemi ifade eden sözcük türü","İsmin yerine geçen, onu tekrar etmeden işaret eden sözcük","Zaman ve durum bildiren sözcük","Cümleye ek anlam katan bağlaç"]'::jsonb, 1, $$Zamirler; isimlerin yerine geçerek tekrarı önleyen sözcüklerdir (ben, sen, o, bu vb.).$$, 1, 4),
('ab7e2fdd-8829-43ef-b499-7424dede2ff6','detail',$$Aşağıdakilerden hangisi bir zarftır?$$,'["Güzel","Masada","Koşmak","Çabucak"]'::jsonb, 3, $$"Çabucak" bir eylemi nasıl yapıldığını nitelediği için zarftır; "güzel" sıfat, "masada" isim, "koşmak" fiildir.$$, 1, 5);
INSERT INTO text_questions (text_id, question_type, question_text, options, correct_index, explanation, difficulty, order_index) VALUES
('4f934385-ef45-46c1-8676-bd7a96c2fc15','main_idea',$$Bu metnin ana fikri aşağıdakilerden hangisidir?$$,'["Demokrasi yalnızca seçimlerden ibarettir.","Demokrasi; hukukun üstünlüğü, temel haklar ve aktif vatandaşlık ilkeleriyle işleyen, koruma altına alınması gereken bir yönetim biçimidir.","Temel haklar yalnızca belirli grupları kapsar.","Sivil toplum kuruluşlarının demokrasiyle ilgisi yoktur."]'::jsonb, 1, $$Metin, demokrasiyi yalnızca seçim sistemi olarak değil; haklar, hukuk ve katılım üçgeninde ele almaktadır.$$, 2, 1),
('4f934385-ef45-46c1-8676-bd7a96c2fc15','detail',$$Metne göre ifade özgürlüğünün sınırları nelerdir?$$,'["İfade özgürlüğü hiçbir sınır tanımaz.","Başkalarına zarar vermemek ve kamu düzenini bozmamak koşuluyla ifade özgürlüğü güvence altındadır.","İfade özgürlüğü yalnızca basın mensuplarına tanınmıştır.","Devlet her türlü ifadeyi sansürleyebilir."]'::jsonb, 1, $$İfade özgürlüğü temel bir hak olmakla birlikte başkalarının haklarına zarar vermeme ve kamu düzenini koruma sınırları dahilinde işler.$$, 2, 2),
('4f934385-ef45-46c1-8676-bd7a96c2fc15','inference',$$Metne göre aktif vatandaşlık demokrasi için neden önemlidir?$$,'["Vatandaşların katılımı seçim süreçlerini yavaşlatır.","Bilinçli ve katılımcı vatandaşlar, hesap verebilirliği güçlendirir ve demokratik değerleri korur.","Demokrasi vatandaş katılımı gerektirmez.","Aktif vatandaşlık yalnızca seçilmiş temsilcilerin görevidir."]'::jsonb, 1, $$Aktif vatandaşlar seçimler, kamuoyu ve sivil toplum aracılığıyla demokrasinin işleyişini denetler ve güçlendirir.$$, 2, 3),
('4f934385-ef45-46c1-8676-bd7a96c2fc15','vocabulary',$$Metinde geçen "hukukun üstünlüğü" ne anlama gelir?$$,'["Yargının diğer tüm kurumları yönetmesi","Yasa önünde herkese eşit muamele edilmesi; hiçbir bireyin ya da kurumun yasaların üzerinde olmaması","Güçlü devletlerin zayıf devletlere hükmetmesi","Hukuk sisteminin değiştirilememesi"]'::jsonb, 1, $$Hukukun üstünlüğü; herkese yasalar önünde eşit muamele edilmesi ve hiçbir kişi ya da kurumun yasa dışı davranamaması ilkesidir.$$, 2, 4),
('4f934385-ef45-46c1-8676-bd7a96c2fc15','detail',$$Aşağıdakilerden hangisi temel insan haklarından biri değildir?$$,'["Yaşam hakkı","Eğitim hakkı","Sınırsız zenginlik hakkı","Adil yargılanma hakkı"]'::jsonb, 2, $$Sınırsız zenginlik bir temel hak değildir; yaşam, eğitim ve adil yargılanma evrensel insan hakları arasında sayılmaktadır.$$, 2, 5);
INSERT INTO text_questions (text_id, question_type, question_text, options, correct_index, explanation, difficulty, order_index) VALUES
('83729042-cc5a-44fd-b664-a87573c0ec36','main_idea',$$Bu metnin ana fikri aşağıdakilerden hangisidir?$$,'["DNA yalnızca adli tıpta kullanılmaktadır.","DNA''nın yapısının ve işlevinin keşfi, tıp, tarım ve biyoteknolojide köklü değişimlere yol açan bir devrim niteliği taşımaktadır.","Genetik araştırmalar yalnızca laboratuvar ortamında anlam ifade eder.","Watson ve Crick DNA''yı tek başlarına keşfetmiştir."]'::jsonb, 1, $$Metin, DNA keşfini ve bunun genetik bilimine yaptığı devrimsel etkiyi merkeze almaktadır.$$, 3, 1),
('83729042-cc5a-44fd-b664-a87573c0ec36','detail',$$DNA''nın çift sarmal yapısını kim tanımlamıştır?$$,'["Gregor Mendel","Watson ve Crick","Louis Pasteur","Charles Darwin"]'::jsonb, 1, $$James Watson ve Francis Crick, 1953 yılında Rosalind Franklin''in X ışını verisinden de yararlanarak DNA''nın çift sarmal yapısını ortaya koymuştur.$$, 3, 2),
('83729042-cc5a-44fd-b664-a87573c0ec36','inference',$$İnsan Genomu Projesi''nin tamamlanması hakkında ne çıkarılabilir?$$,'["Proje yalnızca akademik öneme sahiptir.","İnsan genomunun haritalanması, kalıtsal hastalıkların teşhis ve tedavisinde kişiselleştirilmiş tıbbın önünü açmıştır.","Projenin günlük tıbbi uygulamalarla ilgisi yoktur.","Genom projesi DNA''nın varlığını kanıtlamak için yapılmıştır."]'::jsonb, 1, $$İnsan genomunu bilmek, hastalık risklerini öngörmeyi ve bireye özel tedavi yaklaşımlarını geliştirmeyi mümkün kılmaktadır.$$, 3, 3),
('83729042-cc5a-44fd-b664-a87573c0ec36','vocabulary',$$Metinde geçen "gen" kavramı nasıl tanımlanmaktadır?$$,'["Tüm DNA zincirinin adı","Belirli bir proteini kodlayan ve kalıtsal özellikleri taşıyan DNA''nın işlevsel birimi","Hücre çekirdeğinin koruyucu zarı","Protein sentezini gerçekleştiren organel"]'::jsonb, 1, $$Gen; DNA üzerinde belirli bir proteini kodlayan ve kalıtsal bilgiyi taşıyan işlevsel birimdir.$$, 3, 4),
('83729042-cc5a-44fd-b664-a87573c0ec36','detail',$$CRISPR-Cas9 teknolojisinin önemi nedir?$$,'["Yalnızca bitkisel gen araştırmalarında kullanılır.","DNA''yı hassas biçimde düzenleme imkânı sunarak kalıtsal hastalıkların tedavisinde ve tarımsal iyileştirmelerde devrim yaratmaktadır.","Yalnızca klonlama amacıyla geliştirilmiştir.","CRISPR DNA''yı kopyalamak için kullanılan bir araçtır."]'::jsonb, 1, $$CRISPR-Cas9, belirli gen dizilerini kesip değiştirerek hastalık tedavisi ve biyoteknolojik uygulamalarda çığır açmaktadır.$$, 3, 5);
INSERT INTO text_questions (text_id, question_type, question_text, options, correct_index, explanation, difficulty, order_index) VALUES
('17a5ccde-874b-4093-8581-c50beb9f7e4c','main_idea',$$Bu metnin ana fikri nedir?$$,'["Enzimler yalnızca sindirim sistemi için üretilir.","Enzimler; biyolojik katalizörler olarak metabolik reaksiyonları hızlandırır ve yaşamsal süreçlerin sürdürülmesinde kilit rol oynar.","Metabolizma yalnızca fiziksel egzersiz sırasında aktif olur.","Tüm enzimler aynı reaksiyon türünü katalize eder."]'::jsonb, 1, $$Metin, enzimlerin biyolojik katalizör işlevini ve metabolizmayla ilişkisini ele almaktadır.$$, 3, 1),
('17a5ccde-874b-4093-8581-c50beb9f7e4c','detail',$$Enzimlerin çalışma hızını etkileyen faktörler nelerdir?$$,'["Yalnızca substrat konsantrasyonu","Sıcaklık, pH, substrat konsantrasyonu ve enzim miktarı","Yalnızca sıcaklık","Yalnızca pH değeri"]'::jsonb, 1, $$Enzim aktivitesi; sıcaklık, pH, substrat ve enzim konsantrasyonu gibi birden fazla faktör tarafından etkilenir.$$, 3, 2),
('17a5ccde-874b-4093-8581-c50beb9f7e4c','inference',$$Enzimin denatüre olması hakkında ne çıkarılabilir?$$,'["Denatürasyon enzimlerin etkinliğini artırır.","Aşırı sıcaklık ya da pH değişimleri enzimin üç boyutlu yapısını bozarak işlevsiz kılabilir.","Denatüre enzimler normal faaliyetlerini sürdürür.","Denatürasyon yalnızca besin enzimlerini etkiler."]'::jsonb, 1, $$Denatürasyon, aktif bölgenin şeklini bozarak enzimin substratına bağlanmasını engeller.$$, 3, 3),
('17a5ccde-874b-4093-8581-c50beb9f7e4c','vocabulary',$$Metinde geçen "aktif bölge" kavramı ne anlama gelir?$$,'["Enzimlerin üretildiği hücre organeli","Substratın bağlandığı, enzimin özgünlüğünü belirleyen özel yapısal bölge","Tüm enzim molekülünün yüzey alanı","Reaksiyon ürünlerinin salındığı bölge"]'::jsonb, 1, $$Aktif bölge; substratın enzime özgül biçimde bağlandığı ve katalitik reaksiyonun gerçekleştiği kısımdır.$$, 3, 4),
('17a5ccde-874b-4093-8581-c50beb9f7e4c','detail',$$Anabolizma ve katabolizma arasındaki temel fark nedir?$$,'["İkisi aynı metabolik süreçtir.","Anabolizma karmaşık moleküller inşa ederken katabolizma onları enerji açığa çıkarmak için parçalar.","Anabolizma enerji açığa çıkarır, katabolizma enerji kullanır.","Anabolizma yalnızca kaslarda gerçekleşir."]'::jsonb, 1, $$Anabolizma (yapıcı) basit moleküllerden kompleks yapılar sentezler; katabolizma (yıkıcı) ise büyük molekülleri parçalayarak enerji üretir.$$, 3, 5);
INSERT INTO text_questions (text_id, question_type, question_text, options, correct_index, explanation, difficulty, order_index) VALUES
('d26fa528-607e-484d-a587-445dc5922c87','main_idea',$$Bu metnin ana fikri aşağıdakilerden hangisidir?$$,'["Sinir sistemi yalnızca beyin ve omurilikten oluşur.","Sinir sistemi; vücudu çevresiyle koordineli biçimde hareket ettiren, uyarıları ileten ve yanıt üreten karmaşık bir ağ oluşturur.","Nöronlar yalnızca kol ve bacaklarda bulunur.","Merkezi sinir sistemi refleks hareketlerini kontrol etmez."]'::jsonb, 1, $$Metin, sinir sistemini bilgi iletimi ve koordinasyon sağlayan bütüncül bir ağ olarak tanımlamaktadır.$$, 3, 1),
('d26fa528-607e-484d-a587-445dc5922c87','detail',$$Bir nöronda sinirsel uyarı hangi yönde iletilir?$$,'["Aksondan dendrite","Dendritten akson terminallerine doğru","Hücre gövdesinden dendritlere doğru","Her iki yönde eşit olarak"]'::jsonb, 1, $$Uyarılar dendritlerden hücre gövdesine, oradan da akson boyunca sinaps terminallerine doğru tek yönlü iletilir.$$, 3, 2),
('d26fa528-607e-484d-a587-445dc5922c87','inference',$$Miyelin kılıfının hasar görmesi nasıl bir sonuç doğurur?$$,'["Sinirsel iletim hızlanır.","Sinirsel iletim yavaşlar ve çeşitli nörolojik semptomlar ortaya çıkar; MS hastalığında olduğu gibi.","Miyelin kılıfı sinirsel iletimle ilgisizdir.","Sadece hafıza işlevleri etkilenir."]'::jsonb, 1, $$Miyelin kılıfı uyarı iletimini hızlandırır; hasar görünce iletim yavaşlar ve çeşitli nörolojik belirtiler ortaya çıkabilir.$$, 3, 3),
('d26fa528-607e-484d-a587-445dc5922c87','vocabulary',$$Metinde "sinaps" kavramı nasıl tanımlanmaktadır?$$,'["Nöronun hücre gövdesi","İki nöron arasında kimyasal sinyalin aktarıldığı boşluk","Beynin dış koruyucu zarı","Kas ve sinir arasındaki yapısal bağlantı"]'::jsonb, 1, $$Sinaps; nöronlar (ya da nöron-kas) arasındaki bağlantı noktasıdır; nörotransmitter molekülleri aracılığıyla sinyal aktarımı gerçekleşir.$$, 3, 4),
('d26fa528-607e-484d-a587-445dc5922c87','detail',$$Otonom sinir sistemi hangi işlevlerden sorumludur?$$,'["Bilinçli iskelet kası hareketleri","Kalp atışı, sindirim ve solunum gibi istemsiz işlevler","Yalnızca ağrı sinyallerinin iletimi","Duyusal bilginin işlenmesi"]'::jsonb, 1, $$Otonom sinir sistemi; bilinçli kontrol dışında çalışan iç organ işlevlerini (kalp, akciğer, sindirim) düzenler.$$, 3, 5);
INSERT INTO text_questions (text_id, question_type, question_text, options, correct_index, explanation, difficulty, order_index) VALUES
('12153ab3-9fbe-4bd0-bc44-f0c21d359af8','main_idea',$$Bu metnin ana fikri nedir?$$,'["Cumhuriyet dönemi şiiri Divan edebiyatının devamıdır.","Cumhuriyet dönemi Türk şiiri; hece ölçüsüne yöneliş, serbest nazım ve toplumsal içerik açısından önceki dönemden belirgin biçimde ayrılan çok sesli bir çizgi izlemiştir.","Türk şiiri Cumhuriyet döneminde yalnızca lirik içerikle sınırlı kalmıştır.","Garip hareketi Divan şiirini canlandırmayı amaçlamıştır."]'::jsonb, 1, $$Metin, Cumhuriyet dönemi şiirini önceki dönemden kopuş ve çeşitlenme süreci olarak ele almaktadır.$$, 3, 1),
('12153ab3-9fbe-4bd0-bc44-f0c21d359af8','detail',$$Garip hareketi Türk şiirinde nasıl bir değişim başlatmıştır?$$,'["Aruz ölçüsünü yeniden canlandırmıştır.","Orhan Veli, Melih Cevdet ve Oktay Rifat öncülüğünde kalıplaşmış imgeleri reddederek sıradan insan deneyimini şiire taşımıştır.","Yalnızca milliyetçi temalar işlemiştir.","Divan şiiri biçimlerini modern içerikle yenilemiştir."]'::jsonb, 1, $$Garip; aruz ve kalıp imgelerden uzaklaşarak gündelik dili ve sıradan insanı şiirin merkezine taşımıştır.$$, 3, 2),
('12153ab3-9fbe-4bd0-bc44-f0c21d359af8','inference',$$Nazım Hikmet''in şiirlerinin serbest nazım kullanması ve toplumsal içerik taşıması hakkında ne çıkarılabilir?$$,'["Nazım Hikmet siyasi boyuta ilgi duymamıştır.","Şiiri hem biçimsel hem tematik açıdan yenileyerek edebiyatı toplumsal eleştiri aracına dönüştürmüştür.","Serbest nazım Türk okuyucular tarafından hiç benimsenmemiştir.","Toplumsal içerik şiirsel değeri düşürmektedir."]'::jsonb, 1, $$Nazım Hikmet; serbest nazımı ve sosyal temaları birleştirerek Türk şiirini hem biçimsel hem ideolojik açıdan dönüştürmüştür.$$, 3, 3),
('12153ab3-9fbe-4bd0-bc44-f0c21d359af8','vocabulary',$$Metinde geçen "serbest nazım" ne anlama gelir?$$,'["Uyak ve ölçü zorunluluğu taşıyan şiir biçimi","Belirli bir ölçü ya da uyak zorunluluğu olmaksızın yazılan şiir","Yalnızca hece ölçüsüyle yazılan şiir","Müzik eşliğinde icra edilen şiir"]'::jsonb, 1, $$Serbest nazım; geleneksel ölçü ve uyak kurallarına uymayan, şairin biçim üzerinde tam özgürlük kullandığı şiir türüdür.$$, 3, 4),
('12153ab3-9fbe-4bd0-bc44-f0c21d359af8','detail',$$İkinci Yeni akımının özellikleri nelerdir?$$,'["Açık ve anlaşılır bir dil kullanılmıştır.","Kapalı imgeler, soyut dil ve bireysel iç dünyayı ön plana çıkaran deneysel bir şiir anlayışı benimsenmiştir.","Toplumcu gerçekçilik ilkesine dayanmaktadır.","Folklorik öğeleri şiire taşımayı amaçlamıştır."]'::jsonb, 1, $$İkinci Yeni; alışılmışın dışında imgeler ve soyut dil kullanarak bireyin iç dünyasına odaklanmıştır.$$, 3, 5);
INSERT INTO text_questions (text_id, question_type, question_text, options, correct_index, explanation, difficulty, order_index) VALUES
('aee1cf3b-d508-4155-9ab7-062eb78d7db7','main_idea',$$Bu metnin ana fikri nedir?$$,'["Tanzimat dönemi edebiyatçıları yalnızca çeviri yapmıştır.","Tanzimat edebiyatı; Batı etkisiyle şekillenen ve geleneksel Osmanlı edebiyatından kopuşu temsil eden bir modernleşme sürecidir.","Tanzimat döneminde edebiyat toplumsal sorunlarla ilgilenmemiştir.","Namık Kemal yalnızca tiyatro alanında eserler vermiştir."]'::jsonb, 1, $$Metin, Tanzimat edebiyatını Batılılaşma süreciyle özdeşleşmiş bir modernleşme hareketi olarak konumlandırmaktadır.$$, 3, 1),
('aee1cf3b-d508-4155-9ab7-062eb78d7db7','detail',$$Namık Kemal Tanzimat edebiyatına nasıl bir katkı sağlamıştır?$$,'["Yalnızca şiir yazmıştır.","Vatan, özgürlük ve hürriyet temalarını edebiyata taşıyarak toplumsal değişimi teşvik etmiştir.","Geleneksel Divan şiirini savunmuştur.","Yalnızca Fransız romanlarını Türkçeye çevirmiştir."]'::jsonb, 1, $$Namık Kemal; tiyatro, roman ve gazete yazıları aracılığıyla vatanseverlik ve özgürlük temalarını işlemiştir.$$, 3, 2),
('aee1cf3b-d508-4155-9ab7-062eb78d7db7','inference',$$Tanzimat yazarlarının roman türünü benimsemesi hakkında ne söylenebilir?$$,'["Roman Türk okuyuculardan hiç ilgi görmemiştir.","Roman; toplumsal konuları geniş kitlelere ulaştıran, sosyal eleştiri için uygun bir araç olarak benimsenmiştir.","Tanzimat yazarları romanı yalnızca eğlence amaçlı kullanmıştır.","Roman türü Batı''dan herhangi bir değişiklik yapılmadan alınmıştır."]'::jsonb, 1, $$Roman, toplumsal sorunları yansıtabildiği ve geniş bir okur kitlesine ulaşabildiği için Tanzimat yazarlarının tercih ettiği bir tür olmuştur.$$, 3, 3),
('aee1cf3b-d508-4155-9ab7-062eb78d7db7','vocabulary',$$Metinde "Batılılaşma" kavramı nasıl ele alınmaktadır?$$,'["Türk kimliğinden tamamen vazgeçme","Batı sanat, bilim ve kurumlarını Türk bağlamına uyarlarken özgün kültürel kimliği koruma süreci","Yalnızca dil değişikliği","Osmanlı kurumlarının Avrupalılarca yönetilmesi"]'::jsonb, 1, $$Batılılaşma; Türk kültürel kimliğini yitirmeksizin Batı düşüncesi ve pratiklerinden seçici biçimde yararlanmayı ifade etmektedir.$$, 3, 4),
('aee1cf3b-d508-4155-9ab7-062eb78d7db7','detail',$$Tanzimat dönemi edebiyatının Divan edebiyatından ayrılan en belirgin özelliği nedir?$$,'["Dini konuları tamamen reddetmiştir.","Bireysel ve toplumsal sorunları ele alarak halk diline yaklaşmıştır; Divan edebiyatı ise saray çevresiyle sınırlı, seçkin bir zevke hitap ediyordu.","Yalnızca lirik şiire odaklanmıştır.","Batı dillerinde eser üretilmiştir."]'::jsonb, 1, $$Tanzimat; toplumsal ve bireysel temaları benimseyerek daha geniş kitlelere ulaşmayı heeflerken Divan edebiyatı seçkinci bir saray geleneğini temsil ediyordu.$$, 3, 5);
INSERT INTO text_questions (text_id, question_type, question_text, options, correct_index, explanation, difficulty, order_index) VALUES
('5341d3ca-0a36-44df-b2c7-515597141587','main_idea',$$Bu metnin ana fikri nedir?$$,'["Türk modernizmi yalnızca romancıları kapsamaktadır.","Türk edebiyatında modernizm; psikolojik derinlik, bilinç akışı ve bireysel iç dünyaya odaklanarak anlatının geleneksel kalıplarını kırmıştır.","Modernist yazarlar toplumsal sorunları görmezden gelmiştir.","Modernizm Türk edebiyatına hiçbir özgün katkı sağlamamıştır."]'::jsonb, 1, $$Metin, Türk modernizmini psikolojik ve biçimsel yenilik süreciyle ele almaktadır.$$, 3, 1),
('5341d3ca-0a36-44df-b2c7-515597141587','detail',$$Oğuz Atay''ın Türklüğün Göçerleri eseri modernist açıdan nasıl öne çıkmaktadır?$$,'["Geleneksel anlatı yapısını korumaktadır.","Bölünmüş kimlik, yabancılaşma ve özgüven bunalımını derinlemesine inceleyerek Türk romanına modernist bir soluk getirmiştir.","Yalnızca tarihsel anlatı özelliği taşımaktadır.","Doğrusal bir olay örgüsüne sahiptir."]'::jsonb, 1, $$Atay''ın yapıtı; bilinç akışı, postmodern teknikler ve psikolojik derinlikle Türk modernizminin temel eserleri arasına girmiştir.$$, 3, 2),
('5341d3ca-0a36-44df-b2c7-515597141587','inference',$$Bilinç akışı tekniğinin kullanılması yazarlar hakkında ne düşündürür?$$,'["Yazarlar karakterleri sığ ve yüzeysel biçimde anlatmak istemiştir.","Yazarlar; karmaşık, çokkatmanlı bilinç ve duygusal deneyimleri geleneksel anlatıdan daha sahici biçimde yansıtmayı amaçlamıştır.","Bilinç akışı yalnızca şiirde uygulanmaktadır.","Teknik okuyucuyu kasıtlı olarak kafa karıştırmak için kullanılmaktadır."]'::jsonb, 1, $$Bilinç akışı tekniği, insan zihninin kesintisiz ve dağınık düşünce örüntüsünü kurgusal alanda en sahici biçimde aktarma çabasını yansıtmaktadır.$$, 3, 3),
('5341d3ca-0a36-44df-b2c7-515597141587','vocabulary',$$Metinde geçen "yabancılaşma" kavramı ne anlama gelir?$$,'["Yabancı ülkelere göç etme","Toplumdan, kimlikten ya da varoluşun kendisinden kopukluk ve anlamsızlık duygusu","Farklı bir kültürü benimseme","Psikolojik bozukluk"]'::jsonb, 1, $$Yabancılaşma; bireyin kendi toplumuna, kimliğine ve varoluşuna karşı hissettiği derin kopukluk duygusudur.$$, 3, 4),
('5341d3ca-0a36-44df-b2c7-515597141587','detail',$$Türk edebiyatında modernizmin öne çıkan özellikleri nelerdir?$$,'["Doğrusal olay örgüsü ve güvenilir anlatıcı kullanımı","Psikolojik derinlik, bilinç akışı, çoklu bakış açısı ve kimlik sorunlarını konu alan tematik içerik","Yalnızca epik destanlar ve tarihsel romanlara odaklanma","Dini değerlerin açıkça savunulması"]'::jsonb, 1, $$Türk modernist yazını; iç çatışma, bilinç akışı ve kimlik temalarıyla geleneksel anlatı anlayışından belirgin biçimde ayrılmaktadır.$$, 3, 5);
INSERT INTO text_questions (text_id, question_type, question_text, options, correct_index, explanation, difficulty, order_index) VALUES
('fd33923b-45db-4509-bdc3-d2d1d6ecf29f','main_idea',$$Bu metnin ana fikri nedir?$$,'["Ses dalgaları yalnızca havada iletilir.","Dalga hareketi; enerjiyi aktaran temel bir fizik olgusudur ve ses dalgaları bu ilkelerin en somut günlük hayat örneklerini oluşturur.","Dalgalar yalnızca denizlerde gözlemlenir.","Ses frekansı değişmez bir sabittir."]'::jsonb, 1, $$Metin, dalga hareketini temel fizik ilkeleriyle ele almakta ve ses dalgalarını bu ilkelerin somut bir uygulaması olarak sunmaktadır.$$, 3, 1),
('fd33923b-45db-4509-bdc3-d2d1d6ecf29f','detail',$$Sesin havadaki hızı yaklaşık kaç m/s''dir?$$,'["300 m/s","343 m/s","1500 m/s","3000 m/s"]'::jsonb, 1, $$Ses, oda sıcaklığında havada yaklaşık 343 m/s hızla yayılır; suda ve katılarda daha hızlıdır.$$, 3, 2),
('fd33923b-45db-4509-bdc3-d2d1d6ecf29f','inference',$$Doppler etkisi hakkında ne söylenebilir?$$,'["Doppler etkisi yalnızca ışık dalgaları için geçerlidir.","Bir ses kaynağı gözlemciye yaklaştıkça frekans yükselir, uzaklaştıkça alçalır; bu durum günlük hayatta ambulans sireni örneğiyle gözlemlenir.","Doppler etkisi sabit bir kaynakta da gerçekleşir.","Ses kaynağının hızı Doppler etkisini etkilemez."]'::jsonb, 1, $$Doppler etkisi; kaynak ve gözlemci arasındaki göreli hareket nedeniyle algılanan frekansın değişmesini açıklar.$$, 3, 3),
('fd33923b-45db-4509-bdc3-d2d1d6ecf29f','vocabulary',$$Metinde geçen "frekans" kavramı ne anlama gelir?$$,'["Dalganın birim uzunluktaki enerji miktarı","Saniyede gerçekleşen tam titreşim sayısı; Hz birimiyle ölçülür","Dalganın boydan boya uzunluğu","Dalganın ortamda yayılma hızı"]'::jsonb, 1, $$Frekans; kaynağın saniyede tamamladığı titreşim sayısıdır ve Hertz (Hz) birimiyle ifade edilir.$$, 3, 4),
('fd33923b-45db-4509-bdc3-d2d1d6ecf29f','detail',$$Boyuna ve enine dalgalar arasındaki temel fark nedir?$$,'["İkisi de aynı biçimde hareket eder.","Boyuna dalgalarda tanecik titreşimi dalga yayılış yönündeyken, enine dalgalarda dik yönde gerçekleşir.","Enine dalgalar seste, boyuna dalgalar ışıkta gözlemlenir.","Boyuna dalgalar boşlukta yayılabilir."]'::jsonb, 1, $$Boyuna dalgalarda (ses) titreşim yayılış yönündeyken, enine dalgalarda (ışık) titreşim yayılış yönüne diktir.$$, 3, 5);
INSERT INTO text_questions (text_id, question_type, question_text, options, correct_index, explanation, difficulty, order_index) VALUES
('06e38d93-c8df-4992-b3ab-13736858b130','main_idea',$$Bu metnin ana fikri nedir?$$,'["Evren sadece Güneş sisteminden oluşmaktadır.","Kozmoloji; Büyük Patlama''dan bu yana süregelen evrenin yapısını, genişlemesini ve evrimini inceleyen bilim dalıdır.","Evren sabittir ve genişlememektedir.","Karanlık madde ve enerji henüz teorik birer kavramdır."]'::jsonb, 1, $$Metin, evrenin kökenini, yapısını ve evrimini ele alan kozmolojinin temel kavramlarını açıklamaktadır.$$, 3, 1),
('06e38d93-c8df-4992-b3ab-13736858b130','detail',$$Büyük Patlama teorisine göre evrenin yaşı yaklaşık kaçtır?$$,'["4,5 milyar yıl","13,8 milyar yıl","100 milyar yıl","1 trilyon yıl"]'::jsonb, 1, $$Büyük Patlama teorisi, evrenin yaklaşık 13,8 milyar yıl önce son derece yoğun ve sıcak bir noktadan başladığını öngörmektedir.$$, 3, 2),
('06e38d93-c8df-4992-b3ab-13736858b130','inference',$$Evrenin hâlâ genişliyor olması hakkında ne çıkarılabilir?$$,'["Evren gelecekte büyümekte olan büyük bir patlamaya hazırlanmaktadır.","Galaksiler birbirinden uzaklaşmakta; bu durum, evrenin ortak bir başlangıç noktasından kaynaklandığına işaret etmektedir.","Evren yalnızca Dünya''dan bakıldığında genişliyor görünmektedir.","Evrenin genişlemesi hız kaybetmekte ve durma sürecine girmiştir."]'::jsonb, 1, $$Galaksilerin giderek hızlanan uzaklaşması, Büyük Patlama kökenine ilişkin en güçlü kanıtlardan birini oluşturmaktadır.$$, 3, 3),
('06e38d93-c8df-4992-b3ab-13736858b130','vocabulary',$$Metinde geçen "karanlık madde" kavramı nasıl açıklanmaktadır?$$,'["Işık geçirmeyen siyah delikler","Işık yaymayan, absorplamayan ya da yansıtmayan ancak çekimsel etkisiyle varlığı anlaşılan gizemli madde","Atom altı parçacıklardan oluşan sıradan madde","Yıldız patlamalarından kalan madde bulutları"]'::jsonb, 1, $$Karanlık madde; ışıkla etkileşime girmeyen, ancak etrafındaki madde üzerindeki çekimsel etkisiyle varlığı dolaylı yoldan tespit edilen maddedir.$$, 3, 4),
('06e38d93-c8df-4992-b3ab-13736858b130','detail',$$Galaksiler nasıl sınıflandırılmaktadır?$$,'["Yalnızca boyutlarına göre","Spiral, eliptik ve düzensiz şeklinde başlıca üç kategoride sınıflandırılmaktadır.","Yalnızca içerdikleri yıldız sayısına göre","Güneş''e olan uzaklıklarına göre"]'::jsonb, 1, $$Galaksiler; spiral (sarmal), eliptik ve düzensiz olmak üzere üç temel morfolojik türde sınıflandırılmaktadır.$$, 3, 5);
INSERT INTO text_questions (text_id, question_type, question_text, options, correct_index, explanation, difficulty, order_index) VALUES
('ac7670cd-ca10-454c-ba69-9f184450e7bf','main_idea',$$Bu metnin ana fikri nedir?$$,'["Termodinamik yalnızca mühendisleri ilgilendiren bir alan","Termodinamiğin yasaları; enerji dönüşümlerini, termal davranışları ve evrensel süreçlerin yönünü yöneten temel fizik ilkelerini oluşturur.","Isı enerjisi hiçbir koşulda işe dönüştürülemez.","Mutlak sıfır sıcaklığa herhangi bir süreçte ulaşılabilir."]'::jsonb, 1, $$Metin, termodinamiğin yasalarını evrensel enerji süreçlerini açıklayan temel fizik ilkeleri olarak sunmaktadır.$$, 4, 1),
('ac7670cd-ca10-454c-ba69-9f184450e7bf','detail',$$Termodinamiğin birinci yasası ne ifade etmektedir?$$,'["Entropi her süreçte artmaktadır.","Enerji yaratılamaz ya da yok edilemez; yalnızca bir formdan diğerine dönüşür.","Mutlak sıfırda tüm moleküler hareket durur.","Isı alışverişi olmaksızın gerçekleşen süreçler çevrimseldir."]'::jsonb, 1, $$Birinci yasa (Enerjinin Korunumu): enerji sürekli korunur; farklı biçimler arasında dönüşüm mümkündür ancak toplam miktar sabit kalır.$$, 4, 2),
('ac7670cd-ca10-454c-ba69-9f184450e7bf','inference',$$İkinci yasanın "entropi artışı" ilkesi makine tasarımı açısından ne ifade eder?$$,'["Makineler zamanla daha verimli hale gelir.","Hiçbir gerçek makine %100 verimlilikle çalışamaz; bir kısım enerji her zaman kullanılamaz ısıya dönüşür.","Entropi yalnızca kapalı sistemlerde artar.","Mükemmel bir ısıl makine yapılması teorik olarak mümkündür."]'::jsonb, 1, $$Entropi artışı, bir süreçte kullanılabilir enerjinin her zaman bir miktarının dağıldığına işaret eder ve bu durum %100 verimi imkânsız kılar.$$, 4, 3),
('ac7670cd-ca10-454c-ba69-9f184450e7bf','vocabulary',$$Metinde geçen "entropi" kavramı ne anlama gelir?$$,'["Bir sistemin toplam enerji miktarı","Bir sistemdeki düzensizlik ya da dağınıklık ölçüsü; yüksek entropi düşük kullanılabilir enerjiyi ifade eder","Sıcaklık değişimi","İş çevrimi başına kullanılan ısı miktarı"]'::jsonb, 1, $$Entropi; bir sistemdeki termal düzensizlik ya da rastgeleliği ölçen bir büyüklüktür; zaman ilerledikçe izole sistemlerde entropi artma eğilimindedir.$$, 4, 4),
('ac7670cd-ca10-454c-ba69-9f184450e7bf','detail',$$Üçüncü termodinamik yasa ne ifade etmektedir?$$,'["Enerji korunumlu bir büyüklüktür.","Mutlak sıfıra (0 Kelvin) yaklaşıldıkça mükemmel kristal bir sistemin entropisi sıfıra yaklaşır.","Isı yüksek sıcaklıktan düşük sıcaklığa kendiliğinden akar.","Sistem entropisi her değişimde artmak zorundadır."]'::jsonb, 1, $$Üçüncü yasa; mutlak sıfıra (0 K) erişildiğinde termodinamik olarak ideal bir sistemin entropisi sıfır olacağını öngörmekte ve mutlak sıfıra ulaşmanın pratikte imkânsızlığını ortaya koymaktadır.$$, 4, 5);
INSERT INTO text_questions (text_id, question_type, question_text, options, correct_index, explanation, difficulty, order_index) VALUES
('ff09b133-760b-45c0-a821-1c468811baec','main_idea',$$Bu metnin ana fikri nedir?$$,'["Dalton''un atom modeli günümüzde de geçerliliğini korumaktadır.","Atom modellerinin tarihsel evrimi, kuantum teorisinin klasik fizik anlayışını köklü biçimde dönüştürdüğünü ortaya koymaktadır.","Kuantum teorisi yalnızca çok büyük ölçekler için geçerlidir.","Elektronlar belirli yörüngeler üzerinde kesin konumlarda bulunmaktadır."]'::jsonb, 1, $$Metin, atom modellerinin gelişimini ve kuantum teorisinin bu anlayışı nasıl altüst ettiğini ele almaktadır.$$, 4, 1),
('ff09b133-760b-45c0-a821-1c468811baec','detail',$$Bohr atom modeli Rutherford modelinden nasıl ayrılmaktadır?$$,'["Bohr modeli elektronların bulut içinde dağıldığını öngörür.","Bohr, elektronların ayrık enerji düzeylerinde hareket ettiğini ve yalnızca enerji seviyeleri arasında geçiş yaparken ışıma yaptığını ileri sürmüştür.","Bohr modeli atom çekirdeğini görmezden gelmiştir.","Her iki model de elektronların konumunu kesinlikle belirlemiştir."]'::jsonb, 1, $$Bohr modeli; elektronların kuantumlanmış yörüngeler üzerinde yer aldığını öne sürmüş ve hidrojen spektrumunu başarıyla açıklamıştır.$$, 4, 2),
('ff09b133-760b-45c0-a821-1c468811baec','inference',$$Heisenberg Belirsizlik İlkesi atom fiziği açısından ne ifade etmektedir?$$,'["Atomik ölçekte kesin ölçümler mümkündür.","Bir elektronun konumu ve momentumu aynı anda tam olarak bilinemez; bu durum deterministik atom fiziğini temel düzeyde sorgulatmaktadır.","Belirsizlik yalnızca ölçüm hatalarından kaynaklanmaktadır.","Elektronlar sabit ve tahmin edilebilir yörüngeler izler."]'::jsonb, 1, $$Heisenberg İlkesi; kuantum belirsizliğinin ölçüm hatası değil, gerçekliğin doğasından kaynaklanan temel bir özellik olduğunu ortaya koyar.$$, 4, 3),
('ff09b133-760b-45c0-a821-1c468811baec','vocabulary',$$Metinde geçen "orbital" kavramı ne anlama gelir?$$,'["Yörünge gezegenlerinin izlediği kesin çizgisel yol","Bir elektronu belirli bir enerji seviyesinde bulma olasılığını temsil eden uzaysal bölge","Atom çekirdeğinin dış zarı","Proton ve nötronların oluşturduğu yapı"]'::jsonb, 1, $$Orbital; bir elektronu bulmak için belirli bir olasılığın geçerli olduğu üç boyutlu uzay bölgesini ifade eder.$$, 4, 4),
('ff09b133-760b-45c0-a821-1c468811baec','detail',$$Atomun çekirdeğinden elektronun varlığına kadar öngörülen kuantum fenomeni hangisidir?$$,'["Klasik yörünge mekaniği","Elektron bulutları ve dalga-parçacık ikiliği","Güneş sistemi benzeri katı yörüngeler","Çekirdeğin çevresindeki eşit dağılmış yük"]'::jsonb, 1, $$Kuantum mekaniği, elektronların kesin yörüngelerde değil, olasılık dağılımlarıyla tanımlanan bulutlarda yer aldığını; aynı zamanda hem dalga hem parçacık özellikleri sergilediğini öngörür.$$, 4, 5);
INSERT INTO text_questions (text_id, question_type, question_text, options, correct_index, explanation, difficulty, order_index) VALUES
('f0c4a3ab-c057-4880-90cb-c3e6ab3c3df9','main_idea',$$Bu metnin ana fikri nedir?$$,'["Kimyasal tepkimeler geri dönüşümsüzdür.","Kimyasal denge; ileri ve geri tepkimelerin eşit hızda gerçekleştiği dinamik bir denge durumudur ve Le Chatelier ilkesi bu dengeye etki eden faktörleri açıklar.","Katalizörler kimyasal dengeyi kalıcı olarak bozar.","Tepkime hızı yalnızca sıcaklıkla belirlenir."]'::jsonb, 1, $$Metin, kimyasal dengeyi ve dengeyi etkileyen faktörleri ele almaktadır.$$, 3, 1),
('f0c4a3ab-c057-4880-90cb-c3e6ab3c3df9','detail',$$Le Chatelier İlkesi ne öngörmektedir?$$,'["Bir katalizör eklemek dengeyi bozar.","Kimyasal dengedeki bir sisteme dış etki yapıldığında sistem, bu etkiyi azaltacak yönde tepki vererek yeni bir denge konumuna ulaşır.","Sıcaklık değişimleri dengeyi hiç etkilemez.","Denge sabiti tüm koşullarda sabit kalır."]'::jsonb, 1, $$Le Chatelier İlkesi; konsantrasyon, basınç ve sıcaklık değişimlerine sistematik tepkileri öngörerek denge pozisyonundaki kaymaları açıklar.$$, 3, 2),
('f0c4a3ab-c057-4880-90cb-c3e6ab3c3df9','inference',$$Katalizör eklenmesi denge konumunu nasıl etkiler?$$,'["Denge ürünlere doğru kayar.","Katalizör her iki tepkime yönünü eşit ölçüde hızlandırır; denge konumunu değiştirmez, yalnızca dengeye ulaşma süresini kısaltır.","Katalizör denge sabitini kalıcı olarak değiştirir.","Katalizörler yalnızca ileri tepkimeyi hızlandırır."]'::jsonb, 1, $$Katalizörler; aktivasyon enerjisini düşürerek ileri ve geri tepkimeleri eşit biçimde hızlandırır; denge konumu değişmez.$$, 3, 3),
('f0c4a3ab-c057-4880-90cb-c3e6ab3c3df9','vocabulary',$$Metinde geçen "denge sabiti (Keq)" ne ifade eder?$$,'["Tepkimenin tamamlanma süresi","Denge durumunda ürün konsantrasyonlarının çarpımının reaktan konsantrasyonlarının çarpımına oranı","Tepkimenin gerçekleşebileceği maksimum sıcaklık","Tepkimede üretilen ısı miktarı"]'::jsonb, 1, $$Denge sabiti; belli bir sıcaklıkta belirli bir tepkimenin denge durumundaki ürün ve reaktan oranlarını sayısal olarak ifade eder.$$, 3, 4),
('f0c4a3ab-c057-4880-90cb-c3e6ab3c3df9','detail',$$Endotermik bir tepkimede sıcaklık artışı dengeyi nasıl etkiler?$$,'["Denge reaktanlar tarafına kayar.","Denge ürünler tarafına kayar; sistem ısıyı soğurarak ısınmaya direnç gösterir.","Sıcaklık değişimi dengeyi etkilemez.","Endotermik tepkimeler sıcaklık değişimine duyarsızdır."]'::jsonb, 1, $$Le Chatelier İlkesi''ne göre endotermik bir tepkimede sıcaklık artışı, sistemin fazla ısıyı emmesini sağlayacak biçimde dengeyi ürünler yönüne kaydırır.$$, 3, 5);
INSERT INTO text_questions (text_id, question_type, question_text, options, correct_index, explanation, difficulty, order_index) VALUES
('5146417e-6487-40b9-9d3f-7153eaa0a8b0','main_idea',$$Bu metnin ana fikri nedir?$$,'["Organik kimya yalnızca doğal ürünlerle ilgilenir.","Organik kimya; karbon bileşiklerinin yapı, özellik ve tepkimelerini inceleyen temel bir kimya dalıdır; ilaç, polimer ve yakıt endüstrilerinin temeli bu alanda yatmaktadır.","Organik bileşikler yalnızca canlı organizmalarda bulunur.","Tüm karbon bileşikleri aynı kimyasal özellikleri taşır."]'::jsonb, 1, $$Metin, organik kimyayı karbon bileşiklerine odaklanması ve geniş endüstriyel uygulamaları açısından ele almaktadır.$$, 4, 1),
('5146417e-6487-40b9-9d3f-7153eaa0a8b0','detail',$$Organik kimyanın temel elementi neden karbondur?$$,'["Karbon en hafif elementtir.","Karbonun dört değerliği bulunduğundan çeşitli atom ve moleküllerle karmaşık, kararlı yapılar oluşturabilir.","Karbon doğada en bol bulunan elementtir.","Karbon kolayca iyonlaşır."]'::jsonb, 1, $$Karbonun dört değerliği, zincir, halka ve dallı yapılar kurmasına olanak tanıyarak milyonlarca farklı organik bileşiğin oluşmasını sağlar.$$, 4, 2),
('5146417e-6487-40b9-9d3f-7153eaa0a8b0','inference',$$Organik bileşiklerin çeşitliliği hakkında ne çıkarılabilir?$$,'["Organik kimya yalnızca birkaç temel bileşikle sınırlıdır.","Karbonun olağanüstü bağ kurma kapasitesi, biyolojik işlevlerden endüstriyel uygulamalara uzanan geniş bir çeşitliliğe yol açmaktadır.","Tüm organik bileşikler birbirine benzer özellikler gösterir.","Organik bileşikler yalnızca yakıt olarak kullanılmaktadır."]'::jsonb, 1, $$Karbonun çeşitli bağlanma özellikleri; yaşamın temel bileşenlerinden ilaçlara, boyalardan polimerlere uzanan sonsuz çeşitlilikte organik bileşik üretmesine olanak tanır.$$, 4, 3),
('5146417e-6487-40b9-9d3f-7153eaa0a8b0','vocabulary',$$Metinde geçen "fonksiyonel grup" kavramı ne anlama gelir?$$,'["Bir bileşiğin tamamını oluşturan karbon zinciri","Organik bir moleküle karakteristik kimyasal özellikler kazandıran belirli atom ya da atom grupları (–OH, –COOH vb.)","İki karbon atomu arasındaki çift bağ","Tüm organik bileşiklerde ortak olan yapısal özellik"]'::jsonb, 1, $$Fonksiyonel grup; bir organik moleküldeki kimyasal reaktiviteyi ve özellikleri belirleyen spesifik atom kümeleridir.$$, 4, 4),
('5146417e-6487-40b9-9d3f-7153eaa0a8b0','detail',$$Alkanlar ve alkenler arasındaki temel yapısal fark nedir?$$,'["Alkanlar karbon, alkenler hidrojen içerir.","Alkanlar yalnızca tek karbon-karbon bağları içerirken alkenler en az bir çift bağ (C=C) barındırır.","Alkenler daha yüksek kaynama noktasına sahiptir.","Alkanlar halkalar oluştururken alkenler düz zincir yapısındadır."]'::jsonb, 1, $$Alkanlar doymuş hidrokarbonlardır (yalnızca C–C bağları); alkenler ise C=C çift bağı içeren doymamış bileşiklerdir.$$, 4, 5);
INSERT INTO text_questions (text_id, question_type, question_text, options, correct_index, explanation, difficulty, order_index) VALUES
('bdbb7887-34be-4cd3-9d31-efb7b9323423','main_idea',$$Paragrafın yazarının temel savı aşağıdakilerden hangisidir?$$,'["Bilimsel yöntem yalnızca doğa bilimlerine özgüdür.","Sağlam araştırma metodolojisi; hipotez kurma, sistematik gözlem ve bağımsız doğrulama ilkelerine dayanan bilimsel bilginin bütünlüğünü güvence altına alır.","Nicel araştırma nitel araştırmadan üstündür.","Metodoloji yalnızca verilerin nasıl toplandığıyla ilgilidir."]'::jsonb, 1, $$Metin, araştırma metodolojisinin bilimsel geçerlilik ve güvenilirlik açısından merkezî önemini vurgulamaktadır.$$, 4, 1),
('bdbb7887-34be-4cd3-9d31-efb7b9323423','detail',$$Metne göre hipotezi yanlışlanabilir olmayan bir araştırmanın metodolojik durumu nedir?$$,'["Yalnızca kabul gördüğü takdirde geçerli sayılır.","Yanlışlanabilir olmayan hipotezler bilimsel test edilebilirlik kriterini karşılamaz; dolayısıyla ampirik araştırma konusu yapılamaz.","Veriler tutarlılık gösterdiği sürece araştırma bilimsel kabul edilir.","Ampirik desteğe gerek kalmaksızın geçerli sayılır."]'::jsonb, 1, $$Yanlışlanabilirlik; Karl Popper''ın ortaya koyduğu bilimselliğin temel ölçütlerinden biridir: yanlışlanamaz önerme, ampirik araştırmanın kapsamı dışında kalır.$$, 4, 2),
('bdbb7887-34be-4cd3-9d31-efb7b9323423','inference',$$Akran değerlendirmesinin metodolojik süreçlere dâhil edilmesi hakkında ne çıkarılabilir?$$,'["Akran değerlendirmesi araştırmacının özerkliğini kısıtlar.","Bağımsız inceleme; önyargıları azaltır, standartların korunmasını sağlar ve bilimsel topluluğun güvenini pekiştirir.","Akran değerlendirmesi yalnızca çok büyük bütçeli araştırmalarda zorunludur.","Araştırmacılar çalışmalarını bağımsız biçimde doğrulayabildiğinden akran değerlendirmesi gereksizdir."]'::jsonb, 1, $$Akran değerlendirmesi; metodolojik açıdan zayıf çalışmaların yayımlanmasını engelleyen toplu bir kalite güvencesi mekanizmasıdır.$$, 4, 3),
('bdbb7887-34be-4cd3-9d31-efb7b9323423','vocabulary',$$Metinde geçen "operasyonelleştirme" kavramı ne anlama gelir?$$,'["Araştırma bulgularını kamuoyuyla paylaşma","Soyut kavramları ölçülebilir, gözlemlenebilir göstergelere ya da değişkenlere dönüştürme","Araştırmanın pratik uygulamalarını belirleme","Laboratuvar ekipmanlarının işletilmesi"]'::jsonb, 1, $$Operasyonelleştirme; soyut teorik kavramların (örneğin zekâ, refah) nesnel ve tutarlı biçimde ölçülebilmesi için gözlemlenebilir değişkenlere dönüştürülme sürecidir.$$, 4, 4),
('bdbb7887-34be-4cd3-9d31-efb7b9323423','tone',$$Metindeki yazarın söylemi nasıl nitelendirilebilir?$$,'["Öznel ve savunmacı","Nesnel, analitik ve ölçülü kural koyucu","Anekdotlara dayanan ve gayri resmî","Polemik ve kuşku uyandırıcı"]'::jsonb, 1, $$Metin; metodolojik ilkeleri açık bir çerçevede ortaya koyarken nesnel, çözümsel ve normatif bir üslup benimsemektedir.$$, 4, 5);
INSERT INTO text_questions (text_id, question_type, question_text, options, correct_index, explanation, difficulty, order_index) VALUES
('4f4cd5d8-2e35-495a-bf98-20b3f452c2d0','main_idea',$$Bu pasajın merkezi argümanı nedir?$$,'["İklim değişikliği doğal bir döngüdür ve müdahale gerektirmez.","Beşerî kaynaklı iklim değişikliği; ekosistemleri, insan topluluklarını ve küresel iklim örüntülerini tehdit eden acil bir sorun niteliği taşımakta ve koordineli politika yanıtlarını zorunlu kılmaktadır.","Teknoloji iklim sorununu hükümet müdahalesi gerekmeksizin çözecektir.","Gelişmekte olan ülkeler tek taraflı olarak sera gazı emisyonlarını azaltmalıdır."]'::jsonb, 1, $$Metin; iklim değişikliğini beşerî kaynaklı, kapsamlı bir sorun olarak tanımlamakta ve bütüncül politika yanıtlarını gündeme taşımaktadır.$$, 3, 1),
('4f4cd5d8-2e35-495a-bf98-20b3f452c2d0','detail',$$Sera etkisi nasıl açıklanmaktadır?$$,'["Güneş enerjisini emen okyanuslar tarafından oluşturulur.","Atmosferdeki sera gazları giden kızılötesi ışımayı geri yansıtarak Dünya''nın yüzeyini ısıtır.","Sera etkisi yalnızca insan faaliyetlerinin doğrudan ürünüdür.","Atmosferdeki azalma doğrudan yüzey ısınmasına neden olur."]'::jsonb, 1, $$Sera etkisi; CO₂, metan ve su buharı gibi gazların giden ısı enerjisini atmosferde tutarak yüzey sıcaklıklarını yükselten doğal ve beşerî kaynaklı bir süreçtir.$$, 3, 2),
('4f4cd5d8-2e35-495a-bf98-20b3f452c2d0','inference',$$İklim değişikliğinin adaletsiz dağılımı hakkında ne çıkarılabilir?$$,'["Iklim değişikliği tüm ülkeleri eşit ölçüde etkiler.","En az karbondioksit salan, yoksul ve kırılgan topluluklar iklim değişikliğinden orantısız biçimde zarar görmektedir; bu durum önemli bir küresel adalet sorununa yol açmaktadır.","Zengin ülkeler iklim değişikliğinden daha fazla etkilenmektedir.","Iklim adaleti iklim değişikliği müzakerelerinden bağımsız bir konudur."]'::jsonb, 1, $$İklim kırılganlığı ile ekonomik kalkınma arasındaki uçurum, politika yapıcıların öncelikli olarak ele alması gereken ciddi bir eşitsizlik meselesi doğurmaktadır.$$, 3, 3),
('4f4cd5d8-2e35-495a-bf98-20b3f452c2d0','vocabulary',$$Metinde geçen "azaltma" (mitigation) ve "uyum" (adaptation) terimleri nasıl kullanılmaktadır?$$,'["Her iki terim de aynı anlama gelmektedir.","Azaltma; emisyonları azaltarak iklim değişikliğinin boyutunu sınırlamayı hedeflerken uyum, kaçınılmaz etkilerin üstesinden gelmeyi amaçlar.","Uyum; yeni teknolojilerin geliştirilmesini kapsarken azaltma hükümet politikasını ifade eder.","Azaltma; gelişmiş ülkelerin sorumluluğundayken uyum gelişmekte olan ülkelere düşen bir görevdir."]'::jsonb, 1, $$İklim politikasında bu iki kavram birbirini tamamlar: azaltma kaynakta önlem alırken uyum sonuçlarla baş etme kapasitesini artırır.$$, 3, 4),
('4f4cd5d8-2e35-495a-bf98-20b3f452c2d0','tone',$$Metindeki yazarın iklim değişikliğine ilişkin tutumu nasıl nitelendirilebilir?$$,'["Tarafsız ve bilimsel açıdan belirsiz","Aciliyet vurgulayan, kanıta dayalı ve politika odaklı","Umursamaz ve kaderci","Yalnızca ekonomik maliyetleri öne çıkaran"]'::jsonb, 1, $$Metin; bilimsel kanıtları, potansiyel sonuçları ve politika gerekliliklerini öncelikle vurgulayarak güçlü bir aciliyet duygusu aktarmaktadır.$$, 3, 5);
INSERT INTO text_questions (text_id, question_type, question_text, options, correct_index, explanation, difficulty, order_index) VALUES
('bf269d62-f5cf-4227-b5bb-96105cf8f0de','main_idea',$$Bu metnin merkezi tezi nedir?$$,'["Tüm diller ortak bir ata dilden evrilmiştir.","Dil edinimi; doğuştan gelen biyolojik eğilimler ile çevresel dilsel girdilerin karşılıklı etkileşimiyle şekillenen nörobilişsel bir süreçtir.","Çocuklar dili yalnızca taklit yoluyla öğrenir.","Dil, bireysel zekanın doğrudan bir yansımasıdır."]'::jsonb, 1, $$Metin; dil edinimini biyolojik hazırbulunuşluk ile çevresel girdinin iç içe geçtiği nörobilişsel bir süreç olarak tanımlamaktadır.$$, 4, 1),
('bf269d62-f5cf-4227-b5bb-96105cf8f0de','detail',$$Chomsky''nin Evrensel Dilbilgisi teorisi ne öngörmektedir?$$,'["Her dilin kendine özgü gramer kuralları vardır.","İnsan beyni, sözdizimsel yapıları edinmeyi sağlayan doğuştan gelmiş biyolojik mekanizmalarla donatılmıştır.","Dil, kültürel aktarım yoluyla nesilden nesile geçer.","Dilbilgisi tamamen sosyal öğrenme aracılığıyla kazanılır."]'::jsonb, 1, $$Chomsky; dilin öğrenilme hızını ve evrensel yapısal özelliklerini açıklayabilmek için doğuştan gelen dilbilgisel sezgiler varsaymaktadır.$$, 4, 2),
('bf269d62-f5cf-4227-b5bb-96105cf8f0de','inference',$$Kritik dönem hipotezi, dil öğreniminde neden kritik bir öneme sahiptir?$$,'["Dil, her yaşta eşit etkinlikle edinilebilir.","Biyolojik açıdan optimal bir dönem var gibi görünmekte; bu dönem geçtikten sonra dil edinimi kayda değer güçleşmektedir.","Kritik dönem yalnızca yazılı dil edinimini etkiler.","İkinci bir dil, birinci dilden daha kolay öğrenilir."]'::jsonb, 1, $$Kritik dönem araştırmaları; sinaptik budama ve nöroplastisite dönemleriyle örtüşen hassas bir pencereye işaret etmektedir.$$, 4, 3),
('bf269d62-f5cf-4227-b5bb-96105cf8f0de','vocabulary',$$Metinde geçen "nöroplastisite" kavramı ne anlama gelir?$$,'["Beyin yaralanmalarından kaynaklanan bir bozukluk","Beynin yeni deneyimler ve öğrenme süreçleri karşısında yapısal ve işlevsel düzeyde yeniden düzenlenme kapasitesi","Beynin doğumdan ölüme kadar sabit kalma özelliği","Bilişsel sertlik ve alışkanlık oluşumu"]'::jsonb, 1, $$Nöroplastisite; dil edinimi de dahil olmak üzere öğrenmeye bağlı sinaptik ve nöronal değişimlerin gerçekleşmesine olanak tanıyan beynin uyum yeteneğidir.$$, 4, 4),
('bf269d62-f5cf-4227-b5bb-96105cf8f0de','tone',$$Yazarın dil kökenleri tartışmasındaki tutumu nasıl nitelendirilebilir?$$,'["Dogmatik ve kesin çizgilerle ayrılmış","Araştırmacı, mevcut teorilere eleştirel yaklaşan ve kanıta dayalı","Yalnızca evrimsel açıklamalar üzerine odaklanan","Biyolojik kısıtları önemsizleştiren"]'::jsonb, 1, $$Metin; farklı teorik yaklaşımları dengeli biçimde ele almakta, güçlü ve zayıf yönlerini irdelemekte ve kanıtları akademik bir açıklıkla tartışmaktadır.$$, 4, 5);
INSERT INTO text_questions (text_id, question_type, question_text, options, correct_index, explanation, difficulty, order_index) VALUES
('80f0e6ee-c179-4b20-908c-d38119ba80e4','main_idea',$$Bu pasajın merkezi argümanı nedir?$$,'["Tüm ekonomiler aynı büyüme örüntüsünü izlemektedir.","Ekonomik büyüme teorileri; sermaye birikimi, teknolojik ilerleme ve beşerî sermayenin uzun dönem kalkınmadaki göreli ağırlığı konusunda farklılaşmaktadır.","Büyüme yalnızca doğal kaynak varlığıyla açıklanabilir.","Keynesyen ekonomi büyüme açıklamalarının temel çerçevesini oluşturmaktadır."]'::jsonb, 1, $$Metin; farklı büyüme teorilerini katkı ve sınırlılıkları açısından karşılaştırmalı biçimde ele almaktadır.$$, 4, 1),
('80f0e6ee-c179-4b20-908c-d38119ba80e4','detail',$$Solow-Swan büyüme modeli fiziksel sermayenin sınırlarını nasıl açıklamaktadır?$$,'["Sermaye birikimi büyümeyi sonsuza dek sürdürür.","Azalan verimler yasası nedeniyle fiziksel sermaye birikimi tek başına uzun dönemli büyümeyi sağlayamaz; kalıcı büyüme için teknolojik ilerleme zorunludur.","Sermaye birikimi büyüme üzerinde hiçbir etkiye sahip değildir.","Dışsal şoklar büyümeyi açıklamada tek belirleyici etkendir."]'::jsonb, 1, $$Solow modeli; azalan sermaye getirileri nedeniyle büyümenin zamanla yavaşlayacağını, uzun dönemde ise yalnızca teknolojik ilerlemenin sürdürülebilir büyüme sağlayabileceğini göstermektedir.$$, 4, 2),
('80f0e6ee-c179-4b20-908c-d38119ba80e4','inference',$$İçsel büyüme teorilerinin politika önerileri hakkında ne çıkarılabilir?$$,'["Politika müdahalesi ekonomik büyümeyi olumsuz etkiler.","Araştırma-geliştirme, eğitim ve kurumsal kaliteye yapılan kamu yatırımları büyümeyi kalıcı olarak artırabilir.","Büyüme yalnızca özel sektör dinamiklerine bırakılmalıdır.","İçsel büyüme teorileri politika müdahalesini anlamsız kılmaktadır."]'::jsonb, 1, $$Beşerî sermaye ve bilgiyi büyümenin içsel belirleyicileri olarak ele alan içsel büyüme teorisi, eğitim ve Ar-Ge''ye kamu yatırımını meşrulaştırmaktadır.$$, 4, 3),
('80f0e6ee-c179-4b20-908c-d38119ba80e4','vocabulary',$$Metinde geçen "beşerî sermaye" kavramı ne anlama gelir?$$,'["Çalışanların fiziksel sağlık durumu","Bireylerdeki eğitim, beceri, deneyim ve bilgi birikimi; ekonomik üretkenliği doğrudan artıran gayri maddi varlık","İşgücünün sayısal büyüklüğü","Bireyler arasındaki sosyal bağlar ve güven ilişkileri"]'::jsonb, 1, $$Beşerî sermaye; bireyin birikimli eğitim, beceri ve deneyimleri aracılığıyla yarattığı ekonomik değeri ifade etmektedir.$$, 4, 4),
('80f0e6ee-c179-4b20-908c-d38119ba80e4','tone',$$Yazarın ekonomik büyüme teorilerine yaklaşımı nasıl nitelendirilebilir?$$,'["Savunmacı ve tek bir paradigmayı öne çıkaran","Karşılaştırmalı, analitik ve teorik çoğulculuğa açık","Ampirik kanıtlardan kopuk saf teorik","Keynesyen büyüme modeline açıkça taraflı"]'::jsonb, 1, $$Metin; klasik, neo-klasik ve içsel büyüme teorilerini güçlü ve zayıf yönleriyle dengeli biçimde ele almaktadır.$$, 4, 5);
INSERT INTO text_questions (text_id, question_type, question_text, options, correct_index, explanation, difficulty, order_index) VALUES
('c0cf6035-8bc5-4daf-bc0b-9fa82a306c17','main_idea',$$Bu metnin merkezi epistemolojik savı nedir?$$,'["Bilgi yalnızca duyusal deneyimden elde edilir.","Bilginin kaynağı, yapısı ve sınırları felsefenin temel sorunlarından birini oluşturmakta; ampirizm, rasyonalizm ve eleştirel felsefe bu sorulara birbirinden farklı yanıtlar sunmaktadır.","Gerçek bilgiye ulaşmak felsefî açıdan imkânsızdır.","Bilginin doğrulanabilmesi için bilimsel kanıt zorunludur."]'::jsonb, 1, $$Metin; epistemolojik pozisyonları karşılaştırmalı biçimde ele alarak bilginin kaynağı ve sınırları sorununu çok boyutlu açıdan tartışmaktadır.$$, 5, 1),
('c0cf6035-8bc5-4daf-bc0b-9fa82a306c17','detail',$$Locke ve Hume''un ampirizmi Descartes''ın rasyonalizminden nasıl ayrılmaktadır?$$,'["Ampirizm doğuştan gelen fikirleri kabul eder.","Ampirizm, güvenilir bilginin yalnızca duyusal deneyimden elde edildiğini savunurken rasyonalizm aklı ve doğuştan gelen fikirleri birincil bilgi kaynağı olarak benimser.","Rasyonalizm sadece pratik bilgiyle ilgilenir.","Her iki gelenek de sezgiyi ana bilgi kaynağı kabul eder."]'::jsonb, 1, $$Temel gerilim: ampiristler bilgiyi deneyim ve gözlemle sınırlarken rasyonalistler salt akıl yürütme yoluyla elde edilen apriorik bilgiyi ön plana taşır.$$, 5, 2),
('c0cf6035-8bc5-4daf-bc0b-9fa82a306c17','inference',$$Kant''ın eleştirel felsefesinin ampirizm-rasyonalizm tartışmasını uzlaştırma çabası hakkında ne çıkarılabilir?$$,'["Kant bu iki geleneği birbirinden tamamen bağımsız konumlarda değerlendirmiştir.","Kant; duyusal deneyimin ham veriyi sağladığını, zihnin ise bu veriyi kategorik yapılar ve sezgisel formlar aracılığıyla örgütlediğini ileri sürerek iki geleneği sentezlemiştir.","Kant deneyimi tamamen reddetmiştir.","Kant yalnızca deneysel bilgiye geçerlilik tanımıştır."]'::jsonb, 1, $$Kant''ın sentezi; duyusal veri ve zihinsel yapıyı bilginin zorunlu koşulları olarak bir araya getirmiştir.$$, 5, 3),
('c0cf6035-8bc5-4daf-bc0b-9fa82a306c17','vocabulary',$$Metinde geçen "epistemoloji" kavramı nasıl tanımlanmaktadır?$$,'["Toplumsal normları ve ahlakı inceleyen felsefe dalı","Bilginin doğası, kapsamı ve sınırlarını inceleyen felsefe dalı","Sanat ve estetik değerleri araştıran felsefe dalı","Fiziksel gerçekliğin temel yapısını sorgulayan felsefe dalı"]'::jsonb, 1, $$Epistemoloji; bilginin kaynağı, yöntemleri ve sınırlarını sistematik biçimde ele alan felsefe dalıdır.$$, 5, 4),
('c0cf6035-8bc5-4daf-bc0b-9fa82a306c17','tone',$$Yazarın bilgi kuramındaki epistemolojik pozisyonları sunuş biçimi nasıldır?$$,'["Taraflı; yalnızca ampirizmi desteklemektedir.","Nesnel, karşılaştırmalı ve disiplinlerarası açıdan ilişkilendirici","Teknik ve uzmanlara özgü, geniş okuyucu kitlesine kapalı","Tarihdışı ve bağlamdan bağımsız"]'::jsonb, 1, $$Metin; farklı epistemolojik pozisyonları tarihsel bağlamlarıyla akademik bir tarafsızlıkla sunmaktadır.$$, 5, 5);
INSERT INTO text_questions (text_id, question_type, question_text, options, correct_index, explanation, difficulty, order_index) VALUES
('96209f71-7313-4cbf-a499-5cad686357eb','main_idea',$$Bu metnin merkezi argümanı nedir?$$,'["İstatistiksel analiz yalnızca matematikçiler için gereklidir.","İstatistiksel anlayış, araştırma bulgularını yanlış yorumlamaktan kaçınmak ve bilinçli, kanıta dayalı kararlar alabilmek için vazgeçilmez bir düşünme becerisidir.","Istatistik yalnızca büyük veri kümeleri için kullanışlıdır.","Nicel yöntemler sosyal bilimlere uygulanamaz."]'::jsonb, 1, $$Metin; istatistiksel okuryazarlığı araştırma yorumlama ve karar alma sürecinin temel yetkinliği olarak konumlandırmaktadır.$$, 4, 1),
('96209f71-7313-4cbf-a499-5cad686357eb','detail',$$Tip I ve Tip II hatalar arasındaki fark nasıl açıklanmaktadır?$$,'["Her iki hata türü de aynı anlama gelmektedir.","Tip I hata gerçek olan H₀''ı reddetmektir (yanlış pozitif); Tip II hata ise yanlış olan H₀''ı reddetmemektir (yanlış negatif).","Tip I hata daha az ciddi bir yanlılık türüdür.","Bu hatalar yalnızca tıbbi araştırmalarda geçerlidir."]'::jsonb, 1, $$Hipotez testinde bu iki hata türü birbiriyle karşıt yönde işler; biri azaltılmaya çalışıldıkça diğeri artma eğilimi gösterir.$$, 4, 2),
('96209f71-7313-4cbf-a499-5cad686357eb','inference',$$Korelasyonun nedensellik anlamına gelmemesi hakkında ne çıkarılabilir?$$,'["Güçlü korelasyon her zaman nedensel bir ilişkiyi kanıtlar.","İki değişken arasında gözlemlenen korelasyon; gizli karıştırıcı değişkenlerden ya da rastlantısal örüntülerden kaynaklanıyor olabilir; bu nedenle nedensellik için kontrollü deneysel tasarım gereklidir.","Negatif korelasyon nedenselliğin kesin kanıtıdır.","Korelasyon analizi nedenselliğin araştırılmasını gereksiz kılar."]'::jsonb, 1, $$Korelasyon; ilişkiyi ölçer ancak nedenselliği kanıtlayamaz. Korelasyonu nedensellikle özdeşleştirmek en yaygın istatistiksel yanılgılardan biridir.$$, 4, 3),
('96209f71-7313-4cbf-a499-5cad686357eb','vocabulary',$$Metinde geçen "p değeri" kavramı ne anlama gelir?$$,'["Bir araştırmanın pratik önem düzeyi","Veriler doğru olsaydı null hipotezi altında gözlemlenen ya da daha uç bir sonucun ortaya çıkma olasılığı","İki değişken arasındaki ilişkinin gücü","Örneklemin ana kütleyi temsil etme derecesi"]'::jsonb, 1, $$p değeri; null hipotezinin doğru olduğu varsayımıyla gözlemlenen (ya da daha uç) sonuçların elde edilme olasılığını ifade eder.$$, 4, 4),
('96209f71-7313-4cbf-a499-5cad686357eb','tone',$$Yazarın istatistiksel yöntemlere yaklaşımı nasıl nitelendirilebilir?$$,'["Eleştirel; istatistiğin bilimde kullanımını sorgulamaktadır.","Açıklayıcı ve metodolojik; istatistiksel araçları doğru anlama ve uygulamanın önemini vurgulamaktadır.","Teknik ve sınırlı kitlelere yönelik; yalnızca uzmanları hedeflemektedir.","Yanlılık ve sınırlılıkları önemsizleştiren savunmacı bir üslupla"]'::jsonb, 1, $$Metin; istatistiksel kavramları sınırlılıklarını açıkça belirterek pedagojik ve erişilebilir bir dille sunmaktadır.$$, 4, 5);
INSERT INTO text_questions (text_id, question_type, question_text, options, correct_index, explanation, difficulty, order_index) VALUES
('ba00bfdf-8349-42da-98ca-0f2893ce2d6c','main_idea',$$Bu metnin ana iddiası nedir?$$,'["Bilinç deneysel yöntemlerle tam olarak ölçülebilir.","Bilinç; nörobilimsel ve felsefî boyutlarıyla, beyin süreçleri ile öznel deneyim arasındaki derin gizemden kaynaklanan zorlu bir soru olmayı sürdürmektedir.","Bilinç yalnızca felsefenin konusudur.","Beyin görüntüleme teknolojisi bilinci eksiksiz biçimde açıklamaktadır."]'::jsonb, 1, $$Metin; bilinci hem nörobilimsel hem felsefî açıdan ele almakta ve bu iki disiplinin sınırlarını aşan zorlu bir sorun olduğunu vurgulamaktadır.$$, 5, 1),
('ba00bfdf-8349-42da-98ca-0f2893ce2d6c','detail',$$Nöral korelatlar bilinç araştırması açısından nasıl tanımlanmaktadır?$$,'["Bilinçli deneyimden bağımsız beyin aktiviteleri","Bilinçli deneyimle tutarlı biçimde eşleşen, onunla korelasyon gösteren nöronal aktiviteler; ancak bu aktivitelerin deneyimi oluşturup oluşturmadığı hâlâ tartışmalıdır.","Beyin-zihin ilişkisinin tam anlamıyla açıklanması","Bilinç hallerini doğrudan yaratan belirli beyin bölgeleri"]'::jsonb, 1, $$NCC araştırması, beyin aktivitesini öznel deneyimle ilişkilendirmeye çalışmakta; ancak bu ilişkinin nedensel mi yoksa eşzamanlı mı olduğu sorusu yanıtsız kalmaktadır.$$, 5, 2),
('ba00bfdf-8349-42da-98ca-0f2893ce2d6c','inference',$$"Zor problem"in varlığı felsefî açıdan ne anlama gelmektedir?$$,'["Bilinç sorununun yalnızca teknolojik sınırlılıklar nedeniyle güç olduğuna işaret eder.","Fiziksel beyin süreçleri ile öznel deneyim arasındaki kavramsal uçurumun yalnızca ampirik kanıtla değil, felsefî çözümlemelerle de ele alınmasını zorunlu kıldığına işaret eder.","Zor problem bilinç araştırmacılarını cesaretsizleştirmektedir.","Bilinç felsefesi biyolojik bulguları göz ardı etmektedir."]'::jsonb, 1, $$Zor problem; qualia ve öznel deneyimi fiziksel beyin mekanizmalarına indirgemekle ya da açıklamakla yüzleşilemeyen derin bir kavramsal güçlüğe dikkat çeker.$$, 5, 3),
('ba00bfdf-8349-42da-98ca-0f2893ce2d6c','vocabulary',$$Metinde geçen "qualia" kavramı nasıl açıklanmaktadır?$$,$$["Beyinde gerçekleşen nesnel nöronal ateşleme örüntüleri","Deneyimlerin öznel, birinci şahıs boyutu; örneğin kırmızıyı görmenin nasıl bir şey olduğu gibi","Zihinsel süreçlerin ölçülebilir davranışsal göstergeleri","Bilinçli düşüncenin nörobilimsel mekanizması"]$$::jsonb, 1, $$Qualia; deneyimin ham, öznel hissiyatını (fenomenal bilinç) ifade etmektedir ve doğrudan üçüncü şahıs perspektifinden ölçülmesi güçtür.$$, 5, 4),
('ba00bfdf-8349-42da-98ca-0f2893ce2d6c','tone',$$Metindeki yazarın bilince ilişkin tutumu nasıl nitelendirilebilir?$$,'["Bilinç gizeminin tamamen çözülebileceğinden emin olan","Mevcut nörobilimsel paradigmalar içinde bilincin açıklanamayacağı yönünde kötümser","Nesnel olgularla öznel deneyim arasındaki mesafeyi kabul eden, hem umut verici hem de dürüstçe belirsiz","Bilinç araştırmasının önemini küçümseyen"]'::jsonb, 1, $$Metin; gerçek bilimsel ilerlemeyi kabul etmekte, ancak nesnel nörobilim ile öznel deneyim arasında hâlâ derinlemesine yanıt bekleyen kavramsal boşlukların varlığını da açıkça dile getirmektedir.$$, 5, 5);
INSERT INTO text_questions (text_id, question_type, question_text, options, correct_index, explanation, difficulty, order_index) VALUES
('a9c68a82-c735-4615-9144-e13c99e2435d','main_idea',$$Bu metnin temel odağı nedir?$$,'["Davranışçılık en kapsamlı psikolojik teori olarak kabul edilmektedir.","Bilişsel süreçler; algı, dikkat, bellek ve problem çözme gibi zihinsel işlemleri kapsamakta ve insan davranışıyla deneyiminin anlaşılmasında merkezi bir rol üstlenmektedir.","Bilişsel psikoloji yalnızca beyin bozukluklarıyla ilgilenmektedir.","Duygular bilişsel süreçlerden bütünüyle bağımsızdır."]'::jsonb, 1, $$Metin; temel bilişsel süreçleri ve bunların insan davranışını anlamlandırmadaki önemini ele almaktadır.$$, 4, 1),
('a9c68a82-c735-4615-9144-e13c99e2435d','detail',$$Çalışma belleği ile uzun süreli bellek arasındaki fark nasıl açıklanmaktadır?$$,'["İkisi de sınırsız kapasiteye sahiptir.","Çalışma belleği sınırlı kapasiteli ve geçici bir aktif işlem alanıdır; uzun süreli bellek ise büyük miktarda bilgiyi kalıcı olarak depolar.","Uzun süreli bellek yalnızca motor becerileri saklar.","Çalışma belleği yaşla birlikte sonsuz genişler."]'::jsonb, 1, $$Çalışma belleği kısa süreli, aktif ve sınırlı kapasiteli iken uzun süreli bellek potansiyel olarak sınırsız kalıcı depolamaya imkân tanır.$$, 4, 2),
('a9c68a82-c735-4615-9144-e13c99e2435d','inference',$$Bilişsel yük teorisi eğitim tasarımı açısından ne anlama gelir?$$,'["Eğitim materyalleri olabildiğince karmaşık olmalıdır.","Öğrenme etkinliği; çalışma belleğinin sınırlı kapasitesi gözetilerek bilginin işlenebilir parçalara bölünmesiyle artırılabilir.","Bilişsel yük miktarı öğrenmeyi etkilemez.","Uzman öğreniciler sınırsız bilişsel yük taşıyabilir."]'::jsonb, 1, $$Bilişsel yük teorisi; çalışma belleğinin kısıtlamalarını göz önünde bulunduran eğitim tasarımının öğrenme çıktılarını anlamlı ölçüde iyileştirdiğini ortaya koymaktadır.$$, 4, 3),
('a9c68a82-c735-4615-9144-e13c99e2435d','vocabulary',$$Metinde geçen "üst biliş" (metakognisyon) kavramı ne anlama gelir?$$,'["Şuuraltı düşünce süreçleri","Kişinin kendi bilişsel süreçleri hakkında düşünme, izleme ve düzenleme kapasitesi","Kolektif zekanın birden fazla bireyde tezahür etmesi","Kompleks öğrenme görevleri sırasında oluşan bilişsel yük"]'::jsonb, 1, $$Üst biliş; kendi düşünme süreçlerini denetleme ve düzenleme becerisidir; etkili öğrenme stratejileri ve problem çözmeyle doğrudan ilişkilidir.$$, 4, 4),
('a9c68a82-c735-4615-9144-e13c99e2435d','tone',$$Yazarın bilişsel psikoloji araştırmalarına yaklaşımı nasıl nitelendirilebilir?$$,'["Ampirik bulgular için aşırı iddialar öne süren","Analitik, kanıta dayalı ve uygulama bağlantılarına önem veren","Bilişsel yaklaşımları eleştiren ve davranışçılığı savunan","Yalnızca nörogörüntüleme bulgularına güvenen"]'::jsonb, 1, $$Metin; bilişsel kavramları araştırma kanıtlarıyla destekleyerek sunmakta ve pratik uygulamalara açıkça atıfta bulunmaktadır.$$, 4, 5);
INSERT INTO text_questions (text_id, question_type, question_text, options, correct_index, explanation, difficulty, order_index) VALUES
('32ed0b95-e40c-4d28-9445-1b613d9116aa','main_idea',$$Bu metnin ana fikri nedir?$$,'["Kimlik biyolojik olarak belirlenmekte ve değişmemektedir.","Kimlik; kültür, toplumsal yapılar ve tarihsel süreçlerle şekillenen dinamik ve çok boyutlu bir inşa ürünüdür.","Kültür, kimlik üzerinde herhangi bir etkiye sahip değildir.","Küreselleşme kültürel farklılıkları ortadan kaldırmıştır."]'::jsonb, 1, $$Metin; kimliği değişmez bir öz olarak değil, toplumsal bağlam içinde sürekli inşa edilen bir süreç olarak ele almaktadır.$$, 4, 1),
('32ed0b95-e40c-4d28-9445-1b613d9116aa','detail',$$Goffman''ın gündelik etkileşimde kimlik sunumuna ilişkin teorisi ne anlama gelmektedir?$$,$$["Kimlik, biyolojik içgüdülerin bir yansımasıdır.","Bireyler sosyal bağlama, izleyici kitlesine ve istenen izlenime göre kimliklerini stratejik biçimde sunar; bu durum sahne yönetimi olarak kavramlaştırılmaktadır.","Kimlik sunumu bilinçsiz bir süreçtir.","Insanlar her bağlamda aynı kimliği sergiler."]$$::jsonb, 1, $$Goffman''ın dramatürjik yaklaşımı; toplumsal etkileşimi kimlik müzakeresi açısından bir tiyatro performansı olarak çözümler.$$, 4, 2),
('32ed0b95-e40c-4d28-9445-1b613d9116aa','inference',$$Küreselleşmenin kimlik üzerindeki etkisi hakkında ne çıkarılabilir?$$,'["Küreselleşme kültürel kimlikleri tamamen yok etmektedir.","Küresel kültürel akışlar ile yerel kimlikler arasındaki dinamik gerilim, yeni melez kimlik biçimlerinin ortaya çıkmasına zemin hazırlamaktadır.","Kimlikler küresel etkilerden bütünüyle korunmaktadır.","Küreselleşme yalnızca ekonomik kimliği etkilemektedir."]'::jsonb, 1, $$Melezlik ve glocalization (küyerelleşme) kavramları; yerel ve küresel etkilerin kimlik üzerinde ne denli karmaşık etkileşimlere yol açtığını somutlaştırmaktadır.$$, 4, 3),
('32ed0b95-e40c-4d28-9445-1b613d9116aa','vocabulary',$$Metinde geçen "müzakere edilmiş kimlik" kavramı ne anlama gelir?$$,'["Yasal belgelerle belirlenen resmi kimlik","Bireyin öz algısı ile sosyal çevrenin ona yüklediği kimlik arasındaki dinamik etkileşim süreci","Değişmeyen ve içinde yetişilen kültürden devralınan kimlik","Etnik miras tarafından tamamen belirlenen sabit kimlik"]'::jsonb, 1, $$Müzakere edilmiş kimlik; kişisel benlik algısı ile toplumsal tanıma ve beklentiler arasındaki süregelen diyaloğu ifade etmektedir.$$, 4, 4),
('32ed0b95-e40c-4d28-9445-1b613d9116aa','tone',$$Yazarın kimlik ve kültür tartışmasındaki tutumu nasıl nitelendirilebilir?$$,'["Kültürel görelilik üzerine kurulu ve değer yargılarından arınmış","Analitik, yapısalcı ve çoklu kültürel perspektiflere duyarlı","Belirli bir ulusal kimliği diğerlerinden üstün gören","İnsan kimliğine ilişkin özcü bir bakış açısı benimseyen"]'::jsonb, 1, $$Metin; kimliği sosyal açıdan inşa edilmiş, bağlamsallaştırılmış bir olgu olarak çözümlemekte ve çeşitli teorik perspektifleri dengeli biçimde ele almaktadır.$$, 4, 5);
INSERT INTO text_questions (text_id, question_type, question_text, options, correct_index, explanation, difficulty, order_index) VALUES
('27cec9f6-61ac-45bb-a4a5-ac85f96db988','main_idea',$$Bu pasajın merkezi argümanı nedir?$$,'["Yapay zeka ahlaki kararlar alabilecek kapasitededir.","YZ''nin hızla yayılması; şeffaflık, hesap verebilirlik, önyargı ve değerlerin sisteme gömülmesi konularında çözüm bekleyen etik sorunları gündeme taşımaktadır.","YZ etik sorunları teorik düzeyde kalacak, pratik bir etkisi olmayacaktır.","Teknik mükemmellik YZ''yi özümsünen toplumsal etik sorunları otomatik olarak çözüme kavuşturur."]'::jsonb, 1, $$Metin; YZ dağıtımının beraberinde getirdiği etik boyutlara yönelik dikkatli bir değerlendirme çağrısı yapmaktadır.$$, 4, 1),
('27cec9f6-61ac-45bb-a4a5-ac85f96db988','detail',$$Algoritmik önyargı hangi koşullarda ortaya çıkmaktadır?$$,'["Yalnızca hatalı programlama yapıldığında","Eğitim verisi var olan toplumsal eşitsizlikleri yansıtıyorsa ya da model tasarımı yetersiz kalıyorsa","Yapay zeka sistemi eski donanım üzerinde çalışıyorsa","Yalnızca insanlar veriyi manipüle ettiğinde"]'::jsonb, 1, $$Algoritmik önyargı genellikle eğitim verilerindeki örüntülerden ya da tasarım tercihlerinden kaynaklanır; sistematik hatalara yol açarak adaletsiz sonuçlar doğurabilir.$$, 4, 2),
('27cec9f6-61ac-45bb-a4a5-ac85f96db988','inference',$$YZ sistemlerinde hesap verebilirliğin eksikliği hakkında ne çıkarılabilir?$$,'["YZ sistemleri hesap verebilirlik gerektirmez.","Otonom karar almanın nerede son bulduğu ve insan sorumluluğunun nerede başladığı belirsizleştikçe etik boşluklar oluşmakta; bu durum zarara maruz kalanlar için hukuki başvuru yollarını tıkamaktadır.","YZ şirketleri hesap verebilirliği kendi iç süreçleriyle yeterince güvence altına almaktadır.","Hesap verebilirlik sorunları yalnızca askeri YZ uygulamalarını kapsamaktadır."]'::jsonb, 1, $$YZ''nin karmaşık ekosistemi; paydaşları, karar mekanizmalarını ve hukuki sorumluluk sınırlarını belirsizleştirerek yapısal bir hesap verebilirlik açığı yaratmaktadır.$$, 4, 3),
('27cec9f6-61ac-45bb-a4a5-ac85f96db988','vocabulary',$$Metinde geçen "açıklanabilir YZ" (explainable AI) kavramı ne anlama gelir?$$,'["Basitleştirilmiş algoritmalar kullanan YZ","YZ''nin bir karara nasıl ulaştığını insan anlaşılır biçimde sunabilen, şeffaf ve yorumlanabilir sistem tasarımı","Programlama süreci herkese açık olarak belgelenen YZ","Karar verme sürecini tamamen insan denetimine bırakan sistem"]'::jsonb, 1, $$Açıklanabilir YZ; özellikle yüksek riskli bağlamlarda makul gerekçeler sunmak için hesap verebilirlik ve güven açısından kritik öneme sahiptir.$$, 4, 4),
('27cec9f6-61ac-45bb-a4a5-ac85f96db988','tone',$$Yazarın YZ etiğine yaklaşımı nasıl nitelendirilebilir?$$,'["YZ gelişimini durdurmayı savunan tedirgin","Yenilik ile sorumlu dağıtım arasındaki dengeyi gözeten, dikkatli ve düzenleyici odaklı","YZ''ye sınırsız iyimserlikle yaklaşan","Toplumsal kaygıları önemsizleştiren saf teknik bakış açısı"]'::jsonb, 1, $$Metin; YZ''nin potansiyelini kabul ederken bu teknolojiyi etkin biçimde yönetecek değer odaklı çerçevelerin ve düzenleyici mekanizmaların gerekliliğini özellikle vurgulamaktadır.$$, 4, 5);
INSERT INTO text_questions (text_id, question_type, question_text, options, correct_index, explanation, difficulty, order_index) VALUES
('7ed24693-1ca0-4e49-ac8b-cfde26eb7238','main_idea',$$Bu metnin ana fikri nedir?$$,'["Anadolu yalnızca Karadeniz kıyılarından ibarettir.","Anadolu''nun çeşitli iklim kuşakları, dağlık yapısı ve stratejik konumunun oluşturduğu özgün coğrafi yapı; tarihsel ve ekonomik önemini belirleyen temel unsurdur.","Anadolu düz bir platodur ve iklim değişkenliği yoktur.","Anadolu''nun coğrafi özellikleri ekonomik kalkınmayı engellemiştir."]'::jsonb, 1, $$Metin; Anadolu''nun coğrafi çeşitliliğini ve bu çeşitliliğin tarihsel-ekonomik önemdeki rolünü vurgulamaktadır.$$, 2, 1),
('7ed24693-1ca0-4e49-ac8b-cfde26eb7238','detail',$$Metne göre Orta Anadolu Platosu''nun belirgin özelliği nedir?$$,'["Yoğun orman örtüsü ve yüksek yağış","Az yağışlı karasal iklim; bozkır bitki örtüsü ve tahıl tarımının ön plana çıktığı geniş düzlükler","Dört mevsim ılıman iklim","Türkiye''nin en dağlık bölgesi olması"]'::jsonb, 1, $$Orta Anadolu Platosu; karasal iklimi, bozkır bitki örtüsü ve tahıl ekimine uygun geniş düzlükleriyle tanınmaktadır.$$, 2, 2),
('7ed24693-1ca0-4e49-ac8b-cfde26eb7238','inference',$$Türkiye''nin hem Avrupa hem Asya''ya bağlanan bir köprü konumda bulunması hakkında ne çıkarılabilir?$$,'["Bu konum yalnızca askeri açıdan önemlidir.","Anadolu''nun konumu; tarihin her döneminde göçlere, ticaret güzergahlarına ve kültürel alışverişe zemin hazırlamış, geopolitik açıdan merkezî bir değer kazandırmıştır.","Bu konum kalkınmayı olumsuz etkilemiştir.","Köprü konumu yalnızca modern tarihte stratejik bir anlam taşımaktadır."]'::jsonb, 1, $$Anadolu''nun iki kıta arasındaki köprü konumu; İpek Yolu''nun geçiş noktası olmasından tutun Osmanlı''nın yükselişine dek pek çok tarihsel süreci doğrudan etkilemiştir.$$, 2, 3),
('7ed24693-1ca0-4e49-ac8b-cfde26eb7238','vocabulary',$$Metinde geçen "endemik tür" kavramı ne anlama gelir?$$,'["Dünya genelinde yayılmış tür","Yalnızca belirli bir coğrafi alanda doğal olarak yaşayan tür","Nesli tehlike altındaki tür","Yabancı bölgelerden getirilmiş tür"]'::jsonb, 1, $$Endemik türler; yalnızca belirli bir bölgede doğal olarak dağılım gösteren ve başka yerlerde doğal koşullarda bulunmayan canlılardır.$$, 2, 4),
('7ed24693-1ca0-4e49-ac8b-cfde26eb7238','detail',$$Türkiye''nin birden fazla iklim tipine sahip olmasının başlıca nedeni nedir?$$,'["Küçük yüz ölçümü","Dağların yüksekliği, denizlere göre konum ve enlemler arası farklılık","Yalnızca coğrafi konumu","Büyük nehirlerin varlığı"]'::jsonb, 1, $$İklim çeşitliliği; Türkiye''nin dağlık yapısı, Akdeniz''e ve Karadeniz''e kıyısı ve enlem farklılıklarının bir araya gelmesiyle açıklanmaktadır.$$, 2, 5);
INSERT INTO text_questions (text_id, question_type, question_text, options, correct_index, explanation, difficulty, order_index) VALUES
('179bd104-cb82-4986-9576-d9b93ac1b874','main_idea',$$Bu metnin ana fikri nedir?$$,'["Türkiye tek taraflı bir dış politika izlemektedir.","Türkiye''nin dış politikası; stratejik konumu, Batı ile ittifak ilişkileri, bölgesel dinamikler ve zaman içinde evrilen ulusal çıkarlarla şekillenen çok boyutlu bir yapı sergilemektedir.","Türkiye hiçbir bölgesel güç olma iddiası taşımamaktadır.","Türk dış politikası değişmez bir çizgide seyretmiştir."]'::jsonb, 1, $$Metin; Türk dış politikasının iç içe geçmiş belirleyicilerini ve tarihsel süreçteki değişimini çok boyutlu biçimde ele almaktadır.$$, 3, 1),
('179bd104-cb82-4986-9576-d9b93ac1b874','detail',$$Türkiye''nin NATO üyeliğinin dış politikadaki işlevi nedir?$$,'["Türkiye NATO''ya yalnızca ekonomik çıkar güderek katılmıştır.","NATO üyeliği; Soğuk Savaş''tan bu yana savunma taahhütleri, ittifak yükümlülükleri ve Batı kurumsal düzeniyle bütünleşme açısından Türk dış politikasının temel eksenini oluşturmaktadır.","NATO üyeliği Türkiye''yi Orta Doğu meselelerinden uzaklaştırmaktadır.","Türkiye NATO''nun kurucu üyelerinden biridir."]'::jsonb, 1, $$1952''den bu yana sürdürülen NATO üyeliği; Türkiye''nin savunma, güvenlik ve Batı ittifak sistemi içindeki konumlanmasını belirleyen temel çerçeve olmayı korumaktadır.$$, 3, 2),
('179bd104-cb82-4986-9576-d9b93ac1b874','inference',$$Türkiye''nin hem Batı ittifakları hem de bölgesel aktörlerle ilişki kurma çabası hakkında ne çıkarılabilir?$$,'["Bu denge Türkiye''nin tutarsız bir politika izlediğini göstermektedir.","Çok taraflı ilişkiler; coğrafi konumun dayattığı kısıtlar içinde ulusal çıkarları azami ölçüde koruyan pragmatik bir stratejiyi yansıtmaktadır.","Türkiye her zaman NATO çıkarlarını bölgesel ilişkilerin önünde tutmuştur.","Bölgesel angajman politikası Türkiye''nin AB hedefleriyle çelişmektedir."]'::jsonb, 1, $$Türkiye''nin stratejik muğlaklığı; çakışan çıkarlar ve coğrafi konumun dayattığı bir ikilem içinde pragmatik bir dengeleme tutumunu yansıtmaktadır.$$, 3, 3),
('179bd104-cb82-4986-9576-d9b93ac1b874','vocabulary',$$Metinde geçen "yumuşak güç" kavramı nasıl tanımlanmaktadır?$$,'["Askeri ve ekonomik baskı araçları","Kültür, diplomasi, eğitim ve medya aracılığıyla davranış biçimlendirme ve cazip olma kapasitesi","Tarihsel toprak talepleri","Uluslararası örgütler içindeki oy ağırlığı"]'::jsonb, 1, $$Yumuşak güç; zorlama yerine çekicilik ve ikna yoluyla etki yaratma kapasitesini ifade etmekte; Türkiye bu aracı kültürel dışişleri, TRT World ve Türk dizileri üzerinden kullanmaktadır.$$, 3, 4),
('179bd104-cb82-4986-9576-d9b93ac1b874','detail',$$Türkiye''nin AB üyelik sürecini etkileyen başlıca faktörler nelerdir?$$,'["Süreç yalnızca teknik standartları kapsamaktadır.","Demokratik yönetişim sorunları, Kıbrıs meselesi ve AB ile zaman zaman yaşanan anlaşmazlıklar üyelik müzakerelerini askıya almıştır.","AB siyasi değerlendirmeler yapmaksızın yalnızca ekonomik kriterlere göre karar almaktadır.","Türkiye AB üyeliğinden tamamen vazgeçmiştir."]'::jsonb, 1, $$Türkiye-AB ilişkileri; 1987''deki resmi başvurudan bu yana demokratik standartlar, insan hakları ve çözüme kavuşturulamamış siyasi meseleler ekseninde iniş çıkışlı bir seyir izlemektedir.$$, 3, 5);
INSERT INTO text_questions (text_id, question_type, question_text, options, correct_index, explanation, difficulty, order_index) VALUES
('6c98ecfb-d510-40bb-b82b-eac8f14f4401','main_idea',$$Bu metnin ana fikri nedir?$$,'["Türkiye ekonomisi yalnızca tarıma dayanmaktadır.","Türkiye''nin ekonomik dönüşümü; devlet güdümlü sanayileşmeden ihracata yönelik büyümeye uzanan köklü bir yapısal değişim sürecini kapsamaktadır.","Türk ekonomisi tüm dönemlerde sürekli büyüme kaydetmiştir.","Özel sektör Türk kalkınmasında hiçbir zaman belirleyici bir rol üstlenmemiştir."]'::jsonb, 1, $$Metin; Türkiye''nin devlet merkezli ekonomiden dışa açık bir yapıya geçiş sürecini çeşitli kalkınma evreleriyle ortaya koymaktadır.$$, 3, 1),
('6c98ecfb-d510-40bb-b82b-eac8f14f4401','detail',$$1980 sonrası Türk ekonomi politikasında ne tür bir dönüşüm yaşanmıştır?$$,'["İçe kapanma ve ithal ikameci sanayileşme yoğunlaştı.","IMF destekli liberalleşme reformları; ithalat kısıtlamalarını kaldırarak dışa yönelik ihracat odaklı büyüme stratejisine zemin hazırladı.","Devlet planlaması ekonomik kararların tamamını belirledi.","Özel sektör piyasalardan tamamen çekildi."]'::jsonb, 1, $$1980 Turgut Özal reformları; Türkiye ekonomisini küreselleşme ekseninde yeniden yapılandıran kritik bir dönüm noktası olmuştur.$$, 3, 2),
('6c98ecfb-d510-40bb-b82b-eac8f14f4401','inference',$$Türkiye''nin kronik enflasyon sorunuyla mücadelesi hakkında ne çıkarılabilir?$$,'["Enflasyon Türkiye''de hiçbir dönem ciddi bir sorun olmamıştır.","Tekrarlanan enflasyon dönemleri; para politikasındaki istikrarsızlıklara ve yapısal ekonomik sorunlara işaret etmekte, uzun dönemli planlamayı güçleştirmektedir.","Yüksek enflasyon ekonomik büyümeyi doğrudan desteklemektedir.","Enflasyon yalnızca döviz kuru dalgalanmalarından kaynaklanmaktadır."]'::jsonb, 1, $$Türkiye''nin yüksek enflasyon geçmişi; para politikasına duyulan güveni sarsmakta ve uzun vadeli yatırım ortamını olumsuz etkilemektedir.$$, 3, 3),
('6c98ecfb-d510-40bb-b82b-eac8f14f4401','vocabulary',$$Metinde geçen "ithal ikameci sanayileşme" kavramı ne anlama gelir?$$,'["İhracatı artırarak dış ticaret açığını kapatma stratejisi","Dışarıdan satın alınan malların yurt içinde üretilmesini teşvik ederek dışa bağımlılığı azaltmayı hedefleyen kalkınma stratejisi","Döviz rezervlerini yönetmek amacıyla yapılan döviz müdahaleleri","Sermaye piyasasının açılmasını sağlayan finansal liberalleşme politikaları"]'::jsonb, 1, $$İthal ikameci sanayileşme; yurt içi üretimi koruma altına alarak dış bağımlılığı azaltmayı, ulusal sanayiyi geliştirmeyi ve istihdam yaratmayı amaçlayan bir kalkınma modelidir.$$, 3, 4),
('6c98ecfb-d510-40bb-b82b-eac8f14f4401','detail',$$2001 ekonomik krizi Türkiye''nin kalkınma sürecini nasıl etkilemiştir?$$,'["Kriz, herhangi bir politika değişikliğine yol açmamıştır.","Finansal çöküş; IMF ile kapsamlı bir istikrar programının hayata geçirilmesini zorunlu kılmış ve bankacılık sisteminin yeniden düzenlenmesini beraberinde getirmiştir.","Kriz yalnızca belirli bir sektörü etkilemiştir.","2001 krizi başka bir ülkenin iç sorunundan kaynaklanmıştır."]'::jsonb, 1, $$2001 krizi; köklü bankacılık reformlarını ve IMF destekli sıkı maliye politikalarını gündeme taşıyan bir yapısal dönüşüm sürecini başlatmıştır.$$, 3, 5);
INSERT INTO text_questions (text_id, question_type, question_text, options, correct_index, explanation, difficulty, order_index) VALUES
('9f05d8cd-a2a7-4e3a-b6a8-5ddbd5c2b6dd','main_idea',$$Bu metnin ana fikri nedir?$$,'["İnsan hakları yalnızca uluslararası örgütlerin ilgi alanındadır.","Türkiye; insan hakları standartlarını anayasal güvencelerle koruma altına almış olmakla birlikte uygulama ve uluslararası uyum konularında süregelen güçlüklerle yüzleşmektedir.","Türkiye''de insan hakları meseleleri tamamen çözüme kavuşturulmuştur.","İnsan hakları iç hukuk kapsamında değerlendirilemez."]'::jsonb, 1, $$Metin; Türkiye''nin insan hakları çerçevesini, normatif taahhütlerini ve uygulama aşamasındaki sorunlarını birlikte ele almaktadır.$$, 3, 1),
('9f05d8cd-a2a7-4e3a-b6a8-5ddbd5c2b6dd','detail',$$Avrupa İnsan Hakları Mahkemesi''nin Türkiye açısından önemi nedir?$$,'["AİHM kararları Türkiye için bağlayıcı değildir.","AİHM; Türkiye''nin taraf olduğu davalarda bağlayıcı kararlar vermekte, önemli ihlal tespitlerinde bulunmakta ve içtihadıyla ulusal reformları yönlendirmektedir.","AİHM yalnızca Avrupa''da yerleşik bireylerin başvurularını kabul etmektedir.","Türkiye AİHM kararlarını hiçbir zaman uygulamamaktadır."]'::jsonb, 1, $$AİHM''nin Türkiye aleyhine verdiği kararlar; anayasa reformlarını ve yargı uygulamalarını doğrudan etkilemiştir.$$, 3, 2),
('9f05d8cd-a2a7-4e3a-b6a8-5ddbd5c2b6dd','inference',$$Türkiye''nin insan hakları performansına yönelik eleştiriler hakkında ne çıkarılabilir?$$,'["Bu eleştiriler yabancı güçlerin iç işlerine müdahale girişimidir.","Sistematik güçlükler; anayasal taahhütler ile pratikte uygulanan standartlar arasındaki derin uçurum nedeniyle sürmekte ve AB üyelik sürecini olumsuz etkilemektedir.","Eleştiriler yalnızca geçmişteki uygulamalara yöneliktir.","Uluslararası insan hakları standartları Türkiye''de yasal bağlayıcılık taşımamaktadır."]'::jsonb, 1, $$İnsan hakları sorunları; hem iç demokratikleşme tartışmalarında hem de AB üyelik sürecinde belirleyici bir etken olmaya devam etmektedir.$$, 3, 3),
('9f05d8cd-a2a7-4e3a-b6a8-5ddbd5c2b6dd','vocabulary',$$Metinde geçen "olağanüstü hal" kavramı hak ve özgürlükler açısından ne anlama gelir?$$,'["Normal anayasal düzenin işleyişini güçlendiren bir mekanizma","Hükümetin belirli hakları ve güvenceleri askıya alabileceği, olağan dışı dönemlerde ilan edilen geçici yönetim biçimi","Olağanüstü hallerin haklar üzerinde hiçbir etkisi yoktur.","Yalnızca ekonomik krizlerde başvurulan bir önlem"]'::jsonb, 1, $$Olağanüstü hal dönemleri; bazı hakları uluslararası hukuk çerçevesinde geçici olarak askıya alabilmekte ve bu süreçlerin denetlenmesi güçleşmektedir.$$, 3, 4),
('9f05d8cd-a2a7-4e3a-b6a8-5ddbd5c2b6dd','detail',$$Türkiye''de sivil toplum kuruluşlarının insan hakları alanındaki işlevi nedir?$$,'["STK''lar Türkiye''de bu alanda herhangi bir rol üstlenmemiştir.","STK''lar ihlalleri belgelemekte, kamuoyunu bilinçlendirmekte ve bazen de siyasi baskıyla karşılaşarak hakların geliştirilmesi sürecine katkı sağlamaktadır.","STK''lar yalnızca hükümet talepleri doğrultusunda faaliyet göstermektedir.","Sivil toplum insan hakları gelişimine olumsuz etki etmektedir."]'::jsonb, 1, $$Sivil toplum; insan hakları savunuculuğunda kritik bir rol üstlenmekte; ancak zaman zaman yasal kısıtlamalar ve baskılarla karşı karşıya kalmaktadır.$$, 3, 5);
INSERT INTO text_questions (text_id, question_type, question_text, options, correct_index, explanation, difficulty, order_index) VALUES
('92ac76c4-c202-434f-b8af-fe110219850c','main_idea',$$Bu metnin ana fikri nedir?$$,'["Türkiye''nin anayasal düzeni Cumhuriyet''ten bu yana değişmeden kalmıştır.","Türkiye''nin anayasal yapısı; demokratik cumhuriyet ilkelerini esas alarak yönetim organları arasında görev paylaşımını düzenlemekte ve temel hakları güvence altına almaktadır.","Türk anayasaları hiçbir siyasi değişimi yansıtmamaktadır.","Anayasal düzen yalnızca seçim süreçleriyle sınırlıdır."]'::jsonb, 1, $$Metin; Türkiye''nin anayasal çerçevesini, yönetim yapısını ve güvence altındaki temel hakları ele almaktadır.$$, 3, 1),
('92ac76c4-c202-434f-b8af-fe110219850c','detail',$$Türkiye''nin 2017 anayasa reformu hangi temel değişiklikleri getirmiştir?$$,'["Parlamenter sistemi güçlendirmiştir.","Başbakanlık makamı lağvedilerek cumhurbaşkanlığı merkezinde hükümet gücünü yoğunlaştıran başkanlık sistemine geçilmiştir.","Yerel yönetimlerin yetkileri genişletilmiştir.","Meclisin yasama yetkileri artırılmıştır."]'::jsonb, 1, $$2017 referandumuyla onaylanan değişiklikler; yürütme yetkisini cumhurbaşkanlığı makamında toplayarak parlamenter sistemden başkanlık sistemine geçişi resmileştirmiştir.$$, 3, 2),
('92ac76c4-c202-434f-b8af-fe110219850c','inference',$$Anayasal değişikliklerin referandumla onaylanması zorunluluğu hakkında ne çıkarılabilir?$$,'["Referandumlar anayasal değişiklikleri fiilen engeller.","Referandum şartı; temel değişiklikler için doğrudan halk onayını zorunlu kılarak anayasal değişim sürecine demokratik bir meşruiyet katmanı ekler.","Referandumlar yalnızca biçimsel bir onay sürecinden ibarettir.","Anayasal değişiklikler referanduma gerek kalmaksızın yapılabilir."]'::jsonb, 1, $$Referandum zorunluluğu; temel anayasal değişiklikler için popüler meşruiyet gerektirmekte ve aşırı reformist girişimlere karşı bir güvence işlevi görmektedir.$$, 3, 3),
('92ac76c4-c202-434f-b8af-fe110219850c','vocabulary',$$Metinde geçen "laiklik" ilkesi Türk anayasal sisteminde ne anlama gelir?$$,'["Anayasa''da dine herhangi bir atıfta bulunulmaması","Devlet kurumlarının dinî otoriteden ayrı tutulması; kamu politikalarının dinî hukuka değil, laik hukuka dayandırılması","Türkiye''nin tüm dinî faaliyetleri yasaklaması","Devlet kurumlarında dinî sembollerin zorunlu kılınması"]'::jsonb, 1, $$Türk laikliği; devleti dinî kurumlardan ayırmakta, ancak dini denetim altında tutma geleneğiyle diğer ülkelerin laiklik anlayışından farklılaşmaktadır.$$, 3, 4),
('92ac76c4-c202-434f-b8af-fe110219850c','detail',$$Anayasa Mahkemesi''nin Türk hukuk sistemindeki işlevi nedir?$$,'["Anayasa Mahkemesi yalnızca danışma niteliğinde görüş bildirir.","Kanunların anayasaya uygunluğunu denetler, temel hak ihlali iddialarını bireysel başvuru yoluyla inceler ve anayasal denge üzerinde belirleyici bir rol oynar.","Anayasa Mahkemesi''nin kararları bağlayıcı değildir.","Mahkeme yalnızca idari uyuşmazlıkları karara bağlar."]'::jsonb, 1, $$Türkiye Anayasa Mahkemesi; norm denetimi ve bireysel başvuru mekanizması aracılığıyla anayasal uyum ve hak korumasının güvencesidir.$$, 3, 5);
INSERT INTO text_questions (text_id, question_type, question_text, options, correct_index, explanation, difficulty, order_index) VALUES
('2ee74312-5ab8-487b-99d7-0c36a5261971','main_idea',$$Bu metnin ana fikri nedir?$$,'["Türkiye 1923''ten itibaren tam bir demokrasi olmuştur.","Türkiye''nin demokratikleşmesi; askeri müdahaleler, ekonomik krizler ve kurumsal reformlar arasında ilerleme ve gerilemenin birbirini izlediği karmaşık bir süreçtir.","Demokrasi Türkiye''ye dışarıdan dayatılmıştır.","Türk demokrasisi istikrarlı bir gelişme çizgisi izlemiştir."]'::jsonb, 1, $$Metin; Türk demokratikleşmesini doğrusal değil, iniş-çıkışlı bir süreç olarak ele almaktadır.$$, 3, 1),
('2ee74312-5ab8-487b-99d7-0c36a5261971','detail',$$1950 genel seçimlerinin demokratik önemi nedir?$$,'["1950 seçimleri yalnızca biçimsel bir süreçti.","İlk kez serbest ve adil şartlarda gerçekleştirilen bu seçimde CHP hükümeti DP''ye iktidarı barışçıl biçimde devretti; bu süreç demokratik geçişin somut bir göstergesi oldu.","1950 seçimleri tek parti sisteminin devamını sağladı.","Bu seçimler yabancı baskısının ürünüydü."]'::jsonb, 1, $$1950 seçimleri; Türkiye''de çok partili demokratik sistemin güçlenerek pekişmekte olduğunun ilk önemli sinyalini vermiştir.$$, 3, 2),
('2ee74312-5ab8-487b-99d7-0c36a5261971','inference',$$Türkiye''deki askeri müdahaleler demokratik pekişme açısından ne anlama gelmektedir?$$,'["Askeri müdahaleler Türk demokrasisini güçlendirmiştir.","Dönemsel müdahaleler demokratik sürekliliği sekteye uğratmış; kurumsal güven açığına, değişen sivil-asker ilişkilerine ve anayasal yeniden yapılanma ihtiyacına yol açmıştır.","Türk ordusunun siyasetten tamamen uzak durduğu görülmüştür.","Müdahaleler halk tarafından tutarlı biçimde benimsenmiştir."]'::jsonb, 1, $$1960, 1971, 1980 müdahaleleri ve 1997 postmodern darbesi; demokratik gelişimde ciddi kesintiler yaratmış ve kurumsal zafiyetleri derinleştirmiştir.$$, 3, 3),
('2ee74312-5ab8-487b-99d7-0c36a5261971','vocabulary',$$Metinde geçen "demokratik konsolidasyon" (pekişme) ne anlama gelir?$$,'["İlk serbest seçimlerin yapılması","Demokratik normlar, kurumlar ve değerlerin toplumsal yaşama yerleşerek alternatifsiz kalması; demokratik dışı alternatiflerin meşruiyetini yitirmesi","Yalnızca anayasal değişiklikler","Seçim mevzuatının oluşturulması"]'::jsonb, 1, $$Demokratik pekişme; seçimsel demokrasinin ötesine geçerek demokratik değerlerin halkın zihnine ve kurumsal yapılara derinden nüfuz etmesini ifade eder.$$, 3, 4),
('2ee74312-5ab8-487b-99d7-0c36a5261971','detail',$$Türkiye''nin AB üyelik sürecinin demokratikleşmeye katkısı ne olmuştur?$$,'["AB süreci Türkiye''yi demokratikleşmeden uzaklaştırmıştır.","1999-2005 döneminde yoğunlaşan AB üyelik müzakereleri; yargı reformu, ifade özgürlüğünün genişletilmesi ve sivil-asker ilişkilerinin yeniden düzenlenmesi gibi köklü değişimleri hızlandırmıştır.","AB aday statüsü iç reformlarda herhangi bir etkiye yol açmamıştır.","Demokratikleşme AB sürecinden tamamen bağımsız biçimde gerçekleşmiştir."]'::jsonb, 1, $$AB üyelik süreci; Türkiye''nin demokratik ve hukuki standartlarını Avrupa normlarıyla uyumlu hale getirdiği önemli bir reform dönemini beraberinde getirmiştir.$$, 3, 5);
INSERT INTO text_questions (text_id, question_type, question_text, options, correct_index, explanation, difficulty, order_index) VALUES
('29dd512b-f820-481e-a469-8b890d55bc8e','main_idea',$$Bu metnin ana fikri nedir?$$,'["Türkiye İkinci Dünya Savaşı''na aktif olarak katılmıştır.","Türkiye; İkinci Dünya Savaşı''nda titizlikle yürütülen denge politikasıyla savaşa girmekten kaçınmış ve savunma kapasitesini güçlendirmiştir.","Türkiye savaşa sonradan müttefikler safında girmiştir.","Türkiye''nin tarafsızlığı büyük güçler tarafından kabul görmemiştir."]'::jsonb, 1, $$Metin; Türkiye''nin ikili anlaşmalar ve hassas dengeleme politikasıyla savaş dışında kalma stratejisini ele almaktadır.$$, 3, 1),
('29dd512b-f820-481e-a469-8b890d55bc8e','detail',$$Türkiye''nin hem Almanya hem de İngiltere ile antlaşmalar imzalaması nasıl bir stratejiyi yansıtmaktadır?$$,'["Birleşik Devletler ile gizli ittifakın parçasıydı.","Gerçek anlamda tarafsız kalmayı mümkün kılırken birden fazla taraftan güvenlik güvencesi elde etmeye yönelik pragmatik bir denge politikasıydı.","Türkiye''nin Müttefiklere katılacağının habercisiydi.","Bu antlaşmalar uluslararası alanda geçersiz sayıldı."]'::jsonb, 1, $$Türkiye; hem Mihver hem Müttefik güçleriyle antlaşmalar imzalayarak tarafsızlığını muhafaza etmiş ve olası saldırganlığı caydırma yolunu seçmiştir.$$, 3, 2),
('29dd512b-f820-481e-a469-8b890d55bc8e','inference',$$Savaşın sonunda Türkiye''nin Almanya''ya savaş ilan etmesi hakkında ne çıkarılabilir?$$,'["Bu karar askeri müdahale amacıyla alındı.","BM kuruluş sürecine katılma koşulunu karşılamak için gerekli olan sembolik bir adım niteliğindeydi; savaşa fiilen katılma niyeti taşımıyordu.","Bu karar ciddi savaş kayıplarına yol açtı.","Türkiye Almanya''ya gerçek bir savaş alanı müdahalesi gerçekleştirdi."]'::jsonb, 1, $$Şubat 1945''teki savaş ilanı; gerçek bir askeri angajman değil, kurucu BM üyesi olmak için yerine getirilmesi gereken diplomatik bir zorunluluktu.$$, 3, 3),
('29dd512b-f820-481e-a469-8b890d55bc8e','vocabulary',$$Metinde geçen "tarafsızlık" (Türkiye''nin savaştaki politikası bağlamında) ne anlama gelir?$$,'["Uluslararası olaylara ilgisizlik","Çatışan taraflardan birine kesin olarak taraf tutmaksızın ticaret ve diplomatik ilişkileri sürdürme politikası","BM yükümlülüklerinin reddedilmesi","Anayasal açıdan zorunlu kılınan kalıcı barış politikası"]'::jsonb, 1, $$Türkiye; biçimsel ittifaktan kaçınırken her iki tarafla da ekonomik ve diplomatik ilişkilerini sürdüren aktif bir tarafsızlık politikası izlemiştir.$$, 3, 4),
('29dd512b-f820-481e-a469-8b890d55bc8e','detail',$$İkinci Dünya Savaşı'nın Türkiye''nin savaş sonrası dış politika yönelimi üzerindeki etkisi ne olmuştur?$$,'["Türkiye savaş sonrasında tarafsızlığını sürdürdü.","Savaşın ardından artan Sovyet baskısı Türkiye''yi ABD ile yakınlaşmaya, NATO''ya katılmaya ve Batı güvenlik düzenine dahil olmaya yöneltti.","Türkiye savaş sonrası dönemde Sovyetler Birliği ile ittifak kurdu.","Savaş Türkiye''nin dış politikasını hiç etkilemedi."]'::jsonb, 1, $$Sovyet genişlemesine karşı duyulan kaygı; Türkiye''yi Truman Doktrini''ni kabul etmeye ve 1952''de NATO''ya katılmaya yönelten belirleyici etken olmuştur.$$, 3, 5);
INSERT INTO text_questions (text_id, question_type, question_text, options, correct_index, explanation, difficulty, order_index) VALUES
('1aa9d2de-69d6-43bc-9afa-1775287b32c0','main_idea',$$Bu metnin ana fikri nedir?$$,'["Kurtuluş Savaşı yalnızca askeri bir çatışmadan ibarettir.","Millî Mücadele; Anadolu''nun yabancı kuvvetlerden arındırılmasını sağlayan ve hem siyasi hem askeri boyutlarıyla modern Türk devletinin temelini atan tarihi bir süreçtir.","Kurtuluş Savaşı''nın başarıya ulaşması rastlantısal koşulların ürünüdür.","Atatürk''ün rolü daha sonraki tarih yazımında abartılmıştır."]'::jsonb, 1, $$Metin; Kurtuluş Savaşı''nı askeri ve siyasi boyutlarıyla modern Türk devletinin kuruluş sürecinin temeli olarak ele almaktadır.$$, 2, 1),
('1aa9d2de-69d6-43bc-9afa-1775287b32c0','detail',$$Millî Mücadele döneminin siyasi örgütlenmesi nasıl şekillenmiştir?$$,'["Savaş yalnızca İstanbul Hükümetince yürütülmüştür.","Atatürk önderliğinde Ankara''da toplanan Büyük Millet Meclisi hem direniş hareketini örgütlemiş hem de savaşın ötesine geçen bir meşruiyet zemini oluşturmuştur.","Millî hareket herhangi bir siyasi örgütlenme olmaksızın kendiliğinden gelişmiştir.","Direniş yalnızca askeri komutanlar tarafından yönetilmiştir."]'::jsonb, 1, $$23 Nisan 1920''de kurulan TBMM; varolan İstanbul Hükümeti''nin meşruiyetini sorgulanır hale getirmiş ve millî egemenliğin simgesi olmuştur.$$, 2, 2),
('1aa9d2de-69d6-43bc-9afa-1775287b32c0','inference',$$Lozan Antlaşması''nın (1923) önemi hakkında ne çıkarılabilir?$$,'["Lozan yalnızca sınırların çizilmesini kapsayan teknik bir belgedir.","Lozan; Türkiye''nin tam egemenliğini uluslararası alanda tanıtan belge olarak Sevr''i geçersiz kılmış ve modern Türk devletinin uluslararası statüsünü tescil etmiştir.","Lozan, Kurtuluş Savaşı kazanımlarını fiilen geri almıştır.","Antlaşma koşulları Türkiye tarafından tartışmalı bulunmaktadır."]'::jsonb, 1, $$Lozan; millî egemenliği uluslararası düzeyde tasdik etmesi ve Türkiye''nin modern devlet olarak tanınmasını sağlaması açısından temel bir dönüm noktası niteliği taşımaktadır.$$, 2, 3),
('1aa9d2de-69d6-43bc-9afa-1775287b32c0','vocabulary',$$Metinde geçen "nüfus mübadelesi" kavramı ne anlama gelir?$$,'["Gönüllü göçmen yerleşim programı","Lozan çerçevesinde Türk ve Yunan toplulukların zorla karşılıklı yer değiştirmesi; din temel takas ölçütü olarak belirlendi","Barış koşullarının müzakere edildiği diplomatik konferans","Farklı bölgeler arasında askeri birlik nakli"]'::jsonb, 1, $$1923 nüfus mübadelesi; kalıcı bir demografik değişime yol açmış ve ulus-devlet inşası sürecinde dini kimliği etnik-millî kimliğin belirleyici ölçütü haline getirmiştir.$$, 2, 4),
('1aa9d2de-69d6-43bc-9afa-1775287b32c0','detail',$$Millî Mücadele döneminde halkın direniş hareketine katılımı nasıl sağlandı?$$,'["Halk savaşa zorla katılmak durumunda kaldı.","Tüm katmanlardan gönüllülerin desteğiyle kurulan Millî Kuvvetler ve Müdafaa-i Hukuk cemiyetleri, halk temelli bir örgütlenme zemini oluşturdu.","Direniş yalnızca İstanbul aydınlarının girişimiyle başladı.","Yabancı güçler Türk direnişini fiilen destekledi."]'::jsonb, 1, $$Geniş bir toplumsal tabana dayanan Millî Kuvvetler ve örgütsel yapısıyla TBMM; direniş hareketini halk kitlelerine yayarak kalıcı bir güç merkezi oluşturdu.$$, 2, 5);
INSERT INTO text_questions (text_id, question_type, question_text, options, correct_index, explanation, difficulty, order_index) VALUES
('48851544-9cd8-43a9-8a37-fd7b361e06e6','main_idea',$$Bu metnin ana fikri nedir?$$,'["Osmanlı İmparatorluğu''nda yalnızca İslam dinine mensup nüfus haklar bakımından tanınmıştır.","Millet sistemi; farklı din ve milletlerden oluşan toplulukların din ekseninde örgütlenmesini ve öz yönetim haklarına kavuşmasını sağlayan, Osmanlı''nın çoğulcu yönetim anlayışının kurumsal ifadesiydi.","Osmanlı''nın dinî azınlıklara hiçbir özerklik tanımadığı bilinmektedir.","Millet sistemi yalnızca gayrimüslim toplulukları kapsıyordu."]'::jsonb, 1, $$Metin; millet sistemini Osmanlı''nın dinî çeşitliliği yönetme biçimi olarak ele almakta ve bu sistemin siyasi boyutlarını irdelemektedir.$$, 3, 1),
('48851544-9cd8-43a9-8a37-fd7b361e06e6','detail',$$Gayrimüslim milletler millet sistemi çerçevesinde hangi alanlarda özerklik kazandı?$$,'["Yalnızca serbest dini ayin hakkı","Dini kurumlar, eğitim, aile hukuku ve cemaat içi uyuşmazlıkların çözümünde kapsamlı iç özerklik","Osmanlı yönetiminden tam bağımsızlık","Osmanlı Devleti''nde her kademede kamu hizmeti hakkı"]'::jsonb, 1, $$Milletler; cemaat kurumlarını, mahkemelerini ve okullarını bağımsız biçimde yönetme hakkına sahip olup Osmanlı üst egemenliği çerçevesinde geniş bir iç özerklik alanından yararlandı.$$, 3, 2),
('48851544-9cd8-43a9-8a37-fd7b361e06e6','inference',$$Millet sisteminin güçlü ve zayıf yönleri hakkında ne söylenebilir?$$,'["Sistem mükemmeldi ve herhangi bir toplumsal gerilim doğurmadı.","Çoğulculuğu kurumsal düzeyde korurken cemaatler arası ayrışmayı da pekiştirdi; bu durum sonraki dönemlerde milliyetçi çatışmaların zeminini hazırladı.","Millet sistemi bütünleşik bir Osmanlı ulusal kimliğinin ortaya çıkmasını kolaylaştırdı.","Sistem, tüm Osmanlı vatandaşlarına eşit haklar tanıdı."]'::jsonb, 1, $$Millet sistemi; dinî hoşgörü sağlarken farklı toplulukları birbirinden ayırarak ortak bir Osmanlı kimliği yerine cemaat temelli sadakatlerin pekişmesine zemin hazırladı.$$, 3, 3),
('48851544-9cd8-43a9-8a37-fd7b361e06e6','vocabulary',$$Metinde "zimmi" statüsü nasıl tanımlanmaktadır?$$,'["Osmanlı İmparatorluğu''nda Müslüman olmayan zanaatkar","İslam hukukuna göre cizye vergisi ödeyerek koruma ve sınırlı özerklik hakkı kazanan Ehl-i kitap (Hristiyan ve Yahudi) statüsü","Osmanlı ordusunda görev yapan gayrimüslim asker","Gayrimüslimlere yönelik vergi muafiyeti"]'::jsonb, 1, $$Zimmi statüsü; Müslüman yönetimi altında yaşayan gayrimüslimlerin haklarını ve yükümlülüklerini belirleyen İslam hukuku çerçevesini ifade etmektedir.$$, 3, 4),
('48851544-9cd8-43a9-8a37-fd7b361e06e6','detail',$$Tanzimat reformlarının millet sistemini dönüştürmesi nasıl gerçekleşti?$$,'["Tanzimat reformları millet sistemini tamamen kaldırdı.","1839 ve 1856 fermanları; tüm Osmanlı vatandaşlarına eşit haklar tanımayı hedefleyerek geleneksel millet örgütlenmesini aşındırdı.","Tanzimat reformları gayrimüslim haklarını daha da kısıtladı.","Reformlar yalnızca Müslüman milletleri etkiledi."]'::jsonb, 1, $$Islahat Fermanı (1856); yasal eşitliği anayasal güvenceye bağlayarak millet sisteminin ayrımcı çerçevesini kademeli olarak dönüştürmüştür.$$, 3, 5);
INSERT INTO text_questions (text_id, question_type, question_text, options, correct_index, explanation, difficulty, order_index) VALUES
('eb9646ac-2770-4a52-bfec-bcbbd09a6c1a','main_idea',$$Bu metnin ana fikri nedir?$$,'["Atatürk''ün eğitim politikaları yalnızca okuma-yazma kampanyasıyla sınırlıdır.","Atatürk''ün eğitim reformları; laik, ulusal ve evrensel bilimsel ilkelere dayanan bir eğitim sistemi kurarak modern Türkiye''nin insan kaynağı temelini oluşturmuştur.","Eğitim reformları önceki düzenle kesintisiz bir süreklilik içinde gerçekleşmiştir.","Üniversite reformu ilk öğretim alanındaki değişimlerden önce tamamlandı."]'::jsonb, 1, $$Metin; Atatürk''ün eğitim alanındaki kapsamlı reformlarını modern Türkiye''nin kuruluş projesinin temel bileşeni olarak ele almaktadır.$$, 2, 1),
('eb9646ac-2770-4a52-bfec-bcbbd09a6c1a','detail',$$1928''de yeni Türk alfabesine geçilmesinin eğitime katkısı ne oldu?$$,'["Latin harfleri Türkçe için uygunsuzdu.","Latin alfabesinin benimsenmesi okuma yazmayı basitleştirdi; köklü bir okuryazarlık kampanyasının önünü açtı ve eğitime erişimi demokratikleştirdi.","Alfabe değişikliği Osmanlı eserlerinin okunmasını kolaylaştırdı.","Yeni alfabe başlangıçta geniş halk kitleleri tarafından reddedildi."]'::jsonb, 1, $$Latin alfabesine geçiş, fonetik açıdan Osmanlı Türkçesinin karmaşık imlasına kıyasla çok daha öğrenilebilir bir sistem sunarak okuryazarlık oranlarında hızlı bir artışı mümkün kıldı.$$, 2, 2),
('eb9646ac-2770-4a52-bfec-bcbbd09a6c1a','inference',$$Tevhid-i Tedrisat Kanunu (1924) ile eğitim birleştirilmesinin önemi hakkında ne çıkarılabilir?$$,'["Yalnızca müfredat standardizasyonunu kapsıyordu.","Dini kurumların eğitim üzerindeki nüfuzunu kırarak laik, devlet denetimli bir okul düzenini kurdu ve cumhuriyetin ulusal kimlik inşası projesini doğrudan destekledi.","Kanun yalnızca yükseköğretim kurumlarına uygulandı.","Dini okullar devlet denetiminden muaf tutulmaya devam etti."]'::jsonb, 1, $$Tevhid-i Tedrisat; dini ve laik eğitim sistemlerini tek çatı altında birleştirerek Osmanlı''nın çift başlı eğitim yapısına son verdi.$$, 2, 3),
('eb9646ac-2770-4a52-bfec-bcbbd09a6c1a','vocabulary',$$Metinde geçen "Halk Evleri" ne anlama gelir?$$,'["Cumhurbaşkanlığına bağlı resmî devlet kurumları","Cumhuriyet değerlerini, kültürel modernleşmeyi ve eğitimi kentsel ve kırsal alanlara yaymayı amaçlayan toplum eğitim merkezleri","Yalnızca okuma-yazma kurslarının düzenlendiği tesisler","Atatürk dönemi fabrika ve üretim tesisleri"]'::jsonb, 1, $$Halk Evleri; 1932''de kurulan ve Cumhuriyet''in modernleşme projesini geniş halk kesimlerine ulaştırmak amacıyla eğitim, kültür ve sanat faaliyetleri yürüten toplum merkezleriydi.$$, 2, 4),
('eb9646ac-2770-4a52-bfec-bcbbd09a6c1a','detail',$$Atatürk döneminde kız çocuklarının eğitimine yönelik atılan adımlar nelerdir?$$,'["Kız eğitimi yalnızca ev idaresiyle sınırlı tutuldu.","Yeni okullar hem kız hem erkek öğrencilere açık olacak biçimde düzenlendi; kadınların yükseköğretime ve mesleki hayata katılımı için kapılar aralandı.","Kız okulları ayrı binalar halinde örgütlendi, öğrencilere farklı müfredat uygulandı.","Kızların eğitim haklarını düzenleyen reformlar çok geç hayata geçirildi."]'::jsonb, 1, $$Cumhuriyet reformları; karma eğitimi ve kadınlara yönelik mesleki eğitim imkânlarını yaygınlaştırarak kadının toplumsal ve ekonomik yaşama entegrasyonunu hızlandırdı.$$, 2, 5);
INSERT INTO text_questions (text_id, question_type, question_text, options, correct_index, explanation, difficulty, order_index) VALUES
('cea62c16-9211-4225-ba08-0887dbf0cc62','main_idea',$$Bu metnin ana fikri nedir?$$,'["Kuantum fiziği yalnızca parçacık hızlandırıcılarında uygulanmaktadır.","Kuantum fiziği; atom altı dünyanın sezgiyi aşan davranışlarını açıklayan ve modern teknolojiyi temelden şekillendiren bir bilim dalıdır.","Kuantum mekaniği günlük yaşamla hiçbir ilgisi olmayan soyut bir teoridir.","Işık yalnızca dalga özelliği sergileyen bir enerji biçimidir."]'::jsonb, 1, $$Metin; kuantum fiziğini karşı sezgisel ama teknoloji için temel bir alan olarak konumlandırmaktadır.$$, 3, 1),
('cea62c16-9211-4225-ba08-0887dbf0cc62','detail',$$Dalga-parçacık ikiliği ne anlama gelmektedir?$$,'["Parçacıklar yalnızca katı maddelerden oluşmaktadır.","Elektron ve foton gibi varlıklar hem dalga hem parçacık özellikleri sergiler; hangi özelliğin ön plana çıkacağı nasıl ölçüldüklerine bağlıdır.","Dalgalar her zaman parçacık yoğunluklarından oluşur.","Kuantum nesneleri ya tamamen dalga ya da tamamen parçacıktır."]'::jsonb, 1, $$Dalga-parçacık ikiliği; parçacıkların ölçüm bağlamına göre hem dalga hem de parçacık özelliği sergileyebildiğini gösteren kuantum mekaniğinin temel olgusudur.$$, 3, 2),
('cea62c16-9211-4225-ba08-0887dbf0cc62','inference',$$Kuantum tünellemenin günlük hayat uygulamaları hakkında ne çıkarılabilir?$$,'["Kuantum tünelleme yalnızca teorik öneme sahip olup pratik bir uygulama alanı bulamamıştır.","Kuantum etkileri; tünel diyotlar, USB bellekler ve nükleer füzyon gibi teknolojileri mümkün kılan güçlü bir gerçekliktir.","Kuantum etkiler yalnızca çok düşük sıcaklıklarda ortaya çıkmaktadır.","Kuantum tünelleme yalnızca süperiletken malzemelerde gözlemlenmektedir."]'::jsonb, 1, $$Kuantum tünelleme; klasik fiziğin geçilmez saydığı enerji bariyerlerinin aşılmasını sağlayarak elektronik ve enerji alanında pek çok teknolojiyi hayata geçirmektedir.$$, 3, 3),
('cea62c16-9211-4225-ba08-0887dbf0cc62','vocabulary',$$Metinde geçen "kuantum dolanıklığı" kavramı nasıl açıklanmaktadır?$$,'["Parçacıkların birbirlerine fiziksel olarak bağlanması","İki parçacığın birbirinden ne kadar uzak olursa olsun korelasyonlu kalması; birine yapılan ölçümün diğerinin durumunu anında belirlemesi","Kuantum sistemi içindeki parçacık çarpışmaları","Işınlama sürecindeki madde-antimadde etkileşimi"]'::jsonb, 1, $$Dolanıklık; iki parçacık arasındaki korelasyonun mesafeden bağımsız sürdüğü, Einstein''ın ''uzaktan ürkütücü etki'' dediği kuantum fenomenidir.$$, 3, 4),
('cea62c16-9211-4225-ba08-0887dbf0cc62','detail',$$Metne göre kuantum bilgisayarların önemi nedir?$$,'["Kuantum bilgisayarlar mevcut bilgisayarların yalnızca daha büyük versiyonlarıdır.","Kuantum bilgisayarlar, süperpozisyon ve dolanıklık ilkelerinden yararlanarak bazı problem türlerini klasik bilgisayarların ulaşamayacağı bir hızla çözebilmektedir.","Kuantum bilgisayarlar henüz laboratuvar ortamının ötesinde bir uygulamaya geçilememiştir.","Kuantum bilgisayarlar tüm problemlerde klasik bilgisayarlardan üstündür."]'::jsonb, 1, $$Kuantum bilgisayarlar, kuantum mekanik fenomenlerinden yararlanarak kriptografi ve ilaç keşfi gibi seçili alanlarda devrimsel bir hesaplama gücü sunmaktadır.$$, 3, 5);
INSERT INTO text_questions (text_id, question_type, question_text, options, correct_index, explanation, difficulty, order_index) VALUES
('c8bf402a-6b94-441a-be87-ecd13e10eff3','main_idea',$$Bu metnin ana fikri nedir?$$,'["Yenilenebilir enerji fosil yakıtların tamamını hemen ikame edebilir.","Yenilenebilir enerji kaynakları; sürdürülebilir bir geleceğe geçiş için çevresel ve ekonomik açıdan kritik bir öneme sahip olmakla birlikte, ölçeklendirme ve depolama konusundaki güçlükleri aşmayı gerektirmektedir.","Güneş enerjisi tek gerçekçi alternatif enerji seçeneğidir.","Yenilenebilir enerji sistemleri küresel ölçekte uygulamaya tamamen hazırdır."]'::jsonb, 1, $$Metin; yenilenebilir enerjinin potansiyelini gerçekçi biçimde ortaya koymakta, karşılaşılan güçlükleri göz ardı etmeden sürdürülebilir bir geçişin gerekliliğini vurgulamaktadır.$$, 2, 1),
('c8bf402a-6b94-441a-be87-ecd13e10eff3','detail',$$Güneş ve rüzgar enerjisinin başlıca dezavantajı nedir?$$,'["Kurulum maliyetleri fosil yakıtlardan yüksektir.","Kesintisiz talebe yanıt verebilmek için gelişmiş enerji depolama çözümlerine ihtiyaç duyan üretim süreksizliği","Güneş enerjisi yalnızca ılıman iklimlerde kullanılabilir.","Rüzgar türbinleri kuruldukları bölgelere ciddi zararlar vermektedir."]'::jsonb, 1, $$Güneş ve rüzgar enerjisinde üretim; güneş ışığı ve rüzgar koşullarına bağlı olarak dalgalandığından, bu kaynaklardan elde edilen elektriğin güvenilir ızgara sistemlerine entegre edilebilmesi için etkili depolama ve şebeke çözümleri zorunludur.$$, 2, 2),
('c8bf402a-6b94-441a-be87-ecd13e10eff3','inference',$$Yeşil enerji dönüşümünün ekonomik boyutu hakkında ne çıkarılabilir?$$,'["Yenilenebilir enerjiye geçiş her zaman ekonomik açıdan dezavantajlıdır.","Uzun vadeli yakıt tasarrufu ve istihdam yaratımı, başlangıç altyapı maliyetlerini aşabileceğinden yeşil enerji hem çevreci hem ekonomik bir seçenek sunmaktadır.","Yenilenebilir enerjinin maliyetleri hiçbir zaman rekabetçi hale gelemez.","Enerji dönüşümünün tüm ekonomik sonuçları öngörülemeyen riskler içermektedir."]'::jsonb, 1, $$Yenilenebilir enerji maliyetlerinin hızla düşmesi ve yeşil sektörde açılan yeni iş alanları, çevresel kazanımların ekonomik getirileri olduğu güçlü bir argümanı desteklemektedir.$$, 2, 3),
('c8bf402a-6b94-441a-be87-ecd13e10eff3','vocabulary',$$Metinde geçen "karbon nötr" kavramı ne anlama gelmektedir?$$,'["Karbon emisyonlarının tümden ortadan kaldırılması","Havaya salınan karbonun karbon yutak veya ofset programları aracılığıyla telafi edilmesi; net karbon emisyonunun sıfırlanması","Süreçlerin yalnızca karbonsuz yakıt kullanması","Sera gazı emisyonlarının %50 oranında azaltılması"]'::jsonb, 1, $$Karbon nötr; havaya salınan CO₂ miktarı ile ormancılık, karbon yakalama veya ofset projeleri aracılığıyla uzaklaştırılan CO₂ miktarı arasında denge kurulmasını ifade etmektedir.$$, 2, 4),
('c8bf402a-6b94-441a-be87-ecd13e10eff3','detail',$$Enerji depolama kapasitesinin artırılması neden önem taşımaktadır?$$,'["Büyük güç santrallerinin inşasını ortadan kaldırmak için","Kesintisiz olmayan güneş ve rüzgar enerjisinin talebe tam yanıt verebilmesi için yeterli miktarda depolanmasına olanak tanıması","Fosil yakıt altyapısını daha ekonomik hale getirmek için","Nükleer enerji santrallerinin daha verimli çalışmasını desteklemek için"]'::jsonb, 1, $$Batarya ve diğer depolama teknolojileri; yenilenebilir kaynakların güvenilmez enerji üreticisi olmaktan çıkıp sürekli ve kararlı enerji sağlayıcılarına dönüşmesini mümkün kılmaktadır.$$, 2, 5);
INSERT INTO text_questions (text_id, question_type, question_text, options, correct_index, explanation, difficulty, order_index) VALUES
('d7f12f0b-a879-4e5e-b268-3460567dd5b9','main_idea',$$Bu metnin ana fikri nedir?$$,'["Diller tarihsel süreçte hiç değişmemiştir.","Dil; insan topluluklarının değişen ihtiyaçlarını ve toplumsal etkileşimini yansıtacak biçimde sürekli evrilen, canlı bir iletişim sistemidir.","Tüm diller kaçınılmaz olarak yok olma sürecindedir.","Teknoloji dili tamamen gereksiz kılmaktadır."]'::jsonb, 1, $$Metin; dili sosyal ve bilişsel dinamiklere yanıt olarak sürekli değişen, canlı ve dinamik bir sistem olarak ele almaktadır.$$, 3, 1),
('d7f12f0b-a879-4e5e-b268-3460567dd5b9','detail',$$Dijital iletişimin dile etkisi nasıl açıklanmaktadır?$$,'["Dijital iletişim dili bozarak standartları düşürmüştür.","Sosyal medya, mesajlaşma uygulamaları ve çevrimiçi topluluklar; yeni kelimeler, kısaltmalar ve iletişim normları yaratarak dili hızla zenginleştirmektedir.","Teknoloji insan dilini yapay zeka dilleriyle ikame etmiştir.","Yazılı dil dijital çağda hiçbir değişime uğramamıştır."]'::jsonb, 1, $$Dijital platformlar; dil evrimini tarihin hiçbir döneminde görülmemiş bir hızda kitlesel olarak beslemekte ve yeni sözcük dağarcığı ile söylem biçimleri ortaya çıkarmaktadır.$$, 3, 2),
('d7f12f0b-a879-4e5e-b268-3460567dd5b9','inference',$$Dil çeşitliliğinin azalması hakkında ne söylenebilir?$$,'["Dil çeşitliliğinin azalması kültürel ilerlemenin doğal bir sonucudur.","Her dil kaybı; o toplumun kendine özgü bilgi sistemlerini, kültürel mirasını ve bilişsel çerçevelerini geri dönüşü olmayan biçimde yok eder.","Baskın dillere geçiş iletişimi her zaman iyileştirir.","Dil koruması sınırlı kaynak havuzlarının gereksiz yere bölünmesidir."]'::jsonb, 1, $$Diller; geleneksel bilgiyi ve dünyayı yorumlama biçimlerini taşır; bu nedenle bir dilin yok olması tam anlamıyla telafi edilemez bir kültürel kayıptır.$$, 3, 3),
('d7f12f0b-a879-4e5e-b268-3460567dd5b9','vocabulary',$$Metinde geçen "pidgin dil" kavramı ne anlama gelir?$$,'["Belirli bir toplulukta anadil olarak konuşulan dil","Ortak bir anadilleri olmayan grupların iletişim kurmak için geliştirdiği basitleştirilmiş karma dil","Ölmüş ya da yoğun biçimde belgelenen tarihi dil","Aynı dil ailesinden türemiş iki dilin ortak atası"]'::jsonb, 1, $$Pidgin diller; aralarında ortak dil bulunmayan topluluklar arasında genellikle ticaret ya da kolonyal temas yoluyla ortaya çıkan işlevsel iletişim araçlarıdır.$$, 3, 4),
('d7f12f0b-a879-4e5e-b268-3460567dd5b9','detail',$$Dil değişimi için hangi başlıca mekanizmalar sayılmaktadır?$$,'["Dil değişimi yalnızca yazılı edebiyat aracılığıyla gerçekleşir.","Nesiller arası geçiş, topluluklar arası temas, teknolojik gelişme ve sosyal statü dinamikleri; dil evriminin başlıca itici güçleridir.","Dilsel değişim yalnızca resmi akademik kurumlar tarafından yönetilmektedir.","Dil değişimi tahmin edilemez ve rastlantısal bir süreçtir."]'::jsonb, 1, $$Dil değişimi; göç, ticaret, teknoloji ve sosyal dinamikler gibi birden fazla birbirine bağlı etkenin karmaşık etkileşiminden kaynaklanmaktadır.$$, 3, 5);
INSERT INTO text_questions (text_id, question_type, question_text, options, correct_index, explanation, difficulty, order_index) VALUES
('0088f29c-db6b-40f6-beaa-e3f25211c8fc','main_idea',$$Bu metnin ana fikri nedir?$$,'["Okyanuslar yalnızca balıkçılık açısından önem taşımaktadır.","Okyanuslar; Dünya''nın iklimini düzenleyen, eşi görülmemiş bir biyoçeşitliliğe ev sahipliği yapan ve hâlâ büyük ölçüde keşfedilmemiş gizemler barındıran hayati ekosistemlerdir.","Derin deniz yaşamı yüzey ekosistemiyle bağlantısızdır.","Okyanus kirliliği yalnızca kıyı bölgelerini etkilemektedir."]'::jsonb, 1, $$Metin; okyanusları hem büyük bir biyolojik zenginlik hem de küresel iklim dengesi için vazgeçilmez bir kaynak olarak ele almaktadır.$$, 2, 1),
('0088f29c-db6b-40f6-beaa-e3f25211c8fc','detail',$$Okyanuslar iklim düzenlemesinde nasıl bir işlev üstlenmektedir?$$,'["Okyanusların iklim üzerinde herhangi bir etkisi yoktur.","Okyanuslar; ısıyı ve karbondioksiti büyük miktarda depolayarak küresel sıcaklıkları dengelemeye ve iklim değişikliğinin etkilerini hafifletmeye katkı sağlar.","Okyanuslar atmosferden yalnızca oksijeni absorplar.","Okyanus akıntıları iklim değişkenliğiyle ilgisizdir."]'::jsonb, 1, $$Okyanus; güneş ısısını ve atmosferik CO₂''yi büyük miktarlarda depolayarak hayati bir iklim düzenleyici ve tampon işlevi görür.$$, 2, 2),
('0088f29c-db6b-40f6-beaa-e3f25211c8fc','inference',$$Derin deniz araştırmalarındaki ilerleme hakkında ne söylenebilir?$$,'["Derin denizler artık tam olarak haritalanmıştır.","Teknolojik gelişmelerle açığa çıkan yeni derin deniz türleri; okyanusların hâlâ keşfedilmemiş potansiyelini ve kapsamlı araştırmalara duyulan acil ihtiyacı gözler önüne sermektedir.","Derin deniz araştırmaları bilimsel açıdan anlamsızdır.","Bilinen tüm derin deniz yaşam formları kapsamlı biçimde belgelenmiştir."]'::jsonb, 1, $$Yenilikçi sualtı teknolojileri; sürekli yeni türler ve ekosistemlerin keşfedilmesiyle okyanusların ne denli az anlaşıldığını ortaya koymaktadır.$$, 2, 3),
('0088f29c-db6b-40f6-beaa-e3f25211c8fc','vocabulary',$$Metinde geçen "termal tabakalaşma" kavramı ne anlama gelir?$$,'["Okyanus tabanındaki termal bacalar","Okyanusun sıcaklığa bağlı farklı yoğunluktaki su kütlelerinin oluşturduğu katmanlı yapısı; su karışımını ve besin döngüsünü düzenlemektedir","Termal enerjinin okyanusta depolanma mekanizması","Okyanus yüzeyindeki güneş ışığının okyanus tabanına sızma süreci"]'::jsonb, 1, $$Termal tabakalaşma; okyanusun dikey yapısını belirler, su karışımını etkiler ve besin döngüleri ile deniz ekosistemlerinin işleyişini doğrudan düzenler.$$, 2, 4),
('0088f29c-db6b-40f6-beaa-e3f25211c8fc','detail',$$Mercan resiflerinin önemi ve karşılaştığı tehdit nedir?$$,'["Mercan resifleri aşırı biyoçeşitliliği nedeniyle ekosisteme zarar vermektedir.","Mercan resifleri orantısız bir biyoçeşitliliği barındırmakta; ancak ısınan ve asitleşen denizler nedeniyle ağırlaşan mercan ağarması tehdidiyle karşı karşıya kalmaktadır.","Mercan resifleri derin deniz ortamlarında bulunmaktadır.","Asit yağmurları mercan resifleri için başlıca tehdidi oluşturmaktadır."]'::jsonb, 1, $$Mercan resifleri; yüzeyin yalnızca küçük bir kısmını kaplasa da deniz biyoçeşitliliğinin büyük bir bölümüne ev sahipliği yaparak hem ekosistem hem insanlık açısından kritik bir değer taşımaktadır.$$, 2, 5);
INSERT INTO text_questions (text_id, question_type, question_text, options, correct_index, explanation, difficulty, order_index) VALUES
('84fafbb1-12c1-43a1-8b90-3d0c9bf5e97a','main_idea',$$Bu metnin ana fikri nedir?$$,'["Müzik yalnızca estetik bir zevk kaynağıdır.","Müzik; duygu, biliş ve sosyal bağlar üzerinde ölçülebilir etkiler bırakarak refahı ve bilişsel işlevleri güçlendiren güçlü bir psikolojik araçtır.","Müzik terapisi yalnızca belirli zihinsel hastalıklarda uygulanmaktadır.","Müziğin psikolojik etkileri bireyler arasında büyük farklılık göstermektedir."]'::jsonb, 1, $$Metin; müziği duygu, biliş ve sağlık üzerinde somut etkileri olan psikolojik bir araç olarak konumlandırmaktadır.$$, 2, 1),
('84fafbb1-12c1-43a1-8b90-3d0c9bf5e97a','detail',$$Müziğin ruh hali üzerindeki etkisi nörobilim açısından nasıl açıklanmaktadır?$$,'["Müzik yalnızca kişisel anıları tetiklemektedir.","Müzik; dopamin salgılanmasını uyararak ödül merkezlerini harekete geçirir, kortizol düzeylerini düşürür ve kaygıyı azaltır.","Müzik yalnızca hızlı tempolu parçalar için stres azaltıcı etki taşımaktadır.","Müzik, beyin dopamin sistemleriyle etkileşime girmez."]'::jsonb, 1, $$Araştırmalar; müziğin ödül, motivasyon ve duygu düzenlemesiyle ilişkili beyin bölgelerini etkin biçimde devreye soktuğunu tutarlı biçimde ortaya koymaktadır.$$, 2, 2),
('84fafbb1-12c1-43a1-8b90-3d0c9bf5e97a','inference',$$Müzik terapisinin tıbbi ortamlarda kullanılması hakkında ne söylenebilir?$$,'["Müzik terapisinin klinik kanıtı bulunmamaktadır.","Müziğin psikolojik ve nörolojik etkilerinin belgelenmesi, onun acı yönetimi, kaygı azaltımı ve bilişsel rehabilitasyon alanlarında tamamlayıcı bir tedavi olarak kabul görmesinin zeminini hazırlamıştır.","Müzik terapisi yalnızca eğlence amaçlı uygulanmaktadır.","Müzik terapisi geleneksel tedavi yöntemlerini büyük ölçüde geride bırakmıştır."]'::jsonb, 1, $$Müziğin psikolojik mekanizmalarının bilimsel olarak aydınlatılması; onu klinik ortamlarda kanıta dayalı tamamlayıcı bir tedavi seçeneği konumuna yükseltmiştir.$$, 2, 3),
('84fafbb1-12c1-43a1-8b90-3d0c9bf5e97a','vocabulary',$$Metinde geçen "bilişsel rezerv" kavramı müzik bağlamında ne anlama gelir?$$,'["Müzik okuryazarlığı ve nota bilgisi","Müzik eğitiminin bilişsel esnekliğe katkıda bulunduğu ve beyin sağlığının korunmasına yardımcı olduğu kapasite","Bir parçanın hafızada tutulabilme miktarı","Müzisyenlerin sıradan insanlara kıyasla işletebildiği beyin bölümlerinin sayısı"]'::jsonb, 1, $$Bilişsel rezerv; bilişsel gerilemeye karşı koruyucu bir etki üstlenen zihinsel kapasiteyi ifade eder. Müzik eğitiminin bu rezervi artırdığına ilişkin bulgular giderek güçlenmektedir.$$, 2, 4),
('84fafbb1-12c1-43a1-8b90-3d0c9bf5e97a','detail',$$Müziğin sosyal bağ üzerindeki etkisi nasıl açıklanmaktadır?$$,'["Müzik sosyal izolasyonu artırmaktadır.","Birlikte müzik yapma, ritme eşzamanlı tepki verme ve ortak müzik deneyimleri; sosyal uyum ve aidiyet duygusunu güçlerir.","Müziğin sosyal boyutu yalnızca kültürel ritüellerde belirginleşmektedir.","Sosyal bağ yalnızca sözlü iletişim yoluyla kurulabilmektedir."]'::jsonb, 1, $$Senkronize müzik deneyimleri; sosyal bağlılığı ölçülebilir biçimde artıran biyolojik ve psikolojik mekanizmaları harekete geçirir.$$, 2, 5);
INSERT INTO text_questions (text_id, question_type, question_text, options, correct_index, explanation, difficulty, order_index) VALUES
('2c9dc640-44e4-473a-9698-fbcaf8f13c40','main_idea',$$Bu metnin ana fikri nedir?$$,'["Türk mutfağı yalnızca kebaptan ibarettir.","Türk mutfağı; Orta Asya, Orta Doğu ve Akdeniz geleneklerinin buluşmasından doğan zengin bir gastronomik mirastır ve tarihsel derinliği ile coğrafi çeşitliliği yansıtmaktadır.","Osmanlı mutfağı modern Türk yemek kültürünü hiç etkilememiştir.","Bölgesel farklılıklar Türk mutfağını zayıf kılmaktadır."]'::jsonb, 1, $$Metin; Türk mutfağını kültürel sentez ve tarihsel birikim açısından ele almaktadır.$$, 1, 1),
('2c9dc640-44e4-473a-9698-fbcaf8f13c40','detail',$$Osmanlı saray mutfağının Türk mutfak geleneğine katkısı nedir?$$,'["Osmanlı mutfağı yalnızca tatlı yemekleri kapsıyordu.","Saray mutfağı; sofistike pişirme teknikleri, baharatlı-aromatik profiller ve sofra adabını geliştirerek zamanla ulusal mutfak kültürünü derinden etkiledi.","Osmanlı mutfağı ilerleyen süreçte Türk yemek geleneğiyle hiçbir ortak nokta barındırmayan bağımsız bir ekole dönüştü.","Saray mutfağı halkın günlük yemek tercihlerini yansıtıyordu."]'::jsonb, 1, $$Osmanlı saray mutfağı; çeşitli kültürlerden aldığı etkileri harmanlayarak büyük ölçüde bölgesel mutfak gelenekleriyle şekillenen ve sonraki kuşaklara miras bırakılan ulusal bir yemek kültürü oluşturdu.$$, 1, 2),
('2c9dc640-44e4-473a-9698-fbcaf8f13c40','inference',$$Türkiye''nin farklı bölgelerinin kendine özgü yemek geleneklerine sahip olması hakkında ne çıkarılabilir?$$,'["Bölgesel farklılıklar ortak bir ulusal mutfağın varlığını ortadan kaldırmaktadır.","Coğrafya, iklim ve tarihsel temas; bütünlük içinde gerçek bir çeşitliliği barındıran bölgesel lezzetlerin doğmasına zemin hazırlamıştır.","Türk yemekleri bölgeden bölgeye ufak farklılıklar dışında büyük ölçüde birbirine benzemektedir.","Bölgesel mutfak farklılıkları yakın dönemde yabancı etkilerle ortaya çıkmıştır."]'::jsonb, 1, $$Karadeniz''in hamsi yemeğinden Güneydoğu''nun baharatlı kebaplarına uzanan çeşitlilik; yerel malzemelerin ve tarihin belirleyici etkisini somutlaştırmaktadır.$$, 1, 3),
('2c9dc640-44e4-473a-9698-fbcaf8f13c40','vocabulary',$$Metinde geçen "fermente" kavramı gıda bağlamında ne anlama gelir?$$,'["Geleneksel pişirme yöntemleriyle hazırlama","Mikroorganizmalar aracılığıyla gıdanın biyokimyasal dönüşüme uğraması; yoğurt ve turşu bu sürecin tipik örnekleridir","Gıdaların geleneksel fırın yöntemleriyle pişirilmesi","Gıda ürünlerini koruyucu katkı maddeleri eklenerek işlenmesi"]'::jsonb, 1, $$Fermentasyon; bakteri ve mayalar aracılığıyla gerçekleşen ve gıdanın tat, doku ve besin değerini dönüştüren biyokimyasal bir süreçtir; Türk yoğurdu bu sürecin simgesidir.$$, 1, 4),
('2c9dc640-44e4-473a-9698-fbcaf8f13c40','detail',$$Baharat, kuruyemiş ve kuru meyveler Türk mutfağında nasıl bir rol üstlenmektedir?$$,'["Bu malzemeler yalnızca tatlı tariflerde yer almaktadır.","Aromatik derinlik, doku çeşitliliği ve sağlıklı beslenme anlayışıyla Orta Asya ve Orta Doğu geleneklerini yansıtan bu malzemeler, hem tatlı hem tuzlu yemeklerde geniş biçimde kullanılmaktadır.","Baharatlar yalnızca Güneydoğu Anadolu mutfağıyla özdeşleşmektedir.","Bu malzemeler yalnızca bayramlarda ve özel günlerde sofralara girmektedir."]'::jsonb, 1, $$Baharat ve kuruyemiş kullanımı; Orta Asya göçebe geleneği ile İpek Yolu ticaret mirasını bugünkü Türk mutfağına taşıyan görünür bir köprü işlevi görmektedir.$$, 1, 5);
INSERT INTO text_questions (text_id, question_type, question_text, options, correct_index, explanation, difficulty, order_index) VALUES
('d2451a9b-36b2-47c3-bfca-f78307aae039','main_idea',$$Bu metnin ana fikri nedir?$$,'["Meditasyonun faydaları yalnızca dini bir deneyim olarak hissedilebilir.","Meditasyon; stres azaltma, dikkat güçlendirme ve nörolojik değişimler gibi belgelenmiş bilimsel kanıtlarla desteklenen somut zihinsel ve bedensel faydalar sunmaktadır.","Meditasyonun etkileri yalnızca uzun süreli uygulamacılarda gözlemlenmektedir.","Meditasyon; diğer stres yönetimi tekniklerine kıyasla herhangi bir üstünlük taşımamaktadır."]'::jsonb, 1, $$Metin; meditasyonu yalnızca spiritüel bir pratik olarak değil, kanıta dayalı bilimsel faydalar sunan bir zihinsel eğitim aracı olarak konumlandırmaktadır.$$, 2, 1),
('d2451a9b-36b2-47c3-bfca-f78307aae039','detail',$$Meditasyonun strese fizyolojik etkisi nasıl açıklanmaktadır?$$,'["Meditasyon kalp atış hızını artırmaktadır.","Meditasyon kortizol düzeylerini düşürür, parasempatik sinir sistemini etkinleştirir ve stres kaynaklı fizyolojik tepkileri azaltır.","Meditasyonun stres hormonları üzerinde herhangi bir etkisi kanıtlanamamıştır.","Meditasyon yalnızca algılanan stresi azaltır; fizyolojik değişiklikler gözlemlenmez."]'::jsonb, 1, $$Araştırmalar; meditasyonun kortizol gibi stres belirteçlerini ölçülebilir biçimde düşürdüğünü ve vücudun fizyolojik stres yanıtını hafiflettiğini ortaya koymaktadır.$$, 2, 2),
('d2451a9b-36b2-47c3-bfca-f78307aae039','inference',$$Uzun süreli meditasyon pratiğinin beyin yapısında değişikliklere yol açtığı bulgusu hakkında ne söylenebilir?$$,'["Bu bulgular metodolojik açıdan tartışmalı ve güvenilirliği sorgulandığından dikkate alınmamalıdır.","Beyin plastisitesi mekanizmaları aracılığıyla öğrenme ve dikkat süreçleriyle ilişkili bölgeler etkilenebilmekte; bu durum meditasyonun nörobiyolojik kanıtlarını güçlendirmektedir.","Yalnızca meditasyon yapmayanların beyni plastisiteye sahiptir.","Bu değişiklikler klinik açıdan anlamsız boyuttadır."]'::jsonb, 1, $$Nöroplastisite bulguları; meditasyonun beyni dönüştürebileceğini göstererek zihinsel egzersizlerin biyolojik temeline ilişkin bulguları güçlendirmektedir.$$, 2, 3),
('d2451a9b-36b2-47c3-bfca-f78307aae039','vocabulary',$$Metinde geçen "farkındalık" (mindfulness) kavramı nasıl tanımlanmaktadır?$$,'["Zihin kontrolü ve düşüncelerin bastırılması","Yargılamadan, an''a odaklanarak beden ve zihinsel deneyimi bilinçli biçimde gözlemleme pratiği","Özgün bir meditasyon okulu","Hipnoz benzeri değişmiş bilinç hali"]'::jsonb, 1, $$Farkındalık; yargılamaksızın an''a dikkat vermeyi kapsayan meditasyon pratiğidir ve çok sayıda klinik çalışmada etkinliği kanıtlanmıştır.$$, 2, 4),
('d2451a9b-36b2-47c3-bfca-f78307aae039','detail',$$Meditasyonun bilişsel işlevler üzerindeki etkisi nasıl açıklanmaktadır?$$,'["Meditasyon bellek kapasitesini azaltmaktadır.","Meditasyon; dikkat süresini uzatır, öz farkındalığı güçlendirir ve yaşa bağlı bilişsel gerilemeyi yavaşlatmaya yardımcı olur.","Meditasyon etkileri salt duygusal alanla sınırlıdır; bilişsel işlevleri kapsamaz.","Meditasyonun bilişsel faydaları yalnızca ileri yaştaki bireylerde gözlemlenmektedir."]'::jsonb, 1, $$Araştırmalar; meditasyonun dikkat, yürütücü işlevler ve bilişsel esneklik açısından ölçülebilir gelişimlere katkı sağladığını ortaya koymaktadır.$$, 2, 5);
INSERT INTO text_questions (text_id, question_type, question_text, options, correct_index, explanation, difficulty, order_index) VALUES
('4e53ee44-f43c-4c12-a716-46a81ca2089e','main_idea',$$Bu metnin ana fikri nedir?$$,'["Gizlilik kaygıları abartılmaktadır.","Dijital teknolojilerin yaygınlaşması; teknoloji şirketlerinin, hükümetlerin ve bireylerin dikkatli bir denge yönetimi gerektiren ciddi mahremiyet sorunlarını gündeme taşımaktadır.","Mahremiyet ihlalleri yalnızca suç örgütlerinden kaynaklanmaktadır.","Dijital gizlilik, bireylerin kaygılanmaması gereken teknik bir meseledir."]'::jsonb, 1, $$Metin; dijital mahremiyeti bireysel haklar ve kurumsal sorumluluklar ekseninde ele alan kritik bir mesele olarak konumlandırmaktadır.$$, 2, 1),
('4e53ee44-f43c-4c12-a716-46a81ca2089e','detail',$$Kişisel verilerin toplanması ve işlenmesi hangi temel riskleri doğurmaktadır?$$,'["Veri toplanması bireyler için hiçbir risk oluşturmamaktadır.","Kimlik hırsızlığı, manipülatif hedefli reklamcılık, siyasi mikro hedefleme ve kişisel bilgilerin yetkisiz paylaşımı başlıca riskler arasındadır.","Riskler yalnızca büyük teknoloji şirketleri için söz konusudur.","Veri riskleri yalnızca güvensiz uygulamaları kullanan bireyleri etkilemektedir."]'::jsonb, 1, $$Veri toplama; bireyler üzerindeki kontrol potansiyelinden ekonomik sömürüye kadar uzanan çok boyutlu gizlilik risklerini beraberinde getirmektedir.$$, 2, 2),
('4e53ee44-f43c-4c12-a716-46a81ca2089e','inference',$$GDPR ve benzeri veri koruma düzenlemeleri hakkında ne çıkarılabilir?$$,'["Düzenlemeler dijital inovasyonu tamamen durma noktasına getirmiştir.","Yasal yaptırımlar; bireyin verileri üzerindeki haklarını güvence altına almayı ve teknoloji şirketlerini gizlilik standartlarına uymaya zorlamayı amaçlamakta, ancak bu standartlar henüz küresel ölçekte tutarsızdır.","Gizlilik mevzuatı bireyler için yeterli koruma sağlamaktadır.","Düzenleyici çerçeveler dijital mahremiyet sorunlarını tam anlamıyla çözüme kavuşturmaktadır."]'::jsonb, 1, $$Veri koruma düzenlemeleri gerçek bir adımı temsil etmekle birlikte, küresel teknoloji gerçekliğinin hâlâ önünde kalmaktadır.$$, 2, 3),
('4e53ee44-f43c-4c12-a716-46a81ca2089e','vocabulary',$$Metinde geçen "meta veri" kavramı ne anlama gelmektedir?$$,'["Çevrimiçi platformlarda paylaşılan görseller","İçerik hakkında bilgi veren veriler; kim, ne zaman, nereden bağlandığı gibi bağlamsal bilgileri içerir ve içeriğin kendisi kadar açıklayıcı olabilir","Yalnızca arama motorlarına gönderilen anahtar kelimeler","Kullanıcı adları ve parolalar"]'::jsonb, 1, $$Meta veriler; iletişim içeriğini değil, iletişimin örüntüsünü ve bağlamını aktarır; bu nedenle gizlilik açısından içerik verisi kadar hassas olabilir.$$, 2, 4),
('4e53ee44-f43c-4c12-a716-46a81ca2089e','detail',$$Bireyler dijital mahremiyetlerini korumak için hangi adımları atabilmektedir?$$,'["Bireyler dijital ortamlarda gizliliği koruyamaz.","Şifreleme araçlarının kullanımı, gizlilik odaklı tarayıcılar, VPN''ler ve uygulama izinlerinin dikkatli yönetimi temel koruyucu önlemler arasındadır.","Gizlilik koruması yalnızca teknik uzmanların yapabileceği bir işlemdir.","Sosyal medyadan tamamen uzak durmak tek etkili yöntemdir."]'::jsonb, 1, $$Bireysel gizlilik hijyeni; yetersiz kalsa da veri izleme ve ihlal riskini anlamlı ölçüde azaltmaktadır.$$, 2, 5);
INSERT INTO text_questions (text_id, question_type, question_text, options, correct_index, explanation, difficulty, order_index) VALUES
('fc33c0f8-d99b-469e-87d4-08010f466d32','main_idea',$$Bu metnin ana fikri nedir?$$,'["Uzay araştırmaları artık ekonomik açıdan savunulamaz hale gelmiştir.","Uzay keşfinin geleceği; kamu kurumları ile özel şirketler arasındaki iş birliğiyle birlikte insanlığın başka gezegenler ve yıldız sistemlerine ulaşma potansiyelini giderek daha erişilebilir kılmaktadır.","Uzay araştırmaları özel şirketler yerine yalnızca devlet kurumları tarafından yürütülmelidir.","Mars kolonizasyonu 21. yüzyılda gerçekleşmeyecektir."]'::jsonb, 1, $$Metin; uzay keşfini özel-kamu iş birliğiyle yeniden şekillenen, gerçekçi ve heyecan verici bir ufuk olarak ele almaktadır.$$, 2, 1),
('fc33c0f8-d99b-469e-87d4-08010f466d32','detail',$$Ticari uzay şirketlerinin geleneksel uzay kurumlarına kıyasla avantajı nedir?$$,'["Ticari şirketler devlet kurumlarına oranla daha büyük bütçelerle çalışmaktadır.","Rekabetçi piyasa teşvikleri, yeniden kullanılabilir roket teknolojisi ve yalın operasyonel yapılar geliştirme ve fırlatma maliyetlerini önemli ölçüde düşürmüştür.","Özel şirketler devlet kurumlarının erişemediği teknolojilere sahiptir.","Ticari uzay şirketi bulunmamaktadır."]'::jsonb, 1, $$SpaceX''in yeniden kullanılabilir roketleri ve maliyet odaklı yaklaşımı, uzay erişim maliyetlerini önemli ölçüde azaltmış ve yeni olasılıkların önünü açmıştır.$$, 2, 2),
('fc33c0f8-d99b-469e-87d4-08010f466d32','inference',$$Mars kolonizasyon planları hakkında ne söylenebilir?$$,'["Mars kolonizasyonu yakın vadeli ve düşük riskli bir girişimdir.","Yaşam desteği, ışınım koruması ve psikolojik dirençlilik gibi önemli teknolojik ve insani zorluklar aşılmadan kolonizasyon gerçekçi bir seçenek olarak değerlendirilemez.","Mars gezegeninde koloni kurmak için gereken teknoloji tamamen mevcuttur.","Mars''ta yerleşim kurmanın insanlık açısından herhangi bir değeri yoktur."]'::jsonb, 1, $$Mars''a insanlı görev; uzay seyahatinin getireceği biyolojik stresörlerden tutun yüzlerce güne uzanan uzun süreçlere ve uygulama zorluklarına kadar pek çok mühendislik ve tıbbi sorunun çözülmesini zorunlu kılmaktadır.$$, 2, 3),
('fc33c0f8-d99b-469e-87d4-08010f466d32','vocabulary',$$Metinde geçen "Lagrange noktası" kavramı ne anlama gelmektedir?$$,'["Bir gezegenin yüzeyindeki belirli coğrafi konum","İki büyük cismin (güneş-dünya gibi) çekim kuvvetlerinin dengelendiği uzaydaki istikrarlı nokta; uzay istasyonu ve teleskop konumlandırması için tercih edilmektedir","Roketlerin dünya yörüngesine ulaştığı irtifa","Uzay istasyonunun içindeki yer çekimsiz bölge"]'::jsonb, 1, $$Lagrange noktaları; uydu ve uzay teleskoplarını minimum yakıt tüketimiyle kararlı yörüngelerde konumlandırmak için uzay mühendisliğinde stratejik biçimde kullanılmaktadır.$$, 2, 4),
('fc33c0f8-d99b-469e-87d4-08010f466d32','detail',$$Uzay araştırmalarının Dünya''daki yaşama katkıları nelerdir?$$,'["Uzay araştırmaları Dünya''ya hiçbir pratik fayda sağlamamaktadır.","GPS, uydu meteorolojisi, tıbbi görüntüleme ve ısıya dayanıklı malzeme teknolojileri, uzay Ar-Ge''sinin Dünya yaşamına kazandırdığı yan ürünler arasındadır.","Uzay teknolojileri başka sektörlere aktarılamaz niteliktedir.","Uzay araştırmaları yalnızca uzak gelecek uygulamaları için yatırım yapılmasını gerektirmektedir."]'::jsonb, 1, $$Uzay araştırmalarından elde edilen ve sivil hayata aktarılan teknolojik gelişmeler; uzay programlarının dolaylı ekonomik ve toplumsal değerini somut olarak ortaya koymaktadır.$$, 2, 5);
INSERT INTO text_questions (text_id, question_type, question_text, options, correct_index, explanation, difficulty, order_index) VALUES
('359ba415-3cac-446d-919d-94cdc0468918','main_idea',$$Bu metnin ana fikri nedir?$$,'["Yapay zeka yalnızca teknoloji meraklılarını ilgilendirmektedir.","Yapay zeka; sağlık, eğitim, ulaşım ve eğlence alanlarında günlük yaşamı köklü biçimde dönüştürmekte; hem büyük fırsatlar hem de ciddi toplumsal sorunları birlikte gündeme getirmektedir.","Yapay zeka insan işgücünün tamamını yakın gelecekte yerinden edecektir.","YZ uygulamaları henüz sınırlı ve deneysel aşamadadır."]'::jsonb, 1, $$Metin; yapay zekanın günlük yaşama entegrasyonunu, getirdiği faydaları ve doğurduğu toplumsal kaygıları dengeli biçimde ele almaktadır.$$, 2, 1),
('359ba415-3cac-446d-919d-94cdc0468918','detail',$$Metne göre yapay zekanın sağlık alanındaki uygulamaları nelerdir?$$,'["YZ sağlık alanında henüz herhangi bir uygulama imkânı bulamamıştır.","Tıbbi görüntü analizi, erken hastalık teşhisi, ilaç keşfi ve kişiselleştirilmiş tedavi planlaması YZ''nin sağlık alanındaki başlıca uygulamaları arasındadır.","YZ yalnızca tıbbi kayıtların düzenlenmesinde kullanılmaktadır.","YZ sağlık alanında geleneksel yöntemlerin gerisinde kalmaktadır."]'::jsonb, 1, $$YZ uygulamaları; tanı doğruluğunu artırmakta, ilaç geliştirme süreçlerini hızlandırmakta ve tedavi planlarını bireysel hasta verilerine göre uyarlamaktadır.$$, 2, 2),
('359ba415-3cac-446d-919d-94cdc0468918','inference',$$Yapay zekanın yol açtığı iş kayıpları hakkında ne çıkarılabilir?$$,'["YZ istihdamı hiçbir şekilde etkilemeyecektir.","Otomasyon belirli görevleri ortadan kaldırabilirken yeni meslekler de doğmakta; toplumun bu geçişi yönetmesi için politika ve eğitim adaptasyonu kritik önem taşımaktadır.","YZ mevcut işlerin tamamını hemen yerinden edecektir.","İş piyasasındaki değişimler yalnızca imalat sektörüyle sınırlı kalmaktadır."]'::jsonb, 1, $$YZ kaynaklı iş dönüşümü hem yıkıcı hem de yaratıcı etkiler barındırmaktadır; bu nedenle işgücü uyum politikaları kritik bir öncelik kazanmaktadır.$$, 2, 3),
('359ba415-3cac-446d-919d-94cdc0468918','vocabulary',$$Metinde geçen "makine öğrenimi" kavramı nasıl tanımlanmaktadır?$$,'["Robotların fiziksel görevleri yerine getirmek üzere programlanması","Sistemlerin açıkça programlanmaksızın verilerden örüntüler çıkararak performansını kendi kendine iyileştirdiği YZ alt dalı","Her bir durumun elle kodlandığı uzman sistem geliştirme","Beyin fonksiyonlarının doğrudan modellenmesi"]'::jsonb, 1, $$Makine öğrenimi; YZ''nin deneyimden öğrenerek tahmin gücünü artırmasını sağlayan temel yöntemdir; öneri sistemlerinden sesli asistanlara kadar geniş bir uygulama yelpazesini beslemektedir.$$, 2, 4),
('359ba415-3cac-446d-919d-94cdc0468918','detail',$$Yapay zekanın eğitim alanında sunduğu katkılar nelerdir?$$,'["YZ öğretmenlerin öğrencilerle kurduğu ilişkiyi zayıflatmaktadır.","Uyarlanabilir öğrenme platformları, otomatik değerlendirme araçları ve kişiselleştirilmiş müfredat yönetimi her öğrencinin öğrenme deneyimini bireyselleştirmektedir.","YZ eğitimde yalnızca idari süreçleri kolaylaştırmaktadır.","YZ destekli eğitim sistemleri etkin biçimde kullanılabilmesi için ileri düzey teknik donanım gerektirmektedir."]'::jsonb, 1, $$YZ; her öğrencinin güçlü ve zayıf yönlerine uyum sağlayan, daha etkili ve erişilebilir bir öğrenme deneyimi sunmaktadır.$$, 2, 5);
